-- Poems batch 462
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-43','忍死留別獻鹽鐵裴相公二十叔','杜牧','唐','御定全唐诗','yuding','','[]','賢相輔明主，蒼生壽域開。青春辭白日，幽壤作黃埃。',48,'御定全唐詩/json/524.json','["賢相輔明主，蒼生壽域開。青春辭白日，幽壤作黃埃。", "豈是無多士，偏蒙不棄才。孤墳三尺土，誰可為培栽。"]'),
('yuding-44','悲吳王城','杜牧','唐','御定全唐诗','yuding','','[]','二月春風江上來，水精波動碎樓臺。吳王宮殿柳含翠，',40,'御定全唐詩/json/524.json','["二月春風江上來，水精波動碎樓臺。吳王宮殿柳含翠，", "千秋萬古無消息，國作荒原人作灰。"]'),
('yuding-45','閨情代作','杜牧','唐','御定全唐诗','yuding','','[]','梧桐葉落雁初歸，迢遞無因寄遠衣。月照石泉金點冷，',40,'御定全唐詩/json/524.json','["梧桐葉落雁初歸，迢遞無因寄遠衣。月照石泉金點冷，", "遙望戍樓天欲曉，滿城冬鼓白雲飛。"]'),
('yuding-46','寄沈褒秀才','杜牧','唐','御定全唐诗','yuding','','[]','晴河萬里色如刀，處處浮雲臥碧桃。仙桂茂時金鏡曉，',40,'御定全唐詩/json/524.json','["晴河萬里色如刀，處處浮雲臥碧桃。仙桂茂時金鏡曉，", "他日憶君何處望，九天香滿碧蕭騷。"]'),
('yuding-47','入關','杜牧','唐','御定全唐诗','yuding','','[]','東西南北數衢通，曾取江西徑過東。',32,'御定全唐詩/json/524.json','["東西南北數衢通，曾取江西徑過東。", "今日更尋南去路，未秋應有北歸鴻。"]'),
('yuding-48','及第後寄長安故人','杜牧','唐','御定全唐诗','yuding','','[]','東都放榜未花開，三十三人走馬回。',32,'御定全唐詩/json/524.json','["東都放榜未花開，三十三人走馬回。", "秦地少年多釀酒，已將春色入關來。"]'),
('yuding-49','偶作','杜牧','唐','御定全唐诗','yuding','','[]','才子風流詠曉霞，倚樓吟住日初斜。',32,'御定全唐詩/json/524.json','["才子風流詠曉霞，倚樓吟住日初斜。", "驚殺東鄰繡床女，錯將黃暈壓檀花。"]'),
('yuding-50','贈終南蘭若僧','杜牧','唐','御定全唐诗','yuding','','[]','北闕南山是故鄉，兩枝仙桂一時芳。',32,'御定全唐詩/json/524.json','["北闕南山是故鄉，兩枝仙桂一時芳。", "休公都不知名姓，始覺禪門氣味長。"]'),
('yuding-51','遣懷','杜牧','唐','御定全唐诗','yuding','','[]','落魄江南載酒行，楚腰腸斷掌中輕。',32,'御定全唐詩/json/524.json','["落魄江南載酒行，楚腰腸斷掌中輕。", "十年一覺揚州夢，贏得青樓薄幸名。"]'),
('yuding-52','秋感','杜牧','唐','御定全唐诗','yuding','','[]','金風萬里思何盡，玉樹一窗秋影寒。',32,'御定全唐詩/json/524.json','["金風萬里思何盡，玉樹一窗秋影寒。", "獨掩柴門明月下，淚流香袂倚闌幹。"]'),
('yuding-53','贈漁父','杜牧','唐','御定全唐诗','yuding','','[]','蘆花深澤靜垂綸，月夕煙朝幾十春。',32,'御定全唐詩/json/524.json','["蘆花深澤靜垂綸，月夕煙朝幾十春。", "自說孤舟寒水畔，不曾逢著獨醒人。"]'),
('yuding-54','歎花','杜牧','唐','御定全唐诗','yuding','','[]','自恨尋芳到已遲，往年曾見未開時。',32,'御定全唐詩/json/524.json','["自恨尋芳到已遲，往年曾見未開時。", "如今風擺花狼藉，綠葉成陰子滿枝。"]'),
('yuding-55','題劉秀才新竹','杜牧','唐','御定全唐诗','yuding','','[]','數莖幽玉色，曉夕翠煙分。聲破寒窗夢，根穿綠蘚紋。',48,'御定全唐詩/json/524.json','["數莖幽玉色，曉夕翠煙分。聲破寒窗夢，根穿綠蘚紋。", "漸籠當檻日，欲礙入簾雲。不是山陰客，何人愛此君。"]'),
('yuding-56','山行','杜牧','唐','御定全唐诗','yuding','','[]','遠上寒山石徑斜，白雲生處有人家。',32,'御定全唐詩/json/524.json','["遠上寒山石徑斜，白雲生處有人家。", "停車坐愛楓林晚，霜葉紅於二月花。"]'),
('yuding-57','書懷','杜牧','唐','御定全唐诗','yuding','','[]','滿眼青山未得過，鏡中無那鬢絲何。',32,'御定全唐詩/json/524.json','["滿眼青山未得過，鏡中無那鬢絲何。", "只言旋老轉無事，欲到中年事更多。"]'),
('yuding-58','紫薇花','杜牧','唐','御定全唐诗','yuding','','[]','曉迎秋露一枝新，不占園中最上春。',32,'御定全唐詩/json/524.json','["曉迎秋露一枝新，不占園中最上春。", "桃李無言又何在，向風偏笑豔陽人。"]'),
('yuding-59','醉後呈崔大夫','杜牧','唐','御定全唐诗','yuding','','[]','謝傅秋涼閱管弦，徒教賤子侍華筵。',32,'御定全唐詩/json/524.json','["謝傅秋涼閱管弦，徒教賤子侍華筵。", "溪頭正雨歸不得，辜負東窗一覺眠。"]'),
('yuding-60','和宣州沈大夫登北樓書懷','杜牧','唐','御定全唐诗','yuding','','[]','兵符嚴重辭金馬，星劍光芒射鬥牛。筆落青山飄古韻，',40,'御定全唐詩/json/524.json','["兵符嚴重辭金馬，星劍光芒射鬥牛。筆落青山飄古韻，", "可惜登臨佳麗地，羽儀須去鳳池遊。"]'),
('yuding-61','夜雨','杜牧','唐','御定全唐诗','yuding','','[]','九月三十日，雨聲如別秋。無端滿階葉，共白幾人頭。',48,'御定全唐詩/json/524.json','["九月三十日，雨聲如別秋。無端滿階葉，共白幾人頭。", "點滴侵寒夢，蕭騷著淡愁。漁歌聽不唱，蓑濕棹回舟。"]'),
('yuding-62','方響','杜牧','唐','御定全唐诗','yuding','','[]','數條秋水掛琅玕，玉手丁當怕夜寒。',32,'御定全唐詩/json/524.json','["數條秋水掛琅玕，玉手丁當怕夜寒。", "曲盡連敲三四下，恐驚珠淚落金盤。"]'),
('yuding-63','將出關宿層峰驛，卻寄李諫議','杜牧','唐','御定全唐诗','yuding','','[]','孤驛在重阻，雲根掩柴扉。數聲暮禽切，萬壑秋意歸。',48,'御定全唐詩/json/524.json','["孤驛在重阻，雲根掩柴扉。數聲暮禽切，萬壑秋意歸。", "心馳碧泉澗，目斷青瑣闈。明日武關外，夢魂勞遠飛。"]'),
('yuding-64','使回枉唐州崔司馬書，兼寄四韻因和','杜牧','唐','御定全唐诗','yuding','','[]','清晨候吏把書來，十載離憂得暫開。癡叔去時還讀易，',40,'御定全唐詩/json/524.json','["清晨候吏把書來，十載離憂得暫開。癡叔去時還讀易，", "莫為霜台愁歲暮，潛龍須待一聲雷。"]'),
('yuding-65','郡齋秋夜即事，寄斛斯處士許秀才','杜牧','唐','御定全唐诗','yuding','','[]','有客誰人肯夜過，獨憐風景奈愁何。邊鴻怨處迷霜久，',40,'御定全唐詩/json/524.json','["有客誰人肯夜過，獨憐風景奈愁何。邊鴻怨處迷霜久，", "馳心只待城烏曉，幾對虛簷望白河。"]'),
('yuding-66','早春題真上人院','杜牧','唐','御定全唐诗','yuding','','[]','清羸已近百年身，古寺風煙又一春。',32,'御定全唐詩/json/524.json','["清羸已近百年身，古寺風煙又一春。", "寰海自成戎馬地，唯師曾是太平人。"]'),
('yuding-67','對花微疾不飲，呈坐中諸公','杜牧','唐','御定全唐诗','yuding','','[]','花前雖病亦提壺，數調持觴興有無。',32,'御定全唐詩/json/524.json','["花前雖病亦提壺，數調持觴興有無。", "盡日臨風羨人醉，雪香空伴白髭須。"]'),
('yuding-68','酬王秀才桃花園見寄','杜牧','唐','御定全唐诗','yuding','','[]','桃滿西園淑景催，幾多紅豔淺深開。',32,'御定全唐詩/json/524.json','["桃滿西園淑景催，幾多紅豔淺深開。", "此花不逐溪流出，晉客無因入洞來。"]'),
('yuding-69','走筆送杜十三歸京','杜牧','唐','御定全唐诗','yuding','','[]','煙鴻上漢聲聲遠，逸驥尋雲步步高。',32,'御定全唐詩/json/524.json','["煙鴻上漢聲聲遠，逸驥尋雲步步高。", "應笑內兄年六十，郡城閑坐養霜毛。"]'),
('yuding-70','送王十至褒中因寄尚書','杜牧','唐','御定全唐诗','yuding','','[]','闕下經年別，人間兩地情。壇場新漢將，煙月古隋城。',48,'御定全唐詩/json/524.json','["闕下經年別，人間兩地情。壇場新漢將，煙月古隋城。", "雁去梁山遠，雲高楚岫明。君家荷藕好，緘恨寄遙程。"]'),
('yuding-71','後池泛舟送王十','杜牧','唐','御定全唐诗','yuding','','[]','相送西郊暮景和，青蒼竹外繞寒波。',32,'御定全唐詩/json/524.json','["相送西郊暮景和，青蒼竹外繞寒波。", "為君蘸甲十分飲，應見離心一倍多。"]'),
('yuding-72','重送王十','杜牧','唐','御定全唐诗','yuding','','[]','執袂還應立馬看，向來離思始知難。',32,'御定全唐詩/json/524.json','["執袂還應立馬看，向來離思始知難。", "雁飛不見行塵滅，景下山遙極目寒。"]'),
('yuding-73','洛陽秋夕','杜牧','唐','御定全唐诗','yuding','','[]','泠泠寒水帶霜風，更在天橋夜景中。',32,'御定全唐詩/json/524.json','["泠泠寒水帶霜風，更在天橋夜景中。", "清禁漏閑煙樹寂，月輪移在上陽宮。"]'),
('yuding-74','贈獵騎','杜牧','唐','御定全唐诗','yuding','','[]','已落雙雕血尚新，鳴鞭走馬又翻身。',32,'御定全唐詩/json/524.json','["已落雙雕血尚新，鳴鞭走馬又翻身。", "憑君莫射南來雁，恐有家書寄遠人。"]'),
('yuding-75','懷吳中馮秀才','杜牧','唐','御定全唐诗','yuding','','[]','長洲苑外草蕭蕭，卻算游程歲月遙。',32,'御定全唐詩/json/524.json','["長洲苑外草蕭蕭，卻算游程歲月遙。", "唯有別時今不忘，暮煙秋雨過楓橋。"]'),
('yuding-76','寄東塔僧','杜牧','唐','御定全唐诗','yuding','','[]','初月微明漏白煙，碧松梢外掛青天。',32,'御定全唐詩/json/524.json','["初月微明漏白煙，碧松梢外掛青天。", "西風靜起傳深夜，應送愁吟入夜禪。"]'),
('yuding-77','秋夕','杜牧','唐','御定全唐诗','yuding','','[]','紅燭秋光冷畫屏，輕羅小扇撲流螢。',32,'御定全唐詩/json/524.json','["紅燭秋光冷畫屏，輕羅小扇撲流螢。", "天階夜色涼如水，坐看牽牛織女星。"]'),
('yuding-78','瑤瑟','杜牧','唐','御定全唐诗','yuding','','[]','玉仙瑤瑟夜珊珊，月過樓西桂燭殘。',32,'御定全唐詩/json/524.json','["玉仙瑤瑟夜珊珊，月過樓西桂燭殘。", "風景人間不如此，動搖湘水徹明寒。"]'),
('yuding-79','送故人歸山','杜牧','唐','御定全唐诗','yuding','','[]','三清洞裏無端別，又拂塵衣欲臥雲。',32,'御定全唐詩/json/524.json','["三清洞裏無端別，又拂塵衣欲臥雲。", "看著掛冠迷處所，北山蘿月在移文。"]'),
('yuding-80','聞角','杜牧','唐','御定全唐诗','yuding','','[]','曉樓煙檻出雲霄，景下林塘已寂寥。',32,'御定全唐詩/json/524.json','["曉樓煙檻出雲霄，景下林塘已寂寥。", "城角為秋悲更遠，護霜雲破海天遙。"]'),
('yuding-81','押兵甲發谷口寄諸公','杜牧','唐','御定全唐诗','yuding','','[]','曉澗青青桂色孤，楚人隨玉上天衢。',32,'御定全唐詩/json/524.json','["曉澗青青桂色孤，楚人隨玉上天衢。", "水辭穀口山寒少，今日風頭校暖無。"]'),
('yuding-82','和令狐侍禦賞蕙草','杜牧','唐','御定全唐诗','yuding','','[]','尋常詩思巧如春，又喜幽亭蕙草新。',32,'御定全唐詩/json/524.json','["尋常詩思巧如春，又喜幽亭蕙草新。", "本是馨香比君子，繞欄今更為何人。"]'),
('yuding-83','偶題','杜牧','唐','御定全唐诗','yuding','','[]','道在人間或可傳，小還輕變已多年。',32,'御定全唐詩/json/524.json','["道在人間或可傳，小還輕變已多年。", "今來海上升高望，不到蓬萊不是仙。"]'),
('yuding-84','三川驛伏覽座主舍人留題','杜牧','唐','御定全唐诗','yuding','','[]','舊跡依然已十秋，雪山當面照銀鉤。',32,'御定全唐詩/json/524.json','["舊跡依然已十秋，雪山當面照銀鉤。", "懷恩淚盡霜天曉，一片餘霞映驛樓。"]'),
('yuding-85','陝州醉贈裴四同年','杜牧','唐','御定全唐诗','yuding','','[]','淒風洛下同羈思，遲日棠陰得醉歌。',32,'御定全唐詩/json/524.json','["淒風洛下同羈思，遲日棠陰得醉歌。", "自笑與君三歲別，頭銜依舊鬢絲多。"]'),
('yuding-86','破鏡','杜牧','唐','御定全唐诗','yuding','','[]','佳人失手鏡初分，何日團圓再會君。',32,'御定全唐詩/json/524.json','["佳人失手鏡初分，何日團圓再會君。", "今朝萬里秋風起，山北山南一片雲。"]'),
('yuding-87','長安雪後','杜牧','唐','御定全唐诗','yuding','','[]','秦陵漢苑參差雪，北闕南山次第春。',32,'御定全唐詩/json/524.json','["秦陵漢苑參差雪，北闕南山次第春。", "車馬滿城原上去，豈知惆悵有閒人。"]'),
('yuding-88','華清宮','杜牧','唐','御定全唐诗','yuding','','[]','零葉翻紅萬樹霜，玉蓮開蕊暖泉香。',32,'御定全唐詩/json/524.json','["零葉翻紅萬樹霜，玉蓮開蕊暖泉香。", "行雲不下朝元閣，一曲淋鈴淚數行。"]'),
('yuding-89','冬日題智門寺北樓','杜牧','唐','御定全唐诗','yuding','','[]','滿懷多少是恩酬，未見功名已白頭。',32,'御定全唐詩/json/524.json','["滿懷多少是恩酬，未見功名已白頭。", "不為尋山試筋力，豈能寒上背雲樓。"]'),
('yuding-90','別王十後遣京使累路附書','杜牧','唐','御定全唐诗','yuding','','[]','重關曉度宿雲寒，羸馬緣知步步難。',32,'御定全唐詩/json/524.json','["重關曉度宿雲寒，羸馬緣知步步難。", "此信的應中路見，亂山何處拆書看。"]'),
('yuding-91','許秀才至辱李蘄州絕句，問斷酒之情因寄','杜牧','唐','御定全唐诗','yuding','','[]','有客南來話所思，故人遙枉醉中詩。',32,'御定全唐詩/json/524.json','["有客南來話所思，故人遙枉醉中詩。", "暫因微疾須防酒，不是歡情減舊時。"]'),
('yuding-92','送張判官歸兼謁鄂州大夫','杜牧','唐','御定全唐诗','yuding','','[]','處士聞名早，游秦獻疏回。腹中書萬卷，身外酒千杯。',48,'御定全唐詩/json/524.json','["處士聞名早，游秦獻疏回。腹中書萬卷，身外酒千杯。", "江雨春波闊，園林客夢催。今君拜旌戟，凜凜近霜台。"]'),
('yuding-93','宿長慶寺','杜牧','唐','御定全唐诗','yuding','','[]','南行步步遠浮塵，更近青山昨夜鄰。高鐸數聲秋撼玉，',40,'御定全唐詩/json/524.json','["南行步步遠浮塵，更近青山昨夜鄰。高鐸數聲秋撼玉，", "終日官閑無一事，不妨長醉是遊人。"]'),
('yuding-94','望少華三首','杜牧','唐','御定全唐诗','yuding','','[]','身隨白日看將老，心與青雲自有期。',96,'御定全唐詩/json/524.json','["身隨白日看將老，心與青雲自有期。", "今對晴峰無十裏，世緣多累暗生悲。", "文字波中去不還，物情初與是非閑。", "時名竟是無端事，羞對靈山道愛山。", "眼看雲鶴不相隨，何況塵中事作為。", "好伴羽人深洞去，月前秋聽玉參差。"]'),
('yuding-95','登澧州驛樓寄京兆韋尹','杜牧','唐','御定全唐诗','yuding','','[]','一話涔陽舊使君，郡人回首望青雲。',32,'御定全唐詩/json/524.json','["一話涔陽舊使君，郡人回首望青雲。", "政聲長與江聲在，自到津樓日夜聞。"]'),
('yuding-96','長安晴望','杜牧','唐','御定全唐诗','yuding','','[]','翠屏山對鳳城開，碧落搖光霽後來。',32,'御定全唐詩/json/524.json','["翠屏山對鳳城開，碧落搖光霽後來。", "回識六龍巡幸處，飛煙閑繞望春台。"]'),
('yuding-97','歲旦朝回口號','杜牧','唐','御定全唐诗','yuding','','[]','星河猶在整朝衣，遠望天門再拜歸。',32,'御定全唐詩/json/524.json','["星河猶在整朝衣，遠望天門再拜歸。", "笑向春風初五十，敢言知命且知非。"]'),
('yuding-98','驌驦駿','杜牧','唐','御定全唐诗','yuding','','[]','瑤池罷遊宴，良樂委塵沙。遭遇不遭遇，鹽車與鼓車。',24,'御定全唐詩/json/524.json','["瑤池罷遊宴，良樂委塵沙。遭遇不遭遇，鹽車與鼓車。"]'),
('yuding-99','龍丘途中二首','杜牧','唐','御定全唐诗','yuding','','[]','漢苑殘花別，吳江盛夏來。唯看萬樹合，不見一枝開。',48,'御定全唐詩/json/524.json','["漢苑殘花別，吳江盛夏來。唯看萬樹合，不見一枝開。", "水色饒湘浦，灘聲怯建溪。淚流回月上，可得更猿啼。"]'),
('yuding-100','宮人塚','杜牧','唐','御定全唐诗','yuding','','[]','儘是離宮院中女，苑牆城外塚累累。',32,'御定全唐詩/json/524.json','["儘是離宮院中女，苑牆城外塚累累。", "少年入內教歌舞，不識君王到老時。"]'),
('yuding-101','寄浙西李判官','杜牧','唐','御定全唐诗','yuding','','[]','燕臺上客意何如，四五年來漸漸疏。直道莫拋男子業，',40,'御定全唐詩/json/524.json','["燕臺上客意何如，四五年來漸漸疏。直道莫拋男子業，", "唯念賢哉崔大讓，可憐無事不歌魚。"]'),
('yuding-102','寄杜子二首','杜牧','唐','御定全唐诗','yuding','','[]','不識長楊事北胡，且教紅袖醉來扶。',64,'御定全唐詩/json/524.json','["不識長楊事北胡，且教紅袖醉來扶。", "狂風烈焰雖千尺，豁得平生俊氣無。", "武牢關吏應相笑，個裏年年往復來。", "若問使君何處去，為言相憶首長回。"]'),
('yuding-103','盧秀才將出王屋，高步名場，江南相逢贈別','杜牧','唐','御定全唐诗','yuding','','[]','王屋山人有古文，欲攀青桂弄氛氳。將攜健筆幹明主，',40,'御定全唐詩/json/524.json','["王屋山人有古文，欲攀青桂弄氛氳。將攜健筆幹明主，", "交遊話我憑君道，除卻鱸魚更不聞。"]'),
('yuding-104','送劉三複郎中赴闕','杜牧','唐','御定全唐诗','yuding','','[]','橫溪辭寂寞，金馬去追遊。好是鴛鴦侶，正逢霄漢秋。',48,'御定全唐詩/json/524.json','["橫溪辭寂寞，金馬去追遊。好是鴛鴦侶，正逢霄漢秋。", "玉珂聲瑣瑣，錦帳夢悠悠。微笑知今是，因風謝釣舟。"]'),
('yuding-105','羊欄浦夜陪宴會','杜牧','唐','御定全唐诗','yuding','','[]','戈檻營中夜未央，雨沾雲惹侍襄王。球來香袖依稀暖，',40,'御定全唐詩/json/524.json','["戈檻營中夜未央，雨沾雲惹侍襄王。球來香袖依稀暖，", "自比諸生最無取，不知何處亦升堂。"]'),
('yuding-106','送杜顗赴潤州幕','杜牧','唐','御定全唐诗','yuding','','[]','少年才俊赴知音，丞相門欄不覺深。直道事人男子業，',40,'御定全唐詩/json/524.json','["少年才俊赴知音，丞相門欄不覺深。直道事人男子業，", "若去上元懷古去，謝安墳下與沉吟。"]'),
('yuding-107','有感','杜牧','唐','御定全唐诗','yuding','','[]','宛溪垂柳最長枝，曾被春風盡日吹。',32,'御定全唐詩/json/524.json','["宛溪垂柳最長枝，曾被春風盡日吹。", "不堪攀折猶堪看，陌上少年來自遲。"]'),
('yuding-108','書懷寄盧州','杜牧','唐','御定全唐诗','yuding','','[]','謝山南畔州，風物最宜秋。太守懸金印，佳人敞畫樓。',48,'御定全唐詩/json/524.json','["謝山南畔州，風物最宜秋。太守懸金印，佳人敞畫樓。", "凝缸暗醉夕，殘月上汀州。可惜當年鬢，朱門不得遊。"]'),
('yuding-109','賀崔大夫崔正字','杜牧','唐','御定全唐诗','yuding','','[]','內舉無慚古所難，燕台遙想拂塵冠。登龍有路水不峻，',40,'御定全唐詩/json/524.json','["內舉無慚古所難，燕台遙想拂塵冠。登龍有路水不峻，", "謝公樓下潺湲響，離恨詩情添幾般。"]'),
('yuding-110','江南送左師','杜牧','唐','御定全唐诗','yuding','','[]','江南為客正悲秋，更送吾師古渡頭。',32,'御定全唐詩/json/524.json','["江南為客正悲秋，更送吾師古渡頭。", "惆悵不同塵土別，水雲蹤跡去悠悠。"]'),
('yuding-111','寢夜','杜牧','唐','御定全唐诗','yuding','','[]','蛩唱如波咽，更深似水寒。露華驚弊褐，燈影掛塵冠。',48,'御定全唐詩/json/524.json','["蛩唱如波咽，更深似水寒。露華驚弊褐，燈影掛塵冠。", "故國初離夢，前溪更下灘。紛紛毫髮事，多少宦遊難。"]'),
('yuding-112','十九兄郡樓有宴，病不赴','杜牧','唐','御定全唐诗','yuding','','[]','十二層樓敞畫簷，連去歌盡草纖纖。',32,'御定全唐詩/json/524.json','["十二層樓敞畫簷，連去歌盡草纖纖。", "空堂病怯階前月，燕子嗔垂一竹簾。"]'),
('yuding-113','愁','杜牧','唐','御定全唐诗','yuding','','[]','聚散竟無形，回腸自結成。古今留不得，離別又潛生。',48,'御定全唐詩/json/524.json','["聚散竟無形，回腸自結成。古今留不得，離別又潛生。", "降虜將軍思，窮秋遠客情。何人更憔悴，落第泣秦京。"]'),
('yuding-114','隋苑','杜牧','唐','御定全唐诗','yuding','','[]','紅霞一抹廣陵春，定子當筵睡臉新。',32,'御定全唐詩/json/524.json','["紅霞一抹廣陵春，定子當筵睡臉新。", "卻笑吃虧隋煬帝，破家亡國為誰人。"]'),
('yuding-115','芭蕉','杜牧','唐','御定全唐诗','yuding','','[]','芭蕉為雨移，故向窗前種。憐渠點滴聲，留得歸鄉夢。',36,'御定全唐詩/json/524.json','["芭蕉為雨移，故向窗前種。憐渠點滴聲，留得歸鄉夢。", "夢遠莫歸鄉，覺來一翻動。"]'),
('yuding-116','汴人舟行答張祜','杜牧','唐','御定全唐诗','yuding','','[]','千萬長河共使船，聽君詩句倍愴然。',32,'御定全唐詩/json/524.json','["千萬長河共使船，聽君詩句倍愴然。", "春風野岸名花發，一道帆檣畫柳煙。"]'),
('yuding-117','牧陪昭應盧郎中在江西宣州佐今吏部沈公幕罷府周歲公宰昭應牧在淮南縻職敘舊成二十二韻用以投寄','杜牧','唐','御定全唐诗','yuding','','[]','燕雁下揚州，涼風柳陌愁。可憐千里夢，還是一年秋。',264,'御定全唐詩/json/524.json','["燕雁下揚州，涼風柳陌愁。可憐千里夢，還是一年秋。", "宛水環朱檻，章江敞碧流。謬陪吾益友，只事我賢侯。", "印組縈光馬，鋒鋩看解牛。井閭安樂易，冠蓋愜依投。", "政簡稀開閣，功成每運籌。送春經野塢，遲日上高樓。", "玉裂歌聲斷，霞飄舞帶收。泥情斜拂印，別臉小低頭。", "日晚花枝爛，釭凝粉彩稠。未曾孤酩酊，剩肯只淹留。", "重德俄征寵，諸生苦宦遊。分途之絕國，灑淚拜行輈。", "聚散真漂梗，光陰極轉郵。銘心徒歷歷，屈指盡悠悠。", "君作烹鮮用，誰膺仄席求。卷懷能憤悱，卒歲且優遊。", "去矣時難遇，沽哉價莫酬。滿枝為鼓吹，衷甲避戈矛。", "隋帝宮荒草，秦王土一丘。相逢好大笑，除此總雲浮。"]'),
('yuding-0','寓言','杜牧','唐','御定全唐诗','yuding','','[]','暖風遲日柳初含，顧影看身又自慚。',32,'御定全唐詩/json/525.json','["暖風遲日柳初含，顧影看身又自慚。", "何事明朝獨惆悵，杏花時節在江南。"]'),
('yuding-1','猿','杜牧','唐','御定全唐诗','yuding','','[]','月白煙青水暗流，孤猿銜恨叫中秋。',32,'御定全唐詩/json/525.json','["月白煙青水暗流，孤猿銜恨叫中秋。", "三聲欲斷疑腸斷，饒是少年今白頭。"]'),
('yuding-2','懷歸','杜牧','唐','御定全唐诗','yuding','','[]','塵埃終日滿窗前，水態雲容思浩然。',32,'御定全唐詩/json/525.json','["塵埃終日滿窗前，水態雲容思浩然。", "爭得便歸湘浦去，卻持竿上釣魚船。"]'),
('yuding-3','邊上晚秋','杜牧','唐','御定全唐诗','yuding','','[]','黑山南面更無州，馬放平沙夜不收。',32,'御定全唐詩/json/525.json','["黑山南面更無州，馬放平沙夜不收。", "風送孤城臨晚角，一聲聲入客心愁。"]'),
('yuding-4','傷友人悼吹簫妓','杜牧','唐','御定全唐诗','yuding','','[]','玉簫聲斷沒流年，滿目春愁隴樹煙。',32,'御定全唐詩/json/525.json','["玉簫聲斷沒流年，滿目春愁隴樹煙。", "豔質已隨雲雨散，鳳樓空鎖月明天。"]'),
('yuding-5','訪許顏','杜牧','唐','御定全唐诗','yuding','','[]','門近寒溪窗近山，枕山流水日潺潺。',32,'御定全唐詩/json/525.json','["門近寒溪窗近山，枕山流水日潺潺。", "長嫌世上浮雲客，老向塵中不解顏。"]'),
('yuding-6','春日古道傍作','杜牧','唐','御定全唐诗','yuding','','[]','萬古榮華旦暮齊，樓臺春盡草萋萋。',32,'御定全唐詩/json/525.json','["萬古榮華旦暮齊，樓臺春盡草萋萋。", "君看陌上何人墓，旋化紅塵送馬蹄。"]'),
('yuding-7','青塚','杜牧','唐','御定全唐诗','yuding','','[]','青塚前頭隴水流，燕支山上暮雲秋。',32,'御定全唐詩/json/525.json','["青塚前頭隴水流，燕支山上暮雲秋。", "蛾眉一墜窮泉路，夜夜孤魂月下愁。"]'),
('yuding-8','大夢上人自廬峰回','杜牧','唐','御定全唐诗','yuding','','[]','行腳尋常到寺稀，一枝藜杖一禪衣。',32,'御定全唐詩/json/525.json','["行腳尋常到寺稀，一枝藜杖一禪衣。", "開門滿院空秋色，新向廬峰過夏歸。"]'),
('yuding-9','洛中二首','杜牧','唐','御定全唐诗','yuding','','[]','柳動晴風拂路塵，年年宮闕鎖濃春。',64,'御定全唐詩/json/525.json','["柳動晴風拂路塵，年年宮闕鎖濃春。", "一從翠輦無巡幸，老卻蛾眉幾許人。", "風吹柳帶搖晴綠，蝶繞花枝戀暖香。", "多把芳菲泛春酒，直教愁色對愁腸。"]'),
('yuding-10','邊上聞笳三首','杜牧','唐','御定全唐诗','yuding','','[]','何處吹笳薄暮天，塞垣高鳥沒狼煙。',96,'御定全唐詩/json/525.json','["何處吹笳薄暮天，塞垣高鳥沒狼煙。", "遊人一聽頭堪白，蘇武爭禁十九年。", "海路無塵邊草新，榮枯不見綠楊春。", "白沙日暮愁雲起，獨感離鄉萬里人。", "胡雛吹笛上高臺，寒雁驚飛去不回。", "盡日春風吹不散，只應分付客愁來。"]'),
('yuding-11','春日寄許渾先輩','杜牧','唐','御定全唐诗','yuding','','[]','薊北雁初去，湘南春又歸。水流滄海急，人到白頭稀。',48,'御定全唐詩/json/525.json','["薊北雁初去，湘南春又歸。水流滄海急，人到白頭稀。", "塞路盡何處，我愁當落暉。終須接鴛鷺，霄漢共高飛。"]'),
('yuding-12','經闔閭城','杜牧','唐','御定全唐诗','yuding','','[]','遺蹤委衰草，行客思悠悠。昔日人何處，終年水自流。',48,'御定全唐詩/json/525.json','["遺蹤委衰草，行客思悠悠。昔日人何處，終年水自流。", "孤煙村戍遠，亂雨海門秋。吟罷獨歸去，煙雲盡慘愁。"]'),
('yuding-13','並州道中','杜牧','唐','御定全唐诗','yuding','','[]','行役我方倦，苦吟誰複聞。戍樓春帶雪，邊角暮吹雲。',48,'御定全唐詩/json/525.json','["行役我方倦，苦吟誰複聞。戍樓春帶雪，邊角暮吹雲。", "極目無人跡，回頭送雁群。如何遣公子，高臥醉醺醺。"]'),
('yuding-14','別懷','杜牧','唐','御定全唐诗','yuding','','[]','相別徒成泣，經過總是空。勞生慣離別，夜夢苦西東。',48,'御定全唐詩/json/525.json','["相別徒成泣，經過總是空。勞生慣離別，夜夢苦西東。", "去路三湘浪，歸程一片風。他年寄消息，書在鯉魚中。"]'),
('yuding-15','漁父','杜牧','唐','御定全唐诗','yuding','','[]','白髮滄浪上，全忘是與非。秋潭垂釣去，夜月叩船歸。',48,'御定全唐詩/json/525.json','["白髮滄浪上，全忘是與非。秋潭垂釣去，夜月叩船歸。", "煙影侵蘆岸，潮痕在竹扉。終年狎鷗鳥，來去且無機。"]'),
('yuding-16','秋夢','杜牧','唐','御定全唐诗','yuding','','[]','寒空動高吹，月色滿清砧。殘夢夜魂斷，美人邊思深。',48,'御定全唐詩/json/525.json','["寒空動高吹，月色滿清砧。殘夢夜魂斷，美人邊思深。", "孤鴻秋出塞，一葉暗辭林。又寄征衣去，迢迢天外心。"]'),
('yuding-17','早秋客舍','杜牧','唐','御定全唐诗','yuding','','[]','風吹一片葉，萬物已驚秋。獨夜他鄉淚，年年為客愁。',48,'御定全唐詩/json/525.json','["風吹一片葉，萬物已驚秋。獨夜他鄉淚，年年為客愁。", "別離何處盡，搖落幾時休。不及磻溪叟，身閑長自由。"]'),
('yuding-18','逢故人','杜牧','唐','御定全唐诗','yuding','','[]','故交相見稀，相見倍依依。塵路事不盡，雲岩閑好歸。',48,'御定全唐詩/json/525.json','["故交相見稀，相見倍依依。塵路事不盡，雲岩閑好歸。", "投人銷壯志，徇俗變真機。又落他鄉淚，風前一滿衣。"]'),
('yuding-19','秋晚江上遣懷','杜牧','唐','御定全唐诗','yuding','','[]','孤舟天際外，去路望中賒。貧病遠行客，夢魂多在家。',48,'御定全唐詩/json/525.json','["孤舟天際外，去路望中賒。貧病遠行客，夢魂多在家。", "蟬吟秋色樹，鴉噪夕陽沙。不擬徹雙鬢，他方擲歲華。"]'),
('yuding-20','長安夜月','杜牧','唐','御定全唐诗','yuding','','[]','寒光垂靜夜，皓彩滿重城。萬國盡分照，誰家無此明。',48,'御定全唐詩/json/525.json','["寒光垂靜夜，皓彩滿重城。萬國盡分照，誰家無此明。", "古槐疏影薄，仙桂動秋聲。獨有長門裏，蛾眉對曉晴。"]'),
('yuding-21','雲','杜牧','唐','御定全唐诗','yuding','','[]','東西那有礙，出處豈虛心。曉入洞庭闊，暮歸巫峽深。',48,'御定全唐詩/json/525.json','["東西那有礙，出處豈虛心。曉入洞庭闊，暮歸巫峽深。", "渡江隨鳥影，擁樹隔猿吟。莫隱高唐去，枯苗待作霖。"]'),
('yuding-22','春懷','杜牧','唐','御定全唐诗','yuding','','[]','年光何太急，倏忽又青春。明月誰為主，江山暗換人。',48,'御定全唐詩/json/525.json','["年光何太急，倏忽又青春。明月誰為主，江山暗換人。", "鶯花潛運老，榮樂漸成塵。遙憶朱門柳，別離應更頻。"]'),
('yuding-23','逢故人','杜牧','唐','御定全唐诗','yuding','','[]','年年不相見，相見卻成悲。教我淚如霰，嗟君發似絲。',48,'御定全唐詩/json/525.json','["年年不相見，相見卻成悲。教我淚如霰，嗟君發似絲。", "正傷攜手處，況值落花時。莫惜今宵醉，人間忽忽期。"]'),
('yuding-24','閑題','杜牧','唐','御定全唐诗','yuding','','[]','男兒所在即為家，百鎰黃金一朵花。',32,'御定全唐詩/json/525.json','["男兒所在即為家，百鎰黃金一朵花。", "借問春風何處好，綠楊深巷馬頭斜。"]'),
('yuding-25','金谷園','杜牧','唐','御定全唐诗','yuding','','[]','繁華事散逐香塵，流水無情草自春。',32,'御定全唐詩/json/525.json','["繁華事散逐香塵，流水無情草自春。", "日暮東風怨啼鳥，落花猶似墮樓人。"]'),
('yuding-26','重登科','杜牧','唐','御定全唐诗','yuding','','[]','星漢離宮月出輪，滿街含笑綺羅春。',32,'御定全唐詩/json/525.json','["星漢離宮月出輪，滿街含笑綺羅春。", "花前每被青蛾問，何事重來隻一人。"]'),
('yuding-27','游邊','杜牧','唐','御定全唐诗','yuding','','[]','黃沙連海路無塵，邊草長枯不見春。',32,'御定全唐詩/json/525.json','["黃沙連海路無塵，邊草長枯不見春。", "日暮拂雲堆下過，馬前逢著射雕人。"]'),
('yuding-28','將赴池州道中作','杜牧','唐','御定全唐诗','yuding','','[]','青陽雲水去年尋，黃絹歌詩出翰林。投轄暫停留酒客，',40,'御定全唐詩/json/525.json','["青陽雲水去年尋，黃絹歌詩出翰林。投轄暫停留酒客，", "南去南來盡鄉國，月明秋水只沉沉。"]'),
('yuding-29','隋宮春','杜牧','唐','御定全唐诗','yuding','','[]','龍舟東下事成空，蔓草萋萋滿故宮。',32,'御定全唐詩/json/525.json','["龍舟東下事成空，蔓草萋萋滿故宮。", "亡國亡家為顏色，露桃猶自恨春風。"]'),
('yuding-30','蠻中醉','杜牧','唐','御定全唐诗','yuding','','[]','瘴塞蠻江入洞流，人家多在竹棚頭。',32,'御定全唐詩/json/525.json','["瘴塞蠻江入洞流，人家多在竹棚頭。", "青山海上無城郭，唯見松牌出象州。"]'),
('yuding-31','寓題','杜牧','唐','御定全唐诗','yuding','','[]','把酒直須判酩酊，逢花莫惜暫淹留。',32,'御定全唐詩/json/525.json','["把酒直須判酩酊，逢花莫惜暫淹留。", "假如三萬六千日，半是悲哀半是愁。"]'),
('yuding-32','送趙十二赴舉','杜牧','唐','御定全唐诗','yuding','','[]','省事卻因多事力，無心翻似有心來。',32,'御定全唐詩/json/525.json','["省事卻因多事力，無心翻似有心來。", "秋風郡閣殘花在，別後何人更一杯。"]'),
('yuding-33','偶呈鄭先輩','杜牧','唐','御定全唐诗','yuding','','[]','不語亭亭儼薄妝，畫裙雙鳳鬱金香。',32,'御定全唐詩/json/525.json','["不語亭亭儼薄妝，畫裙雙鳳鬱金香。", "西京才子旁看取，何似喬家那窈娘。"]'),
('yuding-34','《子規','杜牧','唐','御定全唐诗','yuding','','[]','蜀地曾聞子規鳥，宣城又見杜鵑花。',32,'御定全唐詩/json/525.json','["蜀地曾聞子規鳥，宣城又見杜鵑花。", "一叫一回腸一斷，三春三月憶三巴。"]'),
('yuding-35','江樓','杜牧','唐','御定全唐诗','yuding','','[]','獨酌芳春酒，登樓已半醺。誰驚一行雁，沖斷過江雲。',24,'御定全唐詩/json/525.json','["獨酌芳春酒，登樓已半醺。誰驚一行雁，沖斷過江雲。"]'),
('yuding-36','旅宿','杜牧','唐','御定全唐诗','yuding','','[]','旅館無良伴，凝情自悄然。寒燈思舊事，斷雁警愁眠。',48,'御定全唐詩/json/525.json','["旅館無良伴，凝情自悄然。寒燈思舊事，斷雁警愁眠。", "遠夢歸侵曉，家書到來年。湘江好煙月，門系釣魚船。"]'),
('yuding-37','杜鵑','杜牧','唐','御定全唐诗','yuding','','[]','杜宇竟何冤，年年叫蜀門。至今銜積恨，終古吊殘魂。',48,'御定全唐詩/json/525.json','["杜宇竟何冤，年年叫蜀門。至今銜積恨，終古吊殘魂。", "芳草迷腸結，紅花染血痕。山川盡春色，嗚咽複誰論。"]'),
('yuding-38','聞蟬','杜牧','唐','御定全唐诗','yuding','','[]','火雲初似滅，曉角欲微清。故國行千里，新蟬忽數聲。',48,'御定全唐詩/json/525.json','["火雲初似滅，曉角欲微清。故國行千里，新蟬忽數聲。", "時行仍仿佛，度日更分明。不敢頻傾耳，唯憂白髮生。"]'),
('yuding-39','送友人','杜牧','唐','御定全唐诗','yuding','','[]','十載名兼利，人皆與命爭。青春留不住，白髮自然生。',48,'御定全唐詩/json/525.json','["十載名兼利，人皆與命爭。青春留不住，白髮自然生。", "夜雨滴鄉思，秋風從別情。都門五十裏，馳馬逐雞聲。"]'),
('yuding-40','旅情','杜牧','唐','御定全唐诗','yuding','','[]','窗虛枕簟涼，寢倦憶瀟湘。山色幾時老，人心終日忙。',48,'御定全唐詩/json/525.json','["窗虛枕簟涼，寢倦憶瀟湘。山色幾時老，人心終日忙。", "松風半夜雨，簾月滿堂霜。匹馬好歸去，江頭橘正香。"]'),
('yuding-41','曉望','杜牧','唐','御定全唐诗','yuding','','[]','獨起望山色，水雞鳴蓼洲。房星隨月曉，楚木向雲秋。',48,'御定全唐詩/json/525.json','["獨起望山色，水雞鳴蓼洲。房星隨月曉，楚木向雲秋。", "曲渚疑江盡，平沙似浪浮。秦原在何處，澤國碧悠悠。"]'),
('yuding-42','貽友人','杜牧','唐','御定全唐诗','yuding','','[]','自是東西客，逢人又送人。不應相見老，只是別離頻。',48,'御定全唐詩/json/525.json','["自是東西客，逢人又送人。不應相見老，只是別離頻。", "度日還知暮，平生未識春。儻無遷穀分，歸去養天真。"]'),
('yuding-43','書事','杜牧','唐','御定全唐诗','yuding','','[]','自笑走紅塵，流年舊複新。東風半夜雨，南國萬家春。',48,'御定全唐詩/json/525.json','["自笑走紅塵，流年舊複新。東風半夜雨，南國萬家春。", "失計拋魚艇，何門化涸鱗。是誰添歲月，老卻暗投人。"]'),
('yuding-44','別鶴','杜牧','唐','御定全唐诗','yuding','','[]','分飛共所從，六翮勢催風。聲斷碧雲外，影孤明月中。',48,'御定全唐詩/json/525.json','["分飛共所從，六翮勢催風。聲斷碧雲外，影孤明月中。", "青田歸路遠，丹桂舊巢空。矯翼知何處，天涯不可窮。"]'),
('yuding-45','晚泊','杜牧','唐','御定全唐诗','yuding','','[]','帆濕去悠悠，停橈宿渡頭。亂煙迷野岸，獨鳥出中流。',48,'御定全唐詩/json/525.json','["帆濕去悠悠，停橈宿渡頭。亂煙迷野岸，獨鳥出中流。", "篷雨延鄉夢，江風阻暮秋。儻無身外事，甘老向扁舟。"]'),
('yuding-46','山寺','杜牧','唐','御定全唐诗','yuding','','[]','峭壁引行徑，截溪開石門。泉飛濺虛檻，雲起漲河軒。',48,'御定全唐詩/json/525.json','["峭壁引行徑，截溪開石門。泉飛濺虛檻，雲起漲河軒。", "隔水看來路，疏籬見定猿。未閑難久住，歸去複何言。"]'),
('yuding-47','早行','杜牧','唐','御定全唐诗','yuding','','[]','垂鞭信馬行，數裏未雞鳴。林下帶殘夢，葉飛時忽驚。',48,'御定全唐詩/json/525.json','["垂鞭信馬行，數裏未雞鳴。林下帶殘夢，葉飛時忽驚。", "霜凝孤鶴迥，月曉遠山橫。僮僕休辭險，時平路複平。"]'),
('yuding-48','秋日偶題','杜牧','唐','御定全唐诗','yuding','','[]','荷花兼柳葉，彼此不勝秋。玉露滴初泣，金風吹更愁。',48,'御定全唐詩/json/525.json','["荷花兼柳葉，彼此不勝秋。玉露滴初泣，金風吹更愁。", "綠眉甘棄墜，紅臉恨飄流。歎息是遊子，少年還白頭。"]'),
('yuding-49','憶歸','杜牧','唐','御定全唐诗','yuding','','[]','新城非故里，終日想柴扃。興罷花還落，愁來酒欲醒。',48,'御定全唐詩/json/525.json','["新城非故里，終日想柴扃。興罷花還落，愁來酒欲醒。", "何人初發白，幾處亂山青。遠憶湘江上，漁歌對月聽。"]'),
('yuding-50','偶見','杜牧','唐','御定全唐诗','yuding','','[]','朔風高緊掠河樓，白鼻騧郎白罽裘。',32,'御定全唐詩/json/525.json','["朔風高緊掠河樓，白鼻騧郎白罽裘。", "有個當壚明似月，馬鞭斜揖笑回頭。"]'),
('yuding-51','醉倒','杜牧','唐','御定全唐诗','yuding','','[]','日晴空樂下仙雲，俱在涼亭送使君。',32,'御定全唐詩/json/525.json','["日晴空樂下仙雲，俱在涼亭送使君。", "莫辭一盞即相請，還是三年更不聞。"]'),
('yuding-52','酬許十三秀才兼依來韻','杜牧','唐','御定全唐诗','yuding','','[]','多為裁詩步竹軒，有時凝思過朝昏。篇成敢道懷金璞，',40,'御定全唐詩/json/525.json','["多為裁詩步竹軒，有時凝思過朝昏。篇成敢道懷金璞，", "憑君把卷侵寒燭，麗句時傳畫戟門。"]'),
('yuding-53','後池泛舟送王十秀才','杜牧','唐','御定全唐诗','yuding','','[]','城日晚悠悠，弦歌在碧流。夕風飄度曲，煙嶼隱行舟。',48,'御定全唐詩/json/525.json','["城日晚悠悠，弦歌在碧流。夕風飄度曲，煙嶼隱行舟。", "問拍擬新令，憐香占彩球。當筵雖一醉，寧複緩離愁。"]'),
('yuding-54','書情','杜牧','唐','御定全唐诗','yuding','','[]','誰家洛浦神，十四五來人。媚發輕垂額，香衫軟著身。',48,'御定全唐詩/json/525.json','["誰家洛浦神，十四五來人。媚發輕垂額，香衫軟著身。", "摘蓮紅袖濕，窺淥翠蛾頻。飛鵲徒來往，平陽公主親。"]'),
('yuding-55','兵部尚書席上作','杜牧','唐','御定全唐诗','yuding','','[]','華堂今日綺筵開，誰喚分司禦史來。',32,'御定全唐詩/json/525.json','["華堂今日綺筵開，誰喚分司禦史來。", "偶發狂言驚滿坐，三重粉面一時回。"]'),
('yuding-56','驌驦阪','杜牧','唐','御定全唐诗','yuding','','[]','荊州一萬里，不如蒯易度。仰首望飛鳴，伊人何異趣。',24,'御定全唐詩/json/525.json','["荊州一萬里，不如蒯易度。仰首望飛鳴，伊人何異趣。"]'),
('yuding-0','冬日五湖館水亭懷別','杜牧','唐','御定全唐诗','yuding','','[]','蘆荻花多觸處飛，獨憑虛檻雨微微。寒林葉落鳥巢出，',40,'御定全唐詩/json/526.json','["蘆荻花多觸處飛，獨憑虛檻雨微微。寒林葉落鳥巢出，", "江城向晚西流急，無限鄉心聞擣衣。"]'),
('yuding-1','不寢','杜牧','唐','御定全唐诗','yuding','','[]','到曉不成夢，思量堪白頭。多無百年命，長有萬般愁。',48,'御定全唐詩/json/526.json','["到曉不成夢，思量堪白頭。多無百年命，長有萬般愁。", "世路應難盡，營生卒未休。莫言名與利，名利是身仇。"]'),
('yuding-2','泊松江','杜牧','唐','御定全唐诗','yuding','','[]','清露白雲明月天，與君齊棹木蘭船。',32,'御定全唐詩/json/526.json','["清露白雲明月天，與君齊棹木蘭船。", "南湖風雨一相失，夜泊橫塘心渺然。"]'),
('yuding-3','題水西寺','杜牧','唐','御定全唐诗','yuding','','[]','三日去還住，一生焉再遊。含情碧溪水，重上粲公樓。',24,'御定全唐詩/json/526.json','["三日去還住，一生焉再遊。含情碧溪水，重上粲公樓。"]'),
('yuding-4','贈別宣州崔群相公','杜牧','唐','御定全唐诗','yuding','','[]','衰散相逢洛水邊，卻思同在紫薇天。',32,'御定全唐詩/json/526.json','["衰散相逢洛水邊，卻思同在紫薇天。", "盡將舟楫板橋去，早晚歸來更濟川。"]'),
('yuding-5','聞開江相國宋下世二首','杜牧','唐','御定全唐诗','yuding','','[]','權門陰進奪移才，驛騎如星墮峽來。晁氏有恩忠作禍，',80,'御定全唐詩/json/526.json','["權門陰進奪移才，驛騎如星墮峽來。晁氏有恩忠作禍，", "畢竟成功何處是，五湖雲月一帆開。", "月落清湘棹不喧，玉杯瑤瑟奠蘋蘩。誰令力制乘軒鶴，", "宵衣旰食明天子，日伏青蒲不為言。"]'),
('yuding-6','出關','杜牧','唐','御定全唐诗','yuding','','[]','朝纓初解佐江濆，麋鹿心知自有群。漢囿獵稀慵獻賦，',40,'御定全唐詩/json/526.json','["朝纓初解佐江濆，麋鹿心知自有群。漢囿獵稀慵獻賦，", "關吏不須迎馬笑，去時無意學終軍。"]'),
('yuding-7','暝投雲智寺渡溪不得，卻取沿江路往','杜牧','唐','御定全唐诗','yuding','','[]','雙岩瀉一川，回馬斷橋前。古廟陰風地，寒鐘暮雨天。',48,'御定全唐詩/json/526.json','["雙岩瀉一川，回馬斷橋前。古廟陰風地，寒鐘暮雨天。", "沙虛留虎跡，水滑帶龍涎。卻下臨江路，潮深無渡船。"]'),
('yuding-8','宣城贈蕭兵曹','杜牧','唐','御定全唐诗','yuding','','[]','桂楫謫湘渚，三年波上春。舟寒句溪雪，衣故洛城塵。',96,'御定全唐詩/json/526.json','["桂楫謫湘渚，三年波上春。舟寒句溪雪，衣故洛城塵。", "客道恥搖尾，皇恩寬犯鱗。花時去國遠，月夕上樓頻。", "賒酒不辭病，傭書非為貧。行吟值漁父，坐隱對樵人。", "紫陌罷雙轍，碧潭窮一綸。高秋更南去，煙水是通津。"]'),
('yuding-9','過鮑溶宅有感','杜牧','唐','御定全唐诗','yuding','','[]','寥落故人宅，重來身已亡。古苔殘墨沼，深竹舊書堂。',48,'御定全唐詩/json/526.json','["寥落故人宅，重來身已亡。古苔殘墨沼，深竹舊書堂。", "秋色池館靜，雨聲雲木涼。無因展交道，日暮倍心傷。"]'),
('yuding-10','《寄兄弟','杜牧','唐','御定全唐诗','yuding','','[]','江城紅葉盡，旅思倍淒涼。孤夢家山遠，獨眠秋夜長。',48,'御定全唐詩/json/526.json','["江城紅葉盡，旅思倍淒涼。孤夢家山遠，獨眠秋夜長。", "道存空倚命，身賤未歸鄉。南望仍垂淚，天邊雁一行。"]'),
('yuding-11','秋日','杜牧','唐','御定全唐诗','yuding','','[]','有計自安業，秋風罷遠吟。買山惟種竹，對客更彈琴。',48,'御定全唐詩/json/526.json','["有計自安業，秋風罷遠吟。買山惟種竹，對客更彈琴。", "煙起藥廚晚，杵聲松院深。閑眠得真性，惆悵舊時心。"]'),
('yuding-12','卜居招書侶','杜牧','唐','御定全唐诗','yuding','','[]','憶昨未知道，臨川每羨魚。世途行處見，人事病來疏。',48,'御定全唐詩/json/526.json','["憶昨未知道，臨川每羨魚。世途行處見，人事病來疏。", "微雨秋栽竹，孤燈夜讀書。憐君亦同志，晚歲傍山居。"]'),
('yuding-13','西山草堂','杜牧','唐','御定全唐诗','yuding','','[]','何處人事少，西峰舊草堂。曬書秋日晚，洗藥石泉香。',48,'御定全唐詩/json/526.json','["何處人事少，西峰舊草堂。曬書秋日晚，洗藥石泉香。", "後嶺有微雨，北窗生曉涼。徒勞問歸路，峰疊繞家鄉。"]'),
('yuding-14','貽隱者','杜牧','唐','御定全唐诗','yuding','','[]','回報隱居山，莫憂山興闌。求人顏色盡，知道性情寬。',48,'御定全唐詩/json/526.json','["回報隱居山，莫憂山興闌。求人顏色盡，知道性情寬。", "信譜彈琴誤，緣崖劚藥難。東皋亦自給，殊愧遠相安。"]'),
('yuding-15','石池','杜牧','唐','御定全唐诗','yuding','','[]','通竹引泉脈，泓澄深石盆。驚魚翻藻葉，浴鳥上松根。',48,'御定全唐詩/json/526.json','["通竹引泉脈，泓澄深石盆。驚魚翻藻葉，浴鳥上松根。", "殘月留山影，高風耗水痕。誰家洗秋藥，來往自開門。"]'),
('yuding-16','送蘇協律從事振武','杜牧','唐','御定全唐诗','yuding','','[]','琴尊詩思勞，更欲學龍韜。王粲暫投筆，呂虔初佩刀。',48,'御定全唐詩/json/526.json','["琴尊詩思勞，更欲學龍韜。王粲暫投筆，呂虔初佩刀。", "夜吟關月苦，秋望塞雲高。去去從軍樂，雕飛岱馬豪。"]'),
('yuding-17','懷政禪師院','杜牧','唐','御定全唐诗','yuding','','[]','山齋路幾層，敗衲學真乘。寒暑移雙樹，光陰盡一燈。',48,'御定全唐詩/json/526.json','["山齋路幾層，敗衲學真乘。寒暑移雙樹，光陰盡一燈。", "風飄高竹雪，泉漲小池冰。莫訝頻來此，修身欲到僧。"]'),
('yuding-18','送荔浦蔣明府赴任','杜牧','唐','御定全唐诗','yuding','','[]','路長春欲盡，歌怨酒多酣。白社蓮塘北，青袍桂水南。',48,'御定全唐詩/json/526.json','["路長春欲盡，歌怨酒多酣。白社蓮塘北，青袍桂水南。", "驛行盤鳥道，船宿避龍潭。真得詩人趣，煙霞處處諳。"]'),
('yuding-19','秋夕有懷','杜牧','唐','御定全唐诗','yuding','','[]','念遠坐西閣，華池涵月涼。書回秋欲盡，酒醒夜初長。',48,'御定全唐詩/json/526.json','["念遠坐西閣，華池涵月涼。書回秋欲盡，酒醒夜初長。", "露白蓮衣淺，風清蕙帶香。前年此佳景，蘭棹醉橫塘。"]'),
('yuding-20','秋霽寄遠','杜牧','唐','御定全唐诗','yuding','','[]','初霽獨登賞，西樓多遠風。橫煙秋水上，疏雨夕陽中。',48,'御定全唐詩/json/526.json','["初霽獨登賞，西樓多遠風。橫煙秋水上，疏雨夕陽中。", "高樹下山鳥，平蕪飛草蟲。唯應待明月，千里與君同。"]'),
('yuding-21','經古行宮','杜牧','唐','御定全唐诗','yuding','','[]','台閣參差倚太陽，年年花發滿山香。重門勘鎖青春晚，',40,'御定全唐詩/json/526.json','["台閣參差倚太陽，年年花發滿山香。重門勘鎖青春晚，", "先皇一去無回駕，紅粉雲環空斷腸。"]'),
('yuding-22','宣州開元寺贈惟真上人','杜牧','唐','御定全唐诗','yuding','','[]','曾與徑山為小師，千年僧行眾人知。夜深月色當禪處，',40,'御定全唐詩/json/526.json','["曾與徑山為小師，千年僧行眾人知。夜深月色當禪處，", "勸君莫厭江城客，雖在風塵別有期。"]'),
('yuding-23','秋晚懷茅山石涵村舍','杜牧','唐','御定全唐诗','yuding','','[]','十畝山田近石涵，村居風俗舊曾諳。簾前白艾驚春燕，',40,'御定全唐詩/json/526.json','["十畝山田近石涵，村居風俗舊曾諳。簾前白艾驚春燕，", "陵陽秋盡多歸思，紅樹蕭蕭覆碧潭。"]'),
('yuding-24','留題李侍禦書齋','杜牧','唐','御定全唐诗','yuding','','[]','曾話平生志，書齋幾見留。道孤心易感，恩重力難酬。',48,'御定全唐詩/json/526.json','["曾話平生志，書齋幾見留。道孤心易感，恩重力難酬。", "獨立千峰晚，頻來一葉秋。雞鳴應有處，不學淚空流。"]'),
('yuding-25','行次白沙館，先寄上河南王侍郎','杜牧','唐','御定全唐诗','yuding','','[]','夜程何處宿，山疊樹層層。孤館閑秋雨，空堂停曙燈。',48,'御定全唐詩/json/526.json','["夜程何處宿，山疊樹層層。孤館閑秋雨，空堂停曙燈。", "歌慚漁浦客，詩學雁門僧。此意無人識，明朝見李膺。"]'),
('yuding-26','貴游','杜牧','唐','御定全唐诗','yuding','','[]','朝回佩馬草萋萋，年少恩深衛霍齊。斧鉞舊威龍塞北，',40,'御定全唐詩/json/526.json','["朝回佩馬草萋萋，年少恩深衛霍齊。斧鉞舊威龍塞北，", "南陌行人盡回首，笙歌一曲暮雲低。"]'),
('yuding-27','越中','杜牧','唐','御定全唐诗','yuding','','[]','石城花暖鷓鴣飛，征客春帆秋不歸。',32,'御定全唐詩/json/526.json','["石城花暖鷓鴣飛，征客春帆秋不歸。", "猶自保郎心似石，綾梭夜夜織寒衣。"]'),
('yuding-28','聞范秀才自蜀游江湖','杜牧','唐','御定全唐诗','yuding','','[]','蜀道下湘渚，客帆應不迷。江分三峽響，山並九華齊。',48,'御定全唐詩/json/526.json','["蜀道下湘渚，客帆應不迷。江分三峽響，山並九華齊。", "秋泊雁初宿，夜吟猿乍啼。歸時慎行李，莫到石城西。"]'),
('yuding-29','綠蘿','杜牧','唐','御定全唐诗','yuding','','[]','綠蘿縈數匝，本在草堂間。秋色寄高樹，晝陰籠近山。',48,'御定全唐詩/json/526.json','["綠蘿縈數匝，本在草堂間。秋色寄高樹，晝陰籠近山。", "移花疏處過，劚藥困時攀。日暮微風起，難尋舊徑還。"]'),
('yuding-30','宿東橫山瀨','杜牧','唐','御定全唐诗','yuding','','[]','孤舟路漸賒，時見碧桃花。溪雨灘聲急，岩風樹勢斜。',48,'御定全唐詩/json/526.json','["孤舟路漸賒，時見碧桃花。溪雨灘聲急，岩風樹勢斜。", "獼猴懸弱柳，鸂鶒睡橫楂。謾向仙林宿，無人識阮家。"]'),
('yuding-31','貽遷客','杜牧','唐','御定全唐诗','yuding','','[]','無機還得罪，直道不傷情。微雨昏山色，疏籠閉鶴聲。',48,'御定全唐詩/json/526.json','["無機還得罪，直道不傷情。微雨昏山色，疏籠閉鶴聲。", "閒居多野客，高枕見江城。門外長溪水，憐君又濯纓。"]'),
('yuding-32','陵陽送客','杜牧','唐','御定全唐诗','yuding','','[]','南樓送郢客，西郭望荊門。鳧鵠下寒渚，牛羊歸遠村。',48,'御定全唐詩/json/526.json','["南樓送郢客，西郭望荊門。鳧鵠下寒渚，牛羊歸遠村。", "蘭舟倚行棹，桂酒掩餘樽。重此一留宿，前汀煙月昏。"]'),
('yuding-33','寄桐江隱者','杜牧','唐','御定全唐诗','yuding','','[]','潮去潮來洲渚春，山花如繡草如茵。',32,'御定全唐詩/json/526.json','["潮去潮來洲渚春，山花如繡草如茵。", "嚴陵台下桐江水，解釣鱸魚能幾人。"]'),
('yuding-34','長興裏夏日寄南鄰避暑','杜牧','唐','御定全唐诗','yuding','','[]','侯家大道傍，蟬噪樹蒼蒼。開鎖洞門遠，捲簾官舍涼。',48,'御定全唐詩/json/526.json','["侯家大道傍，蟬噪樹蒼蒼。開鎖洞門遠，捲簾官舍涼。", "欄圍紅藥盛，架引綠蘿長。永日一欹枕，故山雲水鄉。"]'),
('yuding-35','送太昱禪師','杜牧','唐','御定全唐诗','yuding','','[]','禪床深竹裏，心與徑山期。結社多高客，登壇盡小師。',48,'御定全唐詩/json/526.json','["禪床深竹裏，心與徑山期。結社多高客，登壇盡小師。", "早秋歸寺遠，新雨上灘遲。別後江雲碧，南齋一首詩。"]'),
('yuding-36','梁秀才以早春旅次大梁將歸郊扉言懷兼別示亦蒙見贈凡二十韻走筆依韻','杜牧','唐','御定全唐诗','yuding','','[]','玉塞功猶阻，金門事已陳。世途皆擾擾，鄉黨盡循循。',240,'御定全唐詩/json/526.json','["玉塞功猶阻，金門事已陳。世途皆擾擾，鄉黨盡循循。", "客道難投足，家聲易發身。松篁標節晚，蘭蕙吐詞春。", "處困羞搖尾，懷忠壯犯鱗。宅臨三楚水，衣帶二京塵。", "斂跡愁山鬼，遺形慕穀神。采芝先避貴，栽橘早防貧。", "弦泛桐材響，杯澄糯醁醇。但尋陶令集，休獻楚王珍。", "林密聞風遠，池平見月勻。藤龕紅婀娜，苔磴綠嶙峋。", "雪樹交梁苑，冰河漲孟津。面邀文作友，心許德為鄰。", "旅館將分被，嬰兒共灑巾。渭陽連漢曲，京口接漳濱。", "通塞時應定，榮枯理會均。儒流當自勉，妻族更誰親。", "照矚三光政，生成四氣仁。磻溪有心者，垂白肯湮淪。"]'),
('yuding-37','川守大夫劉公早歲寓居敦行里肆有題壁十韻今之置第乃獲舊居洛下大僚因有唱和歎詠不足輒獻此詩','杜牧','唐','御定全唐诗','yuding','','[]','旅館當年葺，公才此日論。林繁輕竹祖，樹暗惜桐孫。',120,'御定全唐詩/json/526.json','["旅館當年葺，公才此日論。林繁輕竹祖，樹暗惜桐孫。", "煉藥藏金鼎，疏泉陷石盆。散科松有節，深薙草無根。", "龍臥池猶在，鶯遷谷尚存。昔為揚子宅，今是李膺門。", "積學螢嘗聚，微詞鳳早吞。百年明素志，三顧起新恩。", "雪耀冰霜冷，塵飛水墨昏。莫教垂露跡，歲晚雜苔痕。"]'),
('yuding-38','中秋日拜起居表晨渡天津橋即事十六韻獻居守相國崔公兼呈工部劉公','杜牧','唐','御定全唐诗','yuding','','[]','碧樹康莊內，清川鞏洛間。壇分中嶽頂，城繚大河灣。',192,'御定全唐詩/json/526.json','["碧樹康莊內，清川鞏洛間。壇分中嶽頂，城繚大河灣。", "廣殿含涼靜，深宮積翠閑。樓齊雲漠漠，橋束水潺潺。", "過雨檉枝潤，迎霜柿葉殷。紫鱗沖晚浪，白鳥背秋山。", "月拜西歸表，晨趨北向班，鴛鴻隨半仗，貔虎護重關。", "玉帳才容足，金樽暫解顏。跡留傷墮屨，恩在樂銜環。", "南省蘭先握，東堂桂早攀。龍門君夭矯，鶯穀我綿蠻。", "分薄嵇心懶，哀多庾鬢班。人慚公幹臥，頻送子牟還。", "自睹宸居壯，誰憂國步艱。只應時與醉，因病縱疏頑。"]'),
('yuding-39','分司東都寓居履道叨承川尹劉侍郎大夫恩知上四十韻','杜牧','唐','御定全唐诗','yuding','','[]','命世須人瑞，匡君在嶽靈。氣和熏北陸，襟曠納東溟。',480,'御定全唐詩/json/526.json','["命世須人瑞，匡君在嶽靈。氣和熏北陸，襟曠納東溟。", "賦妙排鸚鵡，詩能繼鶺鴒。蒲親香案色，蘭動粉闈馨。", "周孔傳文教，蕭曹授武經。家僮諳禁掖，廄馬識金鈴。", "性與奸邪背，心因啟沃冥。進賢光日月，誅惡助雷霆。", "閶闔開時召，簫韶奏處聽。水精懸禦幄，雲母展宮屏。", "捧詔巡汧隴，飛書護井陘。先聲威虎兕，餘力活蟭螟。", "榮重秦軍箭，功高漢將銘。戈鋋回紫塞，幹戚散彤庭。", "順美皇恩洽，扶顛國步寧。禹謨推掌誥，湯網屬司刑。", "稚榻蓬萊掩，膺舟鞏洛停。馬群先去害，民籍更添丁。", "猾吏門長塞，豪家戶不扃。四知臺上鏡，三惑井中瓶。", "雅韻憑開匣，雄鋩待發硎。火中膠綠樹，泉下劚青萍。", "五嶽期雙節，三台空一星。鳳池方注意，麟閣會圖形。", "寒暑逾流電，光陰甚建瓴。散曹分已白，崇直眼由青。", "賜第成官舍，傭居起客亭。松筠侵巷陌，禾黍接郊坰。", "宿雨回為沼。春沙澱作汀。魚罾棲翡翠，蛛網掛蜻蜓。", "遲曉河初轉，傷秋露已零。夢餘鐘杳杳，吟罷燭熒熒。", "字小書難寫，杯遲酒易醒。久貧驚早雁，多病放殘螢。", "雪勁孤根竹，風凋數莢蓂。轉喉空婀娜，垂手自娉婷。", "脛細摧新履，腰羸減舊鞓。海邊慵逐臭，塵外怯吞腥。", "隱豹窺重巘，潛虯避濁涇。商歌如不顧，歸棹越南𤃩。"]'),
('yuding-40','題白雲樓','杜牧','唐','御定全唐诗','yuding','','[]','西北樓開四望通，殘霞成綺月懸弓。江村夜漲浮天水，',40,'御定全唐詩/json/526.json','["西北樓開四望通，殘霞成綺月懸弓。江村夜漲浮天水，", "才微分薄憂何益，卻欲回心學塞翁。"]'),
('yuding-41','贈別','杜牧','唐','御定全唐诗','yuding','','[]','眼前迎送不曾休，相續輪蹄似水流。門外若無南北路，',40,'御定全唐詩/json/526.json','["眼前迎送不曾休，相續輪蹄似水流。門外若無南北路，", "莫怪分襟銜淚語，十年耕釣憶滄洲。"]'),
('yuding-42','秋夜與友人宿','杜牧','唐','御定全唐诗','yuding','','[]','楚國同遊過十霜，萬重心事幾堪傷。蒹葭露白蓮塘淺，',40,'御定全唐詩/json/526.json','["楚國同遊過十霜，萬重心事幾堪傷。蒹葭露白蓮塘淺，", "寒城欲曉聞吹笛，猶臥東軒月滿床。"]'),
('yuding-43','將赴京留贈僧院','杜牧','唐','御定全唐诗','yuding','','[]','九衢塵土遞追攀，馬跡軒車日暮間。玄發盡驚為客換，',40,'御定全唐詩/json/526.json','["九衢塵土遞追攀，馬跡軒車日暮間。玄發盡驚為客換，", "謝卻從前受恩地，歸來依止叩禪關。"]'),
('yuding-44','寄湘中友人','杜牧','唐','御定全唐诗','yuding','','[]','莫戀醉鄉迷酒杯，流年長怕少年催。西陵水闊魚難到，',40,'御定全唐詩/json/526.json','["莫戀醉鄉迷酒杯，流年長怕少年催。西陵水闊魚難到，", "相如已定題橋志，江上無由夢釣台。"]'),
('yuding-45','江上逢友人','杜牧','唐','御定全唐诗','yuding','','[]','故國歸人酒一杯，暫停蘭棹共裴回。村連三峽暮雲起，',40,'御定全唐詩/json/526.json','["故國歸人酒一杯，暫停蘭棹共裴回。村連三峽暮雲起，", "到時若見東籬菊，為問經霜幾度開。"]'),
('yuding-46','金谷懷古','杜牧','唐','御定全唐诗','yuding','','[]','淒涼遺跡洛川東，浮世榮枯萬古同。桃李香消金穀在，',40,'御定全唐詩/json/526.json','["淒涼遺跡洛川東，浮世榮枯萬古同。桃李香消金穀在，", "徒想夜泉流客恨，夜泉流恨恨無窮。"]'),
('yuding-47','寄盧先輩','杜牧','唐','御定全唐诗','yuding','','[]','一從分首劍江濱，南國相思寄夢頻。書去又逢商嶺雪，',40,'御定全唐詩/json/526.json','["一從分首劍江濱，南國相思寄夢頻。書去又逢商嶺雪，", "願指丹梯曾到處，莫教猶作獨迷人。"]'),
('yuding-48','南樓夜','杜牧','唐','御定全唐诗','yuding','','[]','玉管金樽夜不休，如悲晝短惜年流。歌聲嫋嫋徹清夜，',40,'御定全唐詩/json/526.json','["玉管金樽夜不休，如悲晝短惜年流。歌聲嫋嫋徹清夜，", "思量今日英雄事，身到簪裾已白頭。"]'),
('yuding-49','行經廬山東林寺','杜牧','唐','御定全唐诗','yuding','','[]','離魂斷續楚江壖，葉墜初紅十月天。紫陌事多難暫息，',40,'御定全唐詩/json/526.json','["離魂斷續楚江壖，葉墜初紅十月天。紫陌事多難暫息，", "他歲若教如範蠡，也應須入五湖煙。"]'),
('yuding-50','途中逢故人，話西山讀書早曾遊覽','杜牧','唐','御定全唐诗','yuding','','[]','西岩曾到讀書堂，穿竹行莎十裏強。湖上夢餘波灩灩，',40,'御定全唐詩/json/526.json','["西岩曾到讀書堂，穿竹行莎十裏強。湖上夢餘波灩灩，", "莫道少年頭不白，君看潘嶽幾莖霜。"]'),
('yuding-51','將赴京題陵陽王氏水居','杜牧','唐','御定全唐诗','yuding','','[]','簾卷平蕪接遠天，暫寬行役到樽前。是非境裏有閑日，',40,'御定全唐詩/json/526.json','["簾卷平蕪接遠天，暫寬行役到樽前。是非境裏有閑日，", "馬蹄不道貪西去，爭向一聲高樹蟬。"]'),
('yuding-52','送別','杜牧','唐','御定全唐诗','yuding','','[]','溪邊楊柳色參差，攀折年年贈別離。一片風帆望已極，',40,'御定全唐詩/json/526.json','["溪邊楊柳色參差，攀折年年贈別離。一片風帆望已極，", "莫殢酒杯閑過日，碧雲深處是佳期。"]'),
('yuding-53','寄遠','杜牧','唐','御定全唐诗','yuding','','[]','兩葉愁眉愁不開，獨含惆悵上層台。碧雲空斷雁行處，',40,'御定全唐詩/json/526.json','["兩葉愁眉愁不開，獨含惆悵上層台。碧雲空斷雁行處，", "功名待寄淩煙閣，力盡遼城不肯回。"]'),
('yuding-54','新柳','杜牧','唐','御定全唐诗','yuding','','[]','無力搖風曉色新，細腰爭妒看來頻。綠陰未覆長堤水，',40,'御定全唐詩/json/526.json','["無力搖風曉色新，細腰爭妒看來頻。綠陰未覆長堤水，", "東門門外多離別，愁殺朝朝暮暮人。"]'),
('yuding-55','旅懷作','杜牧','唐','御定全唐诗','yuding','','[]','促促因吟晝短詩，朝驚穠色暮空枝。無情春色不長久，',40,'御定全唐詩/json/526.json','["促促因吟晝短詩，朝驚穠色暮空枝。無情春色不長久，", "眼前擾擾日一日，暗送白頭人不知。"]'),
('yuding-56','雁','杜牧','唐','御定全唐诗','yuding','','[]','萬里銜蘆別故鄉，雲飛雨宿向瀟湘。數聲孤枕堪垂淚，',24,'御定全唐詩/json/526.json','["萬里銜蘆別故鄉，雲飛雨宿向瀟湘。數聲孤枕堪垂淚，"]'),
('yuding-57','惜春','杜牧','唐','御定全唐诗','yuding','','[]','花開又花落，時節暗中遷。無計延春日，何能駐少年。',48,'御定全唐詩/json/526.json','["花開又花落，時節暗中遷。無計延春日，何能駐少年。", "小叢初散蝶，高柳即聞蟬。繁豔歸何處，滿山啼杜鵑。"]'),
('yuding-58','鴛鴦','杜牧','唐','御定全唐诗','yuding','','[]','兩兩戲沙汀，長疑畫不成。錦機爭織樣，歌曲愛呼名。',48,'御定全唐詩/json/526.json','["兩兩戲沙汀，長疑畫不成。錦機爭織樣，歌曲愛呼名。", "好育顧棲息，堪憐泛淺清。鳧鷗皆爾類，惟羨獨含情。"]'),
('yuding-59','聞雁','杜牧','唐','御定全唐诗','yuding','','[]','帶霜南去雁，夜好宿汀沙。驚起向何處，高飛極海涯。',48,'御定全唐詩/json/526.json','["帶霜南去雁，夜好宿汀沙。驚起向何處，高飛極海涯。", "入雲聲漸遠，離岳路由賒。歸夢當時斷，參差欲到家。"]'),
('yuding-60','江樓晚望','杜牧','唐','御定全唐诗','yuding','','[]','湖山翠欲結蒙籠，汗漫誰遊夕照中。初語燕雛知社日，',40,'御定全唐詩/json/526.json','["湖山翠欲結蒙籠，汗漫誰遊夕照中。初語燕雛知社日，", "不欲登樓更懷古，斜陽江上正飛鴻。"]'),
('yuding-0','九日','杜牧','唐','御定全唐诗','yuding','','[]','金英繁亂拂闌香，明府辭官酒滿缸。',32,'御定全唐詩/json/527.json','["金英繁亂拂闌香，明府辭官酒滿缸。", "還有玉樓輕薄女，笑他寒燕一雙雙。"]'),
('yuding-1','寄牛相公','杜牧','唐','御定全唐诗','yuding','','[]','漢水橫沖蜀浪分，危樓點的拂孤雲。',32,'御定全唐詩/json/527.json','["漢水橫沖蜀浪分，危樓點的拂孤雲。", "六年仁政謳歌去，柳繞春堤處處聞。"]'),
('yuding-2','為人題贈二首','杜牧','唐','御定全唐诗','yuding','','[]','我乏青雲稱，君無買笑金。虛傳南國貌，爭奈五陵心。',240,'御定全唐詩/json/527.json','["我乏青雲稱，君無買笑金。虛傳南國貌，爭奈五陵心。", "桂席塵瑤佩，瓊爐燼水沉。凝魂空薦夢，低耳悔聽琴。", "月落珠簾卷，春寒錦幕深。誰家樓上笛，何處月明砧。", "蘭徑飛蝴蝶，筠籠語翠襟。和簪拋鳳髻，將淚入鴛衾。", "的的新添恨，迢迢絕好音。文園終病渴，休詠白頭吟。", "綠樹鶯鶯語，平江燕燕飛。枕前聞雁去，樓上送春歸。", "半月縆雙臉，凝腰素一圍。西牆苔漠漠，南浦夢依依。", "有恨簪花懶，無聊鬥草稀。雕籠長慘澹，蘭畹謾芳菲。", "鏡斂青蛾黛，燈挑皓腕肌。避人勻迸淚，拖袖倚殘暉。", "有貌雖桃李，單棲足是非。雲輧載馭去，寒夜看裁衣。"]'),
('yuding-3','懷紫閣山','杜牧','唐','御定全唐诗','yuding','','[]','學他趨世少深機，紫閣青霄半掩扉。山路遠懷王子晉，',40,'御定全唐詩/json/527.json','["學他趨世少深機，紫閣青霄半掩扉。山路遠懷王子晉，", "人道青山歸去好，青山曾有幾人歸。"]'),
('yuding-4','題孫逸人山居','杜牧','唐','御定全唐诗','yuding','','[]','長懸青紫與芳枝，塵刹無應免別離。馬上多於在家日，',40,'御定全唐詩/json/527.json','["長懸青紫與芳枝，塵刹無應免別離。馬上多於在家日，", "卻羨高人終此老，軒車過盡不知誰。"]'),
('yuding-5','中途寄友人','杜牧','唐','御定全唐诗','yuding','','[]','道傍高木盡依依，落葉驚風處處飛。未到鄉關聞早雁，',40,'御定全唐詩/json/527.json','["道傍高木盡依依，落葉驚風處處飛。未到鄉關聞早雁，", "何日一名隨事了，與君同采碧溪薇。"]'),
('yuding-6','悵詩','杜牧','唐','御定全唐诗','yuding','','[]','自是尋春去校遲，不須惆悵怨芳時。',32,'御定全唐詩/json/527.json','["自是尋春去校遲，不須惆悵怨芳時。", "狂風落盡深紅色，綠葉成陰子滿枝。"]'),
('yuding-7','吳宮詞二首','杜牧','唐','御定全唐诗','yuding','','[]','越兵驅綺羅，越女唱吳歌。宮燼花聲少，台荒麋跡多。',96,'御定全唐詩/json/527.json','["越兵驅綺羅，越女唱吳歌。宮燼花聲少，台荒麋跡多。", "茱萸垂曉露，菡萏落秋波。無遣君王醉，滿城嚬翠蛾。", "香徑繞吳宮，千帆落照中。鶴鳴山苦雨，魚躍水多風。", "城帶晚莎綠，池邊秋蓼紅。當年國門外，誰信伍員忠。"]'),
('yuding-8','金陵','杜牧','唐','御定全唐诗','yuding','','[]','始發碧江口，曠然諧遠心。風清舟在鑒，日落水浮金。',48,'御定全唐詩/json/527.json','["始發碧江口，曠然諧遠心。風清舟在鑒，日落水浮金。", "瓜步逢潮信，台城過雁音。故鄉何處是，雲外即喬林。"]'),
('yuding-9','即事','杜牧','唐','御定全唐诗','yuding','','[]','小院無人雨長苔，滿庭修竹間疏槐。',32,'御定全唐詩/json/527.json','["小院無人雨長苔，滿庭修竹間疏槐。", "春愁兀兀成幽夢，又被流鶯喚醒來。"]'),
('yuding-10','七夕','杜牧','唐','御定全唐诗','yuding','','[]','雲階月地一相過，未抵經年別恨多。',32,'御定全唐詩/json/527.json','["雲階月地一相過，未抵經年別恨多。", "最恨明朝洗車雨，不教回腳渡天河。"]'),
('yuding-11','薔薇花','杜牧','唐','御定全唐诗','yuding','','[]','朵朵精神葉葉柔，雨晴香拂醉人頭。',32,'御定全唐詩/json/527.json','["朵朵精神葉葉柔，雨晴香拂醉人頭。", "石家錦幛依然在，閑倚狂風夜不收。"]'),
('yuding-12','句','杜牧','唐','御定全唐诗','yuding','','[]','幽人聽達曙，聊罷蘇床琴。。',109,'御定全唐詩/json/527.json','["幽人聽達曙，聊罷蘇床琴。。", "魚多知海熟，藥少覺山貧。。", "土控吳兼越，州連歙與池。山河地襟帶，軍鎮國藩維。", "綠水棹雲月，洞庭歸路長。春橋垂酒幔，夜柵集茶檣。", "箬影沉溪暖，蘋花繞郭香。。", "經冬野菜青青色，未臘山梅樹樹花。", "半破前峰月。"]'),
('yuding-0','陪王尚書泛舟蓮池','許渾','唐','御定全唐诗','yuding','','[]','蓮塘移畫舸，泛泛日華清。水暖魚頻躍，煙秋雁早鳴。',48,'御定全唐詩/json/528.json','["蓮塘移畫舸，泛泛日華清。水暖魚頻躍，煙秋雁早鳴。", "舞疑回雪態，歌轉遏雲聲。客散山公醉，風高月滿城。"]'),
('yuding-1','贈裴處士','許渾','唐','御定全唐诗','yuding','','[]','為儒白髮生，鄉里早聞名。暖酒雪初下，讀書山欲明。',48,'御定全唐詩/json/528.json','["為儒白髮生，鄉里早聞名。暖酒雪初下，讀書山欲明。", "字形翻鳥跡，詩調合猿聲。門外滄浪水，知君欲濯纓。"]'),
('yuding-2','對雪','許渾','唐','御定全唐诗','yuding','','[]','飛舞北風涼，玉人歌玉堂。簾帷增曙色，珠翠發寒光。',48,'御定全唐詩/json/528.json','["飛舞北風涼，玉人歌玉堂。簾帷增曙色，珠翠發寒光。", "柳重絮微濕，梅繁花未香。茲辰賀豐歲，簫鼓宴梁王。"]'),
('yuding-3','王居士','許渾','唐','御定全唐诗','yuding','','[]','筇杖倚柴關，都城賣蔔還。雨中耕白水，雲外劚青山。',48,'御定全唐詩/json/528.json','["筇杖倚柴關，都城賣蔔還。雨中耕白水，雲外劚青山。", "有藥身長健，無機性自閑。即應生羽翼，華表在人間。"]'),
('yuding-4','早秋三首','許渾','唐','御定全唐诗','yuding','','[]','遙夜泛清瑟，西風生翠蘿。殘螢委玉露，早雁拂銀河。',144,'御定全唐詩/json/528.json','["遙夜泛清瑟，西風生翠蘿。殘螢委玉露，早雁拂銀河。", "高樹曉還密，遠山晴更多。淮南一葉下，自覺老煙波。", "一葉下前墀，淮南人已悲。蹉跎青漢望，迢遞白雲期。", "老信相如渴，貧憂曼倩饑。生公與園吏，何處是吾師。", "薊北雁猶遠，淮南人已悲。殘桃間墮井，新菊亦侵籬。", "書劍豈相誤，琴尊聊自持。西齋風雨夜，更有詠貧詩。"]'),
('yuding-5','洛東蘭若夜歸','許渾','唐','御定全唐诗','yuding','','[]','一衲老禪床，吾生半異鄉。管弦愁裏老，書劍夢中忙。',48,'御定全唐詩/json/528.json','["一衲老禪床，吾生半異鄉。管弦愁裏老，書劍夢中忙。", "鳥急山初暝，蟬稀樹正涼。又歸何處去，塵路月蒼蒼。"]'),
('yuding-6','送段覺歸杜曲閒居','許渾','唐','御定全唐诗','yuding','','[]','書劍南歸去，山扉別幾年。苔侵岩下路，果落洞中泉。',48,'御定全唐詩/json/528.json','["書劍南歸去，山扉別幾年。苔侵岩下路，果落洞中泉。", "紅葉高齋雨，青蘿曲檻煙。甯知遠遊客，羸馬太行前。"]'),
('yuding-7','寄天鄉寺仲儀上人富春孫處士','許渾','唐','御定全唐诗','yuding','','[]','詩僧與釣翁，千里兩情通。雲帶雁門雪，水連漁浦風。',48,'御定全唐詩/json/528.json','["詩僧與釣翁，千里兩情通。雲帶雁門雪，水連漁浦風。", "心期榮辱外，名掛是非中。歲晚亦歸去，田園清洛東。"]'),
('yuding-8','寄契盈上人','許渾','唐','御定全唐诗','yuding','','[]','何處是西林，疏鐘複遠砧。雁來秋水闊，鴉盡夕陽沉。',48,'御定全唐詩/json/528.json','["何處是西林，疏鐘複遠砧。雁來秋水闊，鴉盡夕陽沉。", "婚嫁乖前志，功名異夙心。湯師不可問，江上碧雲深。"]'),
('yuding-9','晨起二首','許渾','唐','御定全唐诗','yuding','','[]','桂樹綠層層，風微煙露凝。簷楹銜落月，幃幌映殘燈。',96,'御定全唐詩/json/528.json','["桂樹綠層層，風微煙露凝。簷楹銜落月，幃幌映殘燈。", "蘄簟曙香冷，越瓶秋水澄。心閑即無事，何異住山僧。", "殘月皓煙露，掩門深竹齋。水蟲鳴曲檻，山鳥下空階。", "清鏡曉看發，素琴秋寄懷。因知北窗客，日與世情乖。"]'),
('yuding-10','曉發鄞江北渡寄崔韓二先輩','許渾','唐','御定全唐诗','yuding','','[]','南北信多岐，生涯半別離。地窮山盡處，江泛水寒時。',48,'御定全唐詩/json/528.json','["南北信多岐，生涯半別離。地窮山盡處，江泛水寒時。", "露曉蒹葭重，霜晴橘柚垂。無勞促回楫，千里有心期。"]'),
('yuding-11','盈上人','許渾','唐','御定全唐诗','yuding','','[]','月沉霜已凝，無夢竟寒燈。寄世何殊客，修身未到僧。',48,'御定全唐詩/json/528.json','["月沉霜已凝，無夢竟寒燈。寄世何殊客，修身未到僧。", "二毛梳上雪，雙淚枕前冰。借問曹溪路，山多路幾層。"]'),
('yuding-12','廣陵道中','許渾','唐','御定全唐诗','yuding','','[]','城勢已坡陀，城邊東逝波。綠桑非苑樹，青草是宮莎。',48,'御定全唐詩/json/528.json','["城勢已坡陀，城邊東逝波。綠桑非苑樹，青草是宮莎。", "山暝牛羊少，水寒鳧雁多。因高一回首，還詠黍離歌。"]'),
('yuding-13','宿開元寺樓','許渾','唐','御定全唐诗','yuding','','[]','誰家歌嫋嫋，孤枕在西樓。竹色寒清簟，松香染翠幬。',48,'御定全唐詩/json/528.json','["誰家歌嫋嫋，孤枕在西樓。竹色寒清簟，松香染翠幬。", "月移珠殿曉，風遞玉箏秋。日出應移棹，三湘萬里愁。"]'),
('yuding-14','洞靈觀冬青','許渾','唐','御定全唐诗','yuding','','[]','霜霰不凋色，兩株交石壇。未秋紅實淺，經夏綠陰寒。',48,'御定全唐詩/json/528.json','["霜霰不凋色，兩株交石壇。未秋紅實淺，經夏綠陰寒。", "露重蟬鳴急，風多鳥宿難。何如西禁柳，晴舞玉闌幹。"]'),
('yuding-15','送友人自荊襄歸江東','許渾','唐','御定全唐诗','yuding','','[]','商洛轉江濆，一杯聊送君。劍愁龍失伴，琴怨鶴離群。',48,'御定全唐詩/json/528.json','["商洛轉江濆，一杯聊送君。劍愁龍失伴，琴怨鶴離群。", "楚驛枕秋水，湘帆淩暮雲。猿聲斷腸夜，應向雨中聞。"]'),
('yuding-16','送同年崔先輩','許渾','唐','御定全唐诗','yuding','','[]','西風帆勢輕，南浦遍離情。菊豔含秋水，荷花遞雨聲。',48,'御定全唐詩/json/528.json','["西風帆勢輕，南浦遍離情。菊豔含秋水，荷花遞雨聲。", "扣舷灘鳥沒，移棹草蟲鳴。更憶前年別，槐花滿鳳城。"]'),
('yuding-17','山雞','許渾','唐','御定全唐诗','yuding','','[]','珍禽暫不扃，飛舞躍前庭。翠網摧金距，雕籠減繡翎。',48,'御定全唐詩/json/528.json','["珍禽暫不扃，飛舞躍前庭。翠網摧金距，雕籠減繡翎。", "月圓疑望鏡，花暖似依屏。何必舊巢去，山山芳草青。"]'),
('yuding-18','孤雁','許渾','唐','御定全唐诗','yuding','','[]','昔年雙頡頏，池上靄春暉。霄漢力猶怯，稻粱心已違。',48,'御定全唐詩/json/528.json','["昔年雙頡頏，池上靄春暉。霄漢力猶怯，稻粱心已違。", "蘆洲寒獨宿，榆塞夜孤飛。不及營巢燕，西風相伴歸。"]'),
('yuding-19','寓懷','許渾','唐','御定全唐诗','yuding','','[]','南國浣紗伴，盈盈天下姝。盤金明繡帶，動佩響羅襦。',48,'御定全唐詩/json/528.json','["南國浣紗伴，盈盈天下姝。盤金明繡帶，動佩響羅襦。", "素手怨瑤瑟，清心悲玉壺。春華坐銷落，未忍泣蘼蕪。"]'),
('yuding-20','洛中游眺貽同志','許渾','唐','御定全唐诗','yuding','','[]','康衢一望通，河洛正天中。樓勢排高鳳，橋形架斷虹。',48,'御定全唐詩/json/528.json','["康衢一望通，河洛正天中。樓勢排高鳳，橋形架斷虹。", "遠山晴帶雪，寒水晚多風。幾日還攜手，鳥鳴花滿宮。"]'),
('yuding-21','夏日戲題郭別駕東堂','許渾','唐','御定全唐诗','yuding','','[]','微風起畫鸞，金翠暗珊珊。晚樹垂朱實，春篁露粉竿。',48,'御定全唐詩/json/528.json','["微風起畫鸞，金翠暗珊珊。晚樹垂朱實，春篁露粉竿。", "散香蘄簟滑，沉水越瓶寒。猶恐何郎熱，冰生白玉盤。"]'),
('yuding-22','長安旅夜','許渾','唐','御定全唐诗','yuding','','[]','久客怨長夜，西風吹雁聲。雲移河漢淺，月泛露華清。',48,'御定全唐詩/json/528.json','["久客怨長夜，西風吹雁聲。雲移河漢淺，月泛露華清。", "掩瑟獨凝思，緩歌空寄情。門前有歸路，迢遞洛陽城。"]'),
('yuding-23','鸂鶒','許渾','唐','御定全唐诗','yuding','','[]','池寒柳複凋，獨宿夜迢迢。雨頂冠應冷，風毛劍欲飄。',48,'御定全唐詩/json/528.json','["池寒柳複凋，獨宿夜迢迢。雨頂冠應冷，風毛劍欲飄。", "故巢迷碧水，舊侶越丹霄。不是無歸處，心高多寂寥。"]'),
('yuding-24','懿安皇太后挽歌詞','許渾','唐','御定全唐诗','yuding','','[]','陵前春不盡，陵下夜何窮。未信金蠶老，先驚玉燕空。',48,'御定全唐詩/json/528.json','["陵前春不盡，陵下夜何窮。未信金蠶老，先驚玉燕空。", "挽移蘭殿月，笳引柏城風。自此隨龍馭，橋山翠靄中。"]'),
('yuding-25','示弟','許渾','唐','御定全唐诗','yuding','','[]','自爾出門去，淚痕長滿衣。家貧為客早，路遠得書稀。',48,'御定全唐詩/json/528.json','["自爾出門去，淚痕長滿衣。家貧為客早，路遠得書稀。", "文字何人賞，煙波幾日歸。秋風正搖落，孤雁又南飛。"]'),
('yuding-26','送楊處士叔初卜居曲江','許渾','唐','御定全唐诗','yuding','','[]','雁門歸去遠，垂老脫袈裟。蕭寺休為客，曹溪便寄家。',48,'御定全唐詩/json/528.json','["雁門歸去遠，垂老脫袈裟。蕭寺休為客，曹溪便寄家。", "綠琪千歲樹，黃槿四時花。別怨應無限，門前桂水斜。"]'),
('yuding-27','發靈溪館','許渾','唐','御定全唐诗','yuding','','[]','山多水不窮，一葉似漁翁。鳥浴寒潭雨，猿吟暮嶺風。',48,'御定全唐詩/json/528.json','["山多水不窮，一葉似漁翁。鳥浴寒潭雨，猿吟暮嶺風。", "雜英垂錦繡，眾籟合絲桐。應有曹溪路，千岩萬壑中。"]'),
('yuding-28','題杜居士','許渾','唐','御定全唐诗','yuding','','[]','松偃石床平，何人識姓名。溪冰寒棹響，岩雪夜窗明。',48,'御定全唐詩/json/528.json','["松偃石床平，何人識姓名。溪冰寒棹響，岩雪夜窗明。", "機盡心猿伏，神閑意馬行。應知此來客，身世兩無情。"]'),
('yuding-29','神女祠','許渾','唐','御定全唐诗','yuding','','[]','停車祀聖女，涼葉下陰風。龍氣石床濕，鳥聲山廟空。',48,'御定全唐詩/json/528.json','["停車祀聖女，涼葉下陰風。龍氣石床濕，鳥聲山廟空。", "長眉留桂綠，丹臉寄蓮紅。莫學陽臺畔，朝雲暮雨中。"]'),
('yuding-30','送李定言南游','許渾','唐','御定全唐诗','yuding','','[]','酒酣輕別恨，酒醒複離憂。遠水應移棹，高峰更上樓。',48,'御定全唐詩/json/528.json','["酒酣輕別恨，酒醒複離憂。遠水應移棹，高峰更上樓。", "簟涼清露夜，琴響碧天秋。重惜芳尊宴，滿城無舊遊。"]'),
('yuding-31','早發中岩寺別契直上人','許渾','唐','御定全唐诗','yuding','','[]','蒼蒼松桂陰，殘月半西岑。素壁寒燈暗，紅爐夜火深。',48,'御定全唐詩/json/528.json','["蒼蒼松桂陰，殘月半西岑。素壁寒燈暗，紅爐夜火深。", "廚開山鼠散，鐘盡嶺猿吟。行役方如此，逢師懶話心。"]'),
('yuding-32','行次潼關題驛後軒','許渾','唐','御定全唐诗','yuding','','[]','飛閣極層台，終南此路回。山形朝闕去，河勢抱關來。',48,'御定全唐詩/json/528.json','["飛閣極層台，終南此路回。山形朝闕去，河勢抱關來。", "雁過秋風急，蟬鳴宿霧開。平生無限意，驅馬任塵埃。"]'),
('yuding-33','晨至南亭呈裴明府','許渾','唐','御定全唐诗','yuding','','[]','南齋夢釣竿，晨起月猶殘。露重螢依草，風高蝶委蘭。',48,'御定全唐詩/json/528.json','["南齋夢釣竿，晨起月猶殘。露重螢依草，風高蝶委蘭。", "池光秋鏡澈，山色曉屏寒。更戀陶彭澤，無心議去官。"]'),
('yuding-34','灞東題司馬郊園','許渾','唐','御定全唐诗','yuding','','[]','楚翁秦塞住，昔事李輕車。白社貧思橘，青門老仰瓜。',48,'御定全唐詩/json/528.json','["楚翁秦塞住，昔事李輕車。白社貧思橘，青門老仰瓜。", "讀書三徑草，沽酒一籬花。更欲尋芝朮，商山便寄家。"]'),
('yuding-35','遊維山新興寺，宿石屏村謝叟家','許渾','唐','御定全唐诗','yuding','','[]','晚過石屏村，村長日漸曛。僧歸下嶺見，人語隔溪聞。',48,'御定全唐詩/json/528.json','["晚過石屏村，村長日漸曛。僧歸下嶺見，人語隔溪聞。", "穀響寒耕雪，山明夜燒雲。家家扣銅鼓，欲賽魯將軍。"]'),
('yuding-36','送從兄歸隱藍溪二首','許渾','唐','御定全唐诗','yuding','','[]','名高猶素衣，窮巷掩荊扉。漸老故人少，久貧豪客稀。',96,'御定全唐詩/json/528.json','["名高猶素衣，窮巷掩荊扉。漸老故人少，久貧豪客稀。", "塞雲橫劍望，山月抱琴歸。幾日藍溪醉，藤花拂釣磯。", "京洛多高蓋，憐兄劇斷蓬。身隨一劍老，家入萬山空。", "夜憶蕭關月，行悲易水風。無人知此意，甘臥白雲中。"]'),
('yuding-37','村舍','許渾','唐','御定全唐诗','yuding','','[]','燕雁下秋塘，田家自此忙。移蔬通遠水，收果待繁霜。',48,'御定全唐詩/json/528.json','["燕雁下秋塘，田家自此忙。移蔬通遠水，收果待繁霜。", "野碓舂粳滑，山廚焙茗香。客來還有酒，隨事宿茅堂。"]'),
('yuding-38','思歸','許渾','唐','御定全唐诗','yuding','','[]','疊嶂平蕪外，依依識舊邦。氣高詩易怨，愁極酒難降。',48,'御定全唐詩/json/528.json','["疊嶂平蕪外，依依識舊邦。氣高詩易怨，愁極酒難降。", "樹暗支公院，山寒謝守窗。殷勤樓下水，幾日到荊江。"]'),
('yuding-39','晚泊七裏灘','許渾','唐','御定全唐诗','yuding','','[]','天晚日沉沉，歸舟系柳陰。江村平見寺，山郭遠聞砧。',48,'御定全唐詩/json/528.json','["天晚日沉沉，歸舟系柳陰。江村平見寺，山郭遠聞砧。", "樹密猿聲響，波澄雁影深。榮華暫時事，誰識子陵心。"]'),
('yuding-40','寄題南山王隱居','許渾','唐','御定全唐诗','yuding','','[]','近逢商洛客，知爾住南塘。草閣平春水，柴門掩夕陽。',48,'御定全唐詩/json/528.json','["近逢商洛客，知爾住南塘。草閣平春水，柴門掩夕陽。", "隨蜂收野蜜，尋麝采生香。更憶前年醉，松花滿石床。"]'),
('yuding-41','晨裝','許渾','唐','御定全唐诗','yuding','','[]','帶月飯行侶，西游關塞長。晨雞鳴遠戍，宿雁起寒塘。',48,'御定全唐詩/json/528.json','["帶月飯行侶，西游關塞長。晨雞鳴遠戍，宿雁起寒塘。", "雲卷四山雪，風凝千樹霜。誰家遊俠子，沉醉臥蘭堂。"]'),
('yuding-42','題韋隱居西齋','許渾','唐','御定全唐诗','yuding','','[]','劚藥去還歸，家人半掩扉。山風藤子落，溪雨豆花肥。',48,'御定全唐詩/json/528.json','["劚藥去還歸，家人半掩扉。山風藤子落，溪雨豆花肥。", "寺遠僧來少，橋危客到稀。不聞砧杵動，應解制荷衣。"]'),
('yuding-43','送李溟秀才西行','許渾','唐','御定全唐诗','yuding','','[]','萬里不辭勞，寒裝疊縕袍。停車山店雨，掛席海門濤。',48,'御定全唐詩/json/528.json','["萬里不辭勞，寒裝疊縕袍。停車山店雨，掛席海門濤。", "鷹勢暮偏急，鶴聲秋更高。知君北邙路，留劍泣黃蒿。"]'),
('yuding-0','經馬鎮西宅','許渾','唐','御定全唐诗','yuding','','[]','將軍久已沒，行客自興哀。功業山長在，繁華水不回。',48,'御定全唐詩/json/529.json','["將軍久已沒，行客自興哀。功業山長在，繁華水不回。", "亂藤侵廢井，荒菊上叢台。借問此中事，幾家歌舞來。"]'),
('yuding-1','重游郁林寺道玄上人院','許渾','唐','御定全唐诗','yuding','','[]','藤杖叩松關，春溪劚藥還。雨晴巢燕急，波暖浴鷗閑。',48,'御定全唐詩/json/529.json','["藤杖叩松關，春溪劚藥還。雨晴巢燕急，波暖浴鷗閑。", "倚檻花臨水，回舟月照山。憶歸師莫笑，書劍在人間。"]'),
('yuding-2','泛溪','許渾','唐','御定全唐诗','yuding','','[]','疑與武陵通，青溪碧嶂中。水寒深見石，松晚靜聞風。',48,'御定全唐詩/json/529.json','["疑與武陵通，青溪碧嶂中。水寒深見石，松晚靜聞風。", "遁跡驅雞吏，冥心失馬翁。才應畢婚嫁，還此息微躬。"]'),
('yuding-3','送樓煩李別駕','許渾','唐','御定全唐诗','yuding','','[]','琴清詩思勞，更欲學龍韜。王粲暫停筆，呂虔初佩刀。',48,'御定全唐詩/json/529.json','["琴清詩思勞，更欲學龍韜。王粲暫停筆，呂虔初佩刀。", "夜吟關月靜，秋望塞雲高。去去從軍樂，雕飛代馬豪。"]'),
('yuding-4','聞兩河用兵因貽友人','許渾','唐','御定全唐诗','yuding','','[]','故人日已遠，身事與誰論。性拙難趨世，心孤易感恩。',48,'御定全唐詩/json/529.json','["故人日已遠，身事與誰論。性拙難趨世，心孤易感恩。", "秋悲憐宋玉，夜舞笑劉琨。徒有幹時策，青山尚掩門。"]'),
('yuding-5','獻白尹','許渾','唐','御定全唐诗','yuding','','[]','醉舞任生涯，褐寬烏帽斜。庾公先在郡，疏傅早還家。',48,'御定全唐詩/json/529.json','["醉舞任生涯，褐寬烏帽斜。庾公先在郡，疏傅早還家。", "林晚鳥爭樹，園春蜂護花。高吟應更逸，嵩洛舊煙霞。"]'),
('yuding-6','茅山贈梁尊師','許渾','唐','御定全唐诗','yuding','','[]','雲屋何年客，青山白日長。種花春掃雪，看籙夜焚香。',48,'御定全唐詩/json/529.json','["雲屋何年客，青山白日長。種花春掃雪，看籙夜焚香。", "上象壺中闊，平生夢裏忙。幸承仙籍後，乞取大還方。"]'),
('yuding-7','聞薛先輩陪大夫看早梅因寄','許渾','唐','御定全唐诗','yuding','','[]','澗梅寒正發，莫信笛中吹。素豔雪凝樹，清香風滿枝。',49,'御定全唐詩/json/529.json','["澗梅寒正發，莫信笛中吹。素豔雪凝樹，清香風滿枝。", "折驚山鳥散，攜任野蜂隨。今日從公醉，何人倒接z5。"]'),
('yuding-8','送前緱氏韋明府南游','許渾','唐','御定全唐诗','yuding','','[]','酒闌橫劍歌，日暮望關河。道直去官早，家貧為客多。',48,'御定全唐詩/json/529.json','["酒闌橫劍歌，日暮望關河。道直去官早，家貧為客多。", "山昏函穀雨，木落洞庭波。莫盡遠遊興，故園荒薜蘿。"]'),
('yuding-9','看雪','許渾','唐','御定全唐诗','yuding','','[]','松亞竹珊珊，心知萬井歡。山明迷舊徑，溪滿漲新瀾。',48,'御定全唐詩/json/529.json','["松亞竹珊珊，心知萬井歡。山明迷舊徑，溪滿漲新瀾。", "客醉瑤台曙，兵防玉塞寒。紅樓知有酒，誰肯學袁安。"]'),
('yuding-10','贈僧','許渾','唐','御定全唐诗','yuding','','[]','心法本無住，流沙歸複來。錫隨山鳥動，經附海船回。',48,'御定全唐詩/json/529.json','["心法本無住，流沙歸複來。錫隨山鳥動，經附海船回。", "洗足柳遮寺，坐禪花委苔。唯將一童子，又欲上天臺。"]'),
('yuding-11','趨慈和寺移宴','許渾','唐','御定全唐诗','yuding','','[]','高寺移清宴，漁舟系綠蘿。潮平秋水闊，雲斂暮山多。',48,'御定全唐詩/json/529.json','["高寺移清宴，漁舟系綠蘿。潮平秋水闊，雲斂暮山多。", "廣檻停簫鼓，繁弦散綺羅。西樓半床月，莫問夜如何。"]'),
('yuding-12','留贈偃師主人','許渾','唐','御定全唐诗','yuding','','[]','孤城漏未殘，徒侶拂征鞍。洛北去遊遠，淮南歸夢闌。',48,'御定全唐詩/json/529.json','["孤城漏未殘，徒侶拂征鞍。洛北去遊遠，淮南歸夢闌。", "曉燈回壁暗，晴雪捲簾寒。強盡主人酒，出門行路難。"]'),
('yuding-13','送南陵李少府','許渾','唐','御定全唐诗','yuding','','[]','高人亦未閑，來往楚雲間。劍在心應壯，書窮鬢已斑。',48,'御定全唐詩/json/529.json','["高人亦未閑，來往楚雲間。劍在心應壯，書窮鬢已斑。", "落帆秋水寺，驅馬夕陽山。明日南昌尉，空齋又掩關。"]'),
('yuding-14','別韋處士','許渾','唐','御定全唐诗','yuding','','[]','南北斷蓬飛，別多相見稀。更傷今日酒，未換昔年衣。',48,'御定全唐詩/json/529.json','["南北斷蓬飛，別多相見稀。更傷今日酒，未換昔年衣。", "舊友幾人在，故鄉何處歸。秦原向西路，雲晚雪霏霏。"]'),
('yuding-15','九日登樟亭驛樓','許渾','唐','御定全唐诗','yuding','','[]','鱸鱠與蓴羹，西風片席輕。潮回孤島晚，雲斂眾山晴。',48,'御定全唐詩/json/529.json','["鱸鱠與蓴羹，西風片席輕。潮回孤島晚，雲斂眾山晴。", "丹羽下高閣，黃花垂古城。因秋倍多感，鄉樹接咸京。"]'),
('yuding-16','再遊越中，傷朱餘慶協律好直上人','許渾','唐','御定全唐诗','yuding','','[]','昔年湖上客，留訪雪山翁。王氏船猶在，蕭家寺已空。',48,'御定全唐詩/json/529.json','["昔年湖上客，留訪雪山翁。王氏船猶在，蕭家寺已空。", "月高花有露，煙合水無風。處處多遺韻，何曾入剡中。"]'),
('yuding-17','京口津亭送張崔二侍禦','許渾','唐','御定全唐诗','yuding','','[]','愛樹滿西津，津亭墮淚頻。素車應度洛，珠履更歸秦。',48,'御定全唐詩/json/529.json','["愛樹滿西津，津亭墮淚頻。素車應度洛，珠履更歸秦。", "水接三湘暮，山通五嶺春。傷離與懷舊，明日白頭人。"]'),
('yuding-18','江樓夜別','許渾','唐','御定全唐诗','yuding','','[]','離別奈情何，江樓凝豔歌。蕙蘭秋露重，蘆葦夜風多。',48,'御定全唐詩/json/529.json','["離別奈情何，江樓凝豔歌。蕙蘭秋露重，蘆葦夜風多。", "深怨寄清瑟，遠愁生翠蛾。酒酣相顧起，明月棹寒波。"]'),
('yuding-19','送惟素上人歸新安','許渾','唐','御定全唐诗','yuding','','[]','山空葉複落，一徑下新安。風急渡溪晚，雪晴歸寺寒。',48,'御定全唐詩/json/529.json','["山空葉複落，一徑下新安。風急渡溪晚，雪晴歸寺寒。", "尋雲策藤杖，向日倚蒲團。甯憶西遊客，勞勞歌路難。"]'),
('yuding-20','霅上宴別','許渾','唐','御定全唐诗','yuding','','[]','山斷水茫茫，洛人西路長。笙歌留遠棹，風雨寄華堂。',48,'御定全唐詩/json/529.json','["山斷水茫茫，洛人西路長。笙歌留遠棹，風雨寄華堂。", "紅壁耿秋燭，翠簾凝曉香。誰堪從此去，雲樹滿陵陽。"]'),
('yuding-21','下第別友人楊至之','許渾','唐','御定全唐诗','yuding','','[]','花落水潺潺，十年離舊山。夜愁添白髮，春淚減朱顏。',48,'御定全唐詩/json/529.json','["花落水潺潺，十年離舊山。夜愁添白髮，春淚減朱顏。", "孤劍北遊塞，遠書東出關。逢君話心曲，一醉灞陵間。"]'),
('yuding-22','尋戴處士','許渾','唐','御定全唐诗','yuding','','[]','車馬長安道，誰知大隱心。蠻僧留古鏡，蜀客寄新琴。',48,'御定全唐詩/json/529.json','["車馬長安道，誰知大隱心。蠻僧留古鏡，蜀客寄新琴。", "曬藥竹齋暖，搗茶松院深。思君一相訪，殘雪似山陰。"]'),
('yuding-23','放猿','許渾','唐','御定全唐诗','yuding','','[]','殷勤解金鎖，昨夜雨淒淒。山淺憶巫峽，水寒思建溪。',48,'御定全唐詩/json/529.json','["殷勤解金鎖，昨夜雨淒淒。山淺憶巫峽，水寒思建溪。", "遠尋紅樹宿，深向白雲啼。好覓來時路，煙蘿莫共迷。"]'),
('yuding-24','將離郊園留示弟侄','許渾','唐','御定全唐诗','yuding','','[]','身賤與心違，秋風生旅衣。久貧辭國遠，多病在家稀。',48,'御定全唐詩/json/529.json','["身賤與心違，秋風生旅衣。久貧辭國遠，多病在家稀。", "山暝客初散，樹涼人未歸。西都萬餘裏，明旦別柴扉。"]'),
('yuding-25','夜歸丁卯橋村舍','許渾','唐','御定全唐诗','yuding','','[]','月涼風靜夜，歸客泊岩前。橋響犬遙吠，庭空人散眠。',48,'御定全唐詩/json/529.json','["月涼風靜夜，歸客泊岩前。橋響犬遙吠，庭空人散眠。", "紫蒲低水檻，紅葉半江船。自有還家計，南湖二頃田。"]'),
('yuding-26','題青山館','許渾','唐','御定全唐诗','yuding','','[]','昔人詩酒地，芳草思王孫。白水半塘岸，青山橫郭門。',48,'御定全唐詩/json/529.json','["昔人詩酒地，芳草思王孫。白水半塘岸，青山橫郭門。", "懸岩碑已折，磐石井猶存。無處繼行樂，野花空一尊。"]'),
('yuding-27','秋日眾哲館對竹','許渾','唐','御定全唐诗','yuding','','[]','蕭蕭淩雪霜，濃翠異三湘。疏影月移壁，寒聲風滿堂。',48,'御定全唐詩/json/529.json','["蕭蕭淩雪霜，濃翠異三湘。疏影月移壁，寒聲風滿堂。", "捲簾秋更早，高枕夜偏長。忽憶秦溪路，萬竿今正涼。"]'),
('yuding-28','春日題韋曲野老村舍二首','許渾','唐','御定全唐诗','yuding','','[]','繞屋遍桑麻，村南第一家。林繁樹勢直，溪轉水紋斜。',96,'御定全唐詩/json/529.json','["繞屋遍桑麻，村南第一家。林繁樹勢直，溪轉水紋斜。", "竹院晝看筍，藥欄春賣花。故園歸未得，到此是天涯。", "北嶺枕南塘，數家村落長。鶯啼幼婦懶，蠶出小姑忙。", "煙草近溝濕，風花臨路香。自憐非楚客，春望亦心傷。"]'),
('yuding-29','崇聖寺別楊至之','許渾','唐','御定全唐诗','yuding','','[]','蕭寺暫相逢，離憂滿病容。寒齋秋少燕，陰壁夜多蛩。',48,'御定全唐詩/json/529.json','["蕭寺暫相逢，離憂滿病容。寒齋秋少燕，陰壁夜多蛩。", "樹暗水千里，山深雲萬重。懷君在書信，莫過雁回峰。"]'),
('yuding-30','途經李翰林墓','許渾','唐','御定全唐诗','yuding','','[]','氣逸何人識，才高舉世疑。禰生狂善賦，陶令醉能詩。',48,'御定全唐詩/json/529.json','["氣逸何人識，才高舉世疑。禰生狂善賦，陶令醉能詩。", "碧水鱸魚思，青山鵩鳥悲。至今孤塚在，荊棘楚江湄。"]'),
('yuding-31','嚴陵釣台貽行侶','許渾','唐','御定全唐诗','yuding','','[]','故人天下定，垂釣碧岩幽。舊跡隨台古，高名寄水流。',48,'御定全唐詩/json/529.json','["故人天下定，垂釣碧岩幽。舊跡隨台古，高名寄水流。", "鳥喧群木晚，蟬急眾山秋。更待新安月，憑君暫駐舟。"]'),
('yuding-32','南樓春望','許渾','唐','御定全唐诗','yuding','','[]','南樓春一望，雲水共昏昏。野店歸山路，危橋帶郭村。',48,'御定全唐詩/json/529.json','["南樓春一望，雲水共昏昏。野店歸山路，危橋帶郭村。", "晴煙和草色，夜雨長溪痕。下岸誰家住，殘陽半掩門。"]'),
('yuding-33','送無夢道人先歸甘露寺','許渾','唐','御定全唐诗','yuding','','[]','飄飄隨晚浪，杯影入鷗群。岸凍千船雪，岩陰一寺雲。',48,'御定全唐詩/json/529.json','["飄飄隨晚浪，杯影入鷗群。岸凍千船雪，岩陰一寺雲。", "夜燈江北見，寒磬水西聞。鶴嶺煙霞在，歸期不羨君。"]'),
('yuding-34','閒居孟夏即事','許渾','唐','御定全唐诗','yuding','','[]','綠樹蔭青苔，柴門臨水開。簟涼初熟麥，枕膩乍經梅。',48,'御定全唐詩/json/529.json','["綠樹蔭青苔，柴門臨水開。簟涼初熟麥，枕膩乍經梅。", "魚躍海風起，鼉鳴江雨來。佳人竟何處，日夕上樓臺。"]'),
('yuding-35','題灞西駱隱士','許渾','唐','御定全唐诗','yuding','','[]','磻溪連灞水，商嶺接秦山。青漢不回駕，白雲長掩關。',48,'御定全唐詩/json/529.json','["磻溪連灞水，商嶺接秦山。青漢不回駕，白雲長掩關。", "雀喧知鶴靜，鳧戲識鷗閑。卻笑南昌尉，悠悠城市間。"]'),
('yuding-36','溪亭二首','許渾','唐','御定全唐诗','yuding','','[]','溪亭四面山，橫柳半溪灣。蟬響螳螂急，魚深翡翠閑。',96,'御定全唐詩/json/529.json','["溪亭四面山，橫柳半溪灣。蟬響螳螂急，魚深翡翠閑。", "水寒留客醉，月上與僧還。猶戀蕭蕭竹，西齋未掩關。", "暖枕眠溪柳，僧齋昨夜期。茶香秋夢後，松韻晚吟時。", "共戲魚翻藻，爭棲鳥墜枝。重陽應一醉，栽菊助東籬。"]'),
('yuding-37','秋日赴闕題潼關驛樓','許渾','唐','御定全唐诗','yuding','','[]','紅葉晚蕭蕭，長亭酒一瓢。殘雲歸太華，疏雨過中條。',48,'御定全唐詩/json/529.json','["紅葉晚蕭蕭，長亭酒一瓢。殘雲歸太華，疏雨過中條。", "樹色隨山迥，河聲入海遙。帝鄉明日到，猶自夢漁樵。"]'),
('yuding-38','吳門送客早發','許渾','唐','御定全唐诗','yuding','','[]','吳歌咽深思，楚客怨歸程。寺曉樓臺迥，江秋管吹清。',48,'御定全唐詩/json/529.json','["吳歌咽深思，楚客怨歸程。寺曉樓臺迥，江秋管吹清。", "早潮低水檻，殘月下山城。惆悵回舟日，湘南春草生。"]'),
('yuding-39','送太昱禪師','許渾','唐','御定全唐诗','yuding','','[]','禪床深竹裏，心與徑山期。結社多高客，登壇盡小師。',48,'御定全唐詩/json/529.json','["禪床深竹裏，心與徑山期。結社多高客，登壇盡小師。", "早秋歸寺遠，新雨上灘遲。別後江雲碧，南齋一首詩。"]'),
('yuding-40','旅懷','許渾','唐','御定全唐诗','yuding','','[]','征車何軋軋，南北極天涯。孤枕易為客，遠書難到家。',48,'御定全唐詩/json/529.json','["征車何軋軋，南北極天涯。孤枕易為客，遠書難到家。", "鄉連雲外樹，城閉月中花。猶有扁舟思，前年別若耶。"]'),
('yuding-0','南亭與首公宴集','許渾','唐','御定全唐诗','yuding','','[]','秋來水上亭，幾處似岩扃。戲鳥翻江葉，遊龜帶綠萍。',48,'御定全唐詩/json/530.json','["秋來水上亭，幾處似岩扃。戲鳥翻江葉，遊龜帶綠萍。", "管弦心戚戚，羅綺鬢星星。行樂非吾事，西齋尚有螢。"]'),
('yuding-1','早發壽安次永壽渡','許渾','唐','御定全唐诗','yuding','','[]','東西車馬塵，鞏洛與咸秦。山月夜行客，水煙朝渡人。',48,'御定全唐詩/json/530.json','["東西車馬塵，鞏洛與咸秦。山月夜行客，水煙朝渡人。", "樹涼風皓皓，灘淺石磷磷。會待功名就，扁舟寄此身。"]'),
('yuding-2','泊松江渡','許渾','唐','御定全唐诗','yuding','','[]','漠漠故宮地，月涼風露幽。雞鳴荒戍曉，雁過古城秋。',48,'御定全唐詩/json/530.json','["漠漠故宮地，月涼風露幽。雞鳴荒戍曉，雁過古城秋。", "楊柳北歸路，蒹葭南渡舟。去鄉今已遠，更上望京樓。"]'),
('yuding-3','送魚思別處士歸有懷','許渾','唐','御定全唐诗','yuding','','[]','宴罷眾賓散，長歌攜一卮。溪亭相送遠，山郭獨歸遲。',48,'御定全唐詩/json/530.json','["宴罷眾賓散，長歌攜一卮。溪亭相送遠，山郭獨歸遲。", "風檻夕雲散，月軒寒露滋。病來雙鬢白，不是舊離時。"]'),
('yuding-4','重經姑蘇懷古二首','許渾','唐','御定全唐诗','yuding','','[]','越兵驅綺羅，越女唱吳歌。宮盡燕聲少，台荒麋跡多。',96,'御定全唐詩/json/530.json','["越兵驅綺羅，越女唱吳歌。宮盡燕聲少，台荒麋跡多。", "茱萸垂曉露，菡萏落秋波。無複君王醉，滿城顰翠蛾。", "香徑繞吳宮，千帆落照中。鸛鳴山欲雨，魚躍水多風。", "城帶晚莎綠，池連秋蓼紅。當年國門外，誰識伍員忠。"]'),
('yuding-5','將赴京師，留題孫處士山居二首','許渾','唐','御定全唐诗','yuding','','[]','草堂近西郭，遙對敬亭開。枕膩海雲起，簟涼山雨來。',96,'御定全唐詩/json/530.json','["草堂近西郭，遙對敬亭開。枕膩海雲起，簟涼山雨來。", "高歌懷地肺，遠賦憶天臺。應學相如志，終須駟馬回。", "西岩有高興，路僻幾人知。松蔭花開晚，山寒酒熟遲。", "遊從隨野鶴，休息遇靈龜。長見鄰翁說，容華似舊時。"]'),
('yuding-6','下第寓居崇聖寺感事','許渾','唐','御定全唐诗','yuding','','[]','懷土泣京華，舊山歸路賒。靜依禪客院，幽學野人家。',48,'御定全唐詩/json/530.json','["懷土泣京華，舊山歸路賒。靜依禪客院，幽學野人家。", "林晚鳥爭樹，園春蝶護花。東門有閑地，誰種邵平瓜。"]'),
('yuding-7','曉發天井關寄李師晦','許渾','唐','御定全唐诗','yuding','','[]','山在水滔滔，流年欲二毛。湘潭歸夢遠，燕趙客程勞。',48,'御定全唐詩/json/530.json','["山在水滔滔，流年欲二毛。湘潭歸夢遠，燕趙客程勞。", "露曉紅蘭重，雲晴碧樹高。逢秋正多感，萬里別同袍。"]'),
('yuding-8','喜遠書','許渾','唐','御定全唐诗','yuding','','[]','端居換時節，離恨隔龍瀧。苔色上春閣，柳陰移晚窗。',48,'御定全唐詩/json/530.json','["端居換時節，離恨隔龍瀧。苔色上春閣，柳陰移晚窗。", "寄懷因桂水，流淚極楓江。此日南來使，金盤魚一雙。"]'),
('yuding-9','懷江南同志','許渾','唐','御定全唐诗','yuding','','[]','南國別經年，雲晴波接天。蒲深鸂鶒戲，花暖鷓鴣眠。',48,'御定全唐詩/json/530.json','["南國別經年，雲晴波接天。蒲深鸂鶒戲，花暖鷓鴣眠。", "竹暗湘妃廟，楓陰楚客船。唯應洞庭月，萬里共嬋娟。"]'),
('yuding-10','洛中秋日','許渾','唐','御定全唐诗','yuding','','[]','故國無歸處，官閑憶遠遊。吳僧秣陵寺，楚客洞庭舟。',48,'御定全唐詩/json/530.json','["故國無歸處，官閑憶遠遊。吳僧秣陵寺，楚客洞庭舟。", "久病先知雨，長貧早覺秋。壯心能幾許，伊水更東流。"]'),
('yuding-11','將赴京師蒜山津送客還荊渚','許渾','唐','御定全唐诗','yuding','','[]','尊前萬里愁，楚塞與皇州。雲識瀟湘雨，風知鄠杜秋。',48,'御定全唐詩/json/530.json','["尊前萬里愁，楚塞與皇州。雲識瀟湘雨，風知鄠杜秋。", "潮平猶倚棹，月上更登樓。他日滄浪水，漁歌對白頭。"]'),
('yuding-12','潼關蘭若','許渾','唐','御定全唐诗','yuding','','[]','來往幾經過，前軒枕大河。遠帆春水闊，高寺夕陽多。',48,'御定全唐詩/json/530.json','["來往幾經過，前軒枕大河。遠帆春水闊，高寺夕陽多。", "蝶影下紅藥，鳥聲喧綠蘿。故山歸未得，徒詠采芝歌。"]'),
('yuding-13','玩殘雪寄江南尹劉大夫','許渾','唐','御定全唐诗','yuding','','[]','豔陽無處避，皎潔不成容。素質添瑤水，清光散玉峰。',48,'御定全唐詩/json/530.json','["豔陽無處避，皎潔不成容。素質添瑤水，清光散玉峰。", "眠鷗猶戀草，棲鶴未離松。聞在金鑾望，群仙對九重。"]'),
('yuding-14','陪越中使院諸公，鏡波館餞明台裴鄭二使君','許渾','唐','御定全唐诗','yuding','','[]','傾幕來華館，淹留二使君。舞移清夜月，歌斷碧空雲。',48,'御定全唐詩/json/530.json','["傾幕來華館，淹留二使君。舞移清夜月，歌斷碧空雲。", "海郡樓臺接，江船劍戟分。明時自鶱翥，無複歎離群。"]'),
('yuding-15','春泊弋陽','許渾','唐','御定全唐诗','yuding','','[]','江行春欲半，孤枕弋陽堤。雲暗猶飄雪，潮寒未應溪。',48,'御定全唐詩/json/530.json','["江行春欲半，孤枕弋陽堤。雲暗猶飄雪，潮寒未應溪。", "飲猿聞棹散，飛鳥背船低。此路成幽絕，家山鞏洛西。"]'),
('yuding-16','晨別翛然上人','許渾','唐','御定全唐诗','yuding','','[]','吳僧誦經罷，敗衲倚蒲團。鐘韻花猶斂，樓陰月向殘。',48,'御定全唐詩/json/530.json','["吳僧誦經罷，敗衲倚蒲團。鐘韻花猶斂，樓陰月向殘。", "晴山開殿響，秋水捲簾寒。獨恨孤舟去，千灘複萬灘。"]'),
('yuding-17','送客江行','許渾','唐','御定全唐诗','yuding','','[]','蕭蕭蘆荻花，郢客獨辭家。遠棹依山響，危檣轉浦斜。',48,'御定全唐詩/json/530.json','["蕭蕭蘆荻花，郢客獨辭家。遠棹依山響，危檣轉浦斜。", "不寒澄淺石，潮落漲虛沙。莫與征徒望，鄉園去漸賒。"]'),
('yuding-18','將歸塗口，宿郁林寺道玄上人院二首','許渾','唐','御定全唐诗','yuding','','[]','西岩一磬長，僧起樹蒼蒼。開殿灑寒水，誦經焚晚香。',96,'御定全唐詩/json/530.json','["西岩一磬長，僧起樹蒼蒼。開殿灑寒水，誦經焚晚香。", "竹風雲漸散，杉露月猶光。無複重來此，歸舟淩夕陽。", "春尋采藥翁，歸路宿禪宮。雲起客眠處，月殘僧定中。", "藤花深洞水，槲葉滿山風。清境不能住，朝朝慚遠公。"]'),
('yuding-19','題宣州元處士幽居','許渾','唐','御定全唐诗','yuding','','[]','潺湲繞門水，未省濯纓塵。鳥散千岩曙，蜂來一徑春。',48,'御定全唐詩/json/530.json','["潺湲繞門水，未省濯纓塵。鳥散千岩曙，蜂來一徑春。", "杉松還待客，芝朮不求人。寧學磻溪叟，逢時罷隱淪。"]'),
('yuding-20','送李秀才','許渾','唐','御定全唐诗','yuding','','[]','南樓送郢客，西郭見荊門。鳧鵠下寒渚，牛羊歸遠村。',48,'御定全唐詩/json/530.json','["南樓送郢客，西郭見荊門。鳧鵠下寒渚，牛羊歸遠村。", "蘭舟倚行棹，桂酒掩餘尊。重此一留宿，前村煙水昏。"]'),
('yuding-21','題倪處士舊居','許渾','唐','御定全唐诗','yuding','','[]','儒翁九十餘，舊向此山居。生寄一壺酒，死留千卷書。',48,'御定全唐詩/json/530.json','["儒翁九十餘，舊向此山居。生寄一壺酒，死留千卷書。", "檻摧新竹少，池淺故蓮疏。但有子孫在，帶經還荷鋤。"]'),
('yuding-22','贈梁將軍','許渾','唐','御定全唐诗','yuding','','[]','曾經黑山虜，一劍出重圍。年長窮書意，時清隱釣磯。',48,'御定全唐詩/json/530.json','["曾經黑山虜，一劍出重圍。年長窮書意，時清隱釣磯。", "高齋雲外住，瘦馬月中歸。唯說鄉心苦，春風雁北飛。"]'),
('yuding-23','春望思舊游','許渾','唐','御定全唐诗','yuding','','[]','適意極春日，南台披薜蘿。花光晴漾漾，山色晝峨峨。',48,'御定全唐詩/json/530.json','["適意極春日，南台披薜蘿。花光晴漾漾，山色晝峨峨。", "湘水美人遠，信陵豪客多。唯憑一瓢酒，彈瑟縱高歌。"]'),
('yuding-24','病中二首','許渾','唐','御定全唐诗','yuding','','[]','三年嬰酒渴，高臥似袁安。秋色鬢應改，夜涼心已寬。',96,'御定全唐詩/json/530.json','["三年嬰酒渴，高臥似袁安。秋色鬢應改，夜涼心已寬。", "風衣藤簟滑，露井竹床寒。臥憶郊扉月，恩深未掛冠。", "私歸人暫適，扶杖繞西林。風急柳溪響，露寒莎徑深。", "一身仍白髮，萬慮只丹心。此意無言處，高窗托素琴。"]'),
('yuding-25','姑熟官舍寄汝洛友人','許渾','唐','御定全唐诗','yuding','','[]','官靜亦無能，平生少面朋。務開唯印吏，公退只棋僧。',48,'御定全唐詩/json/530.json','["官靜亦無能，平生少面朋。務開唯印吏，公退只棋僧。", "藥鼎初寒火，書龕欲夜燈。安知北溟水，終日送摶鵬。"]'),
('yuding-26','恩德寺','許渾','唐','御定全唐诗','yuding','','[]','樓臺橫複重，猶有半岩空。蘿洞淺深水，竹廊高下風。',48,'御定全唐詩/json/530.json','["樓臺橫複重，猶有半岩空。蘿洞淺深水，竹廊高下風。", "晴山疏雨後，秋樹斷雲中。未盡平生意，孤帆又向東。"]'),
('yuding-27','天竺寺題葛洪井','許渾','唐','御定全唐诗','yuding','','[]','羽客煉丹井，井留人已無。舊泉青石下，餘甃碧山隅。',48,'御定全唐詩/json/530.json','["羽客煉丹井，井留人已無。舊泉青石下，餘甃碧山隅。", "雲朗鏡開匣，月寒冰在壺。仍聞釀仙酒，此水過瓊酴。"]'),
('yuding-28','朗上人院晨坐','許渾','唐','御定全唐诗','yuding','','[]','簟涼襟袖清，月沒尚殘星。山果落秋院，水花開曉庭。',48,'御定全唐詩/json/530.json','["簟涼襟袖清，月沒尚殘星。山果落秋院，水花開曉庭。", "疏藤風嫋嫋，圓桂露冥冥。正憶江南寺，岩齋聞誦經。"]'),
('yuding-29','送客歸湘楚','許渾','唐','御定全唐诗','yuding','','[]','無辭一杯酒，昔日與君深。秋色換歸鬢，曙光生別心。',48,'御定全唐詩/json/530.json','["無辭一杯酒，昔日與君深。秋色換歸鬢，曙光生別心。", "桂花山廟冷，楓樹水樓陰。此路千餘裏，應勞楚客吟。"]'),
('yuding-30','過故友舊居','許渾','唐','御定全唐诗','yuding','','[]','往年公子宅，夜宴樂難忘。高竹動疏翠，早蓮飄暗香。',48,'御定全唐詩/json/530.json','["往年公子宅，夜宴樂難忘。高竹動疏翠，早蓮飄暗香。", "珠盤凝寶瑟，綺席遞華觴。今日皆何處，閉門春草長。"]'),
('yuding-31','送客歸峽中','許渾','唐','御定全唐诗','yuding','','[]','津亭多別離，楊柳半無枝。住接猿啼處，行逢雁過時。',48,'御定全唐詩/json/530.json','["津亭多別離，楊柳半無枝。住接猿啼處，行逢雁過時。", "江風颺帆急，山月下樓遲。還就西齋宿，煙波勞夢思。"]'),
('yuding-32','題沖沼上人院','許渾','唐','御定全唐诗','yuding','','[]','劚石種松子，數根侵杳冥。天寒猶講律，雨暗尚尋經。',48,'御定全唐詩/json/530.json','["劚石種松子，數根侵杳冥。天寒猶講律，雨暗尚尋經。", "小殿燈千盞，深爐水一瓶。碧雲多別思，休到望溪亭。"]'),
('yuding-33','和畢員外雪中見寄','許渾','唐','御定全唐诗','yuding','','[]','仙署淹清景，雪華松桂陰。夜淩瑤席宴，春寄玉京吟。',48,'御定全唐詩/json/530.json','["仙署淹清景，雪華松桂陰。夜淩瑤席宴，春寄玉京吟。", "燭晃垂羅幕，香寒重繡衾。相思不相訪，煙月剡溪深。"]'),
('yuding-34','春醉','許渾','唐','御定全唐诗','yuding','','[]','酒醲花一樹，何暇卓文君。客坐長先飲，公閑半已曛。',48,'御定全唐詩/json/530.json','["酒醲花一樹，何暇卓文君。客坐長先飲，公閑半已曛。", "水鄉春足雨，山郭夜多雲。何以參禪理，榮枯盡不聞。"]'),
('yuding-35','題岫上人院','許渾','唐','御定全唐诗','yuding','','[]','病客與僧閑，頻來不掩關。高窗雲外樹，疏磬雨中山。',48,'御定全唐詩/json/530.json','["病客與僧閑，頻來不掩關。高窗雲外樹，疏磬雨中山。", "離索秋蟲響，登臨夕鳥還。心知落帆處，明月浙河灣。"]'),
('yuding-36','送客南歸有懷','許渾','唐','御定全唐诗','yuding','','[]','綠水暖青蘋，湘潭萬里春。瓦尊迎海客，銅鼓賽江神。',48,'御定全唐詩/json/530.json','["綠水暖青蘋，湘潭萬里春。瓦尊迎海客，銅鼓賽江神。", "避雨松楓岸，看雲楊柳津。長安一杯酒，座上有歸人。"]'),
('yuding-37','李生棄官入道因寄','許渾','唐','御定全唐诗','yuding','','[]','西岩一徑通，知學采芝翁。寒暑丹心外，光陰白髮中。',48,'御定全唐詩/json/530.json','["西岩一徑通，知學采芝翁。寒暑丹心外，光陰白髮中。", "水深魚避釣，雲迥鶴辭籠。坐想還家日，人非井邑空。"]'),
('yuding-38','長興裏夏日南鄰避暑','許渾','唐','御定全唐诗','yuding','','[]','侯門大道傍，蟬噪樹蒼蒼。開鎖洞門遠，下簾賓館涼。',48,'御定全唐詩/json/530.json','["侯門大道傍，蟬噪樹蒼蒼。開鎖洞門遠，下簾賓館涼。", "欄圍紅藥盛，架引綠蘿長。永日一欹枕，故山雲水鄉。"]'),
('yuding-39','送韓校書','許渾','唐','御定全唐诗','yuding','','[]','恨與前歡隔，愁因此會同。跡高芸閣吏，名散雪樓翁。',48,'御定全唐詩/json/530.json','["恨與前歡隔，愁因此會同。跡高芸閣吏，名散雪樓翁。", "城閉三秋雨，帆飛一夜風。酒醒鱸鱠美，應在竟陵東。"]'),
('yuding-40','秋晚登城','許渾','唐','御定全唐诗','yuding','','[]','城高不可下，永日一登臨。曲檻涼飆急，空樓返照深。',48,'御定全唐詩/json/530.json','["城高不可下，永日一登臨。曲檻涼飆急，空樓返照深。", "葦花迷夕棹，梧葉散秋砧。謾作歸田賦，蹉跎歲欲陰。"]'),
('yuding-41','江西鄭常侍赴鎮之日有寄，因酬和','許渾','唐','御定全唐诗','yuding','','[]','來暮亦何愁，金貂在鷁舟。旆隨寒浪動，帆帶夕陽收。',48,'御定全唐詩/json/530.json','["來暮亦何愁，金貂在鷁舟。旆隨寒浪動，帆帶夕陽收。", "布令滕王閣，裁詩郢客樓。即應歸鳳沼，中外贊天休。"]'),
('yuding-42','蒙河南劉大夫見示與吏部張公喜雪酬唱，輒敢攀和','許渾','唐','御定全唐诗','yuding','','[]','風度龍山暗，雲凝象闕陰。瑞花瓊樹合，仙草玉苗深。',48,'御定全唐詩/json/530.json','["風度龍山暗，雲凝象闕陰。瑞花瓊樹合，仙草玉苗深。", "欲醉梁王酒，先調楚客琴。即應攜手去，將此助商霖。"]'),
('yuding-43','下第送宋秀才游岐下、楊秀才還江東','許渾','唐','御定全唐诗','yuding','','[]','年來不自得，一望幾傷心。風轉蕙蘭色，月移松桂陰。',48,'御定全唐詩/json/530.json','["年來不自得，一望幾傷心。風轉蕙蘭色，月移松桂陰。", "馬隨邊草遠，帆落海雲深。明旦各分首，更聽梁甫吟。"]'),
('yuding-44','南亭偶題','許渾','唐','御定全唐诗','yuding','','[]','城下水縈回，潮沖野艇來。鳥驚山果落，龜泛綠萍開。',48,'御定全唐詩/json/530.json','["城下水縈回，潮沖野艇來。鳥驚山果落，龜泛綠萍開。", "白首書千卷，朱顏酒一杯。南軒自流涕，不是望燕台。"]'),
('yuding-45','與裴三十秀才自越西歸望亭阻凍登虎丘山寺精舍','許渾','唐','御定全唐诗','yuding','','[]','春草越吳間，心期旦夕還。酒鄉逢客病，詩境遇僧閑。',48,'御定全唐詩/json/530.json','["春草越吳間，心期旦夕還。酒鄉逢客病，詩境遇僧閑。", "倚棹冰生浦，登樓雪滿山。東風不可待，歸鬢坐斑斑。"]'),
('yuding-0','太和初靖恭裏感事','許渾','唐','御定全唐诗','yuding','','[]','清湘吊屈原，垂淚擷蘋蘩。謗起乘軒鶴，機沉在檻猿。',48,'御定全唐詩/json/531.json','["清湘吊屈原，垂淚擷蘋蘩。謗起乘軒鶴，機沉在檻猿。", "乾坤三事貴，華夏一夫冤。甯有唐虞世，心知不為言。"]'),
('yuding-1','與侯春時同年南池夜話','許渾','唐','御定全唐诗','yuding','','[]','蘆葦暮修修，溪禽上釣舟。露涼花斂夕，風靜竹含秋。',48,'御定全唐詩/json/531.json','["蘆葦暮修修，溪禽上釣舟。露涼花斂夕，風靜竹含秋。", "素志應難契，清言豈易求。相歡一瓢酒，明日醉西樓。"]'),
('yuding-2','廣陵送剡縣薛明府赴任','許渾','唐','御定全唐诗','yuding','','[]','車馬楚城壕，清歌送濁醪。露花羞別淚，煙草讓歸袍。',48,'御定全唐詩/json/531.json','["車馬楚城壕，清歌送濁醪。露花羞別淚，煙草讓歸袍。", "鳥浴春塘暖，猿吟暮嶺高。尋仙在仙骨，不用廢牛刀。"]'),
('yuding-3','遊果晝二僧院','許渾','唐','御定全唐诗','yuding','','[]','何必老林泉，冥心便是禪。講時開院去，齋後下簾眠。',48,'御定全唐詩/json/531.json','["何必老林泉，冥心便是禪。講時開院去，齋後下簾眠。", "鏡朗燈分焰，香銷印絕煙。真乘不可到，雲盡月明天。"]'),
('yuding-4','題官舍','許渾','唐','御定全唐诗','yuding','','[]','燕雁水鄉飛，京華信自稀。簟瓢貧守道，書劍病忘機。',48,'御定全唐詩/json/531.json','["燕雁水鄉飛，京華信自稀。簟瓢貧守道，書劍病忘機。", "疊鼓吏初散，繁鐘鳥獨歸。高梧與疏柳，風雨似郊扉。"]'),
('yuding-5','酬報先上人登樓見寄','許渾','唐','御定全唐诗','yuding','','[]','丹葉下西樓，知君萬里愁。鐘非黔峽寺，帆是敬亭舟。',48,'御定全唐詩/json/531.json','["丹葉下西樓，知君萬里愁。鐘非黔峽寺，帆是敬亭舟。", "山色和雲暮，湖光共月秋。天臺多道侶，何惜更南遊。"]'),
('yuding-6','曉過郁林寺戲呈李明府','許渾','唐','御定全唐诗','yuding','','[]','身閑白日長，何處不尋芳。山崦登樓寺，溪灣泊晚檣。',48,'御定全唐詩/json/531.json','["身閑白日長，何處不尋芳。山崦登樓寺，溪灣泊晚檣。", "洞花蜂聚蜜，岩柏麝留香。若指求仙路，劉郎學阮郎。"]'),
('yuding-7','泛舟尋郁林寺道玄上人遇雨而返因寄','許渾','唐','御定全唐诗','yuding','','[]','禪扉倚石梯，雲濕雨淒淒。草色分松徑，泉聲咽稻畦。',48,'御定全唐詩/json/531.json','["禪扉倚石梯，雲濕雨淒淒。草色分松徑，泉聲咽稻畦。", "棹移灘鳥沒，鐘斷嶺猿啼。入夜花如雪，回舟憶剡溪。"]'),
('yuding-8','郁林寺','許渾','唐','御定全唐诗','yuding','','[]','台殿冠嵯峨，春來日日過。水分諸院少，雲近上方多。',48,'御定全唐詩/json/531.json','["台殿冠嵯峨，春來日日過。水分諸院少，雲近上方多。", "眾籟凝絲竹，繁英耀綺羅。酒酣詩自逸，乘月棹寒波。"]'),
('yuding-9','題崇聖寺','許渾','唐','御定全唐诗','yuding','','[]','西林本行殿，池榭日坡阤。雨過水初漲，雲開山漸多。',48,'御定全唐詩/json/531.json','["西林本行殿，池榭日坡阤。雨過水初漲，雲開山漸多。", "曉街垂禦柳，秋院閉宮莎。借問龍歸處，鼎湖空碧波。"]'),
('yuding-10','贈高處士','許渾','唐','御定全唐诗','yuding','','[]','宅前雲水滿，高興一書生。垂釣有深意，望山多遠情。',48,'御定全唐詩/json/531.json','["宅前雲水滿，高興一書生。垂釣有深意，望山多遠情。", "夜棋留客宿，春酒勸僧傾。未作幹時計，何人問姓名。"]'),
('yuding-11','送僧歸金山寺','許渾','唐','御定全唐诗','yuding','','[]','老歸江上寺，不忘舊師恩。駐錫逢山色，停杯見浪痕。',48,'御定全唐詩/json/531.json','["老歸江上寺，不忘舊師恩。駐錫逢山色，停杯見浪痕。", "秋濤吞楚驛，曉月上荊門。為訪題詩處，莓苔幾字存。"]'),
('yuding-12','金谷桃花','許渾','唐','御定全唐诗','yuding','','[]','花在舞樓空，年年依舊紅。淚光停曉露，愁態倚春風。',48,'御定全唐詩/json/531.json','["花在舞樓空，年年依舊紅。淚光停曉露，愁態倚春風。", "開處妾先死，落時君亦終。東流兩三片，應在夜泉中。"]'),
('yuding-13','憶長洲','許渾','唐','御定全唐诗','yuding','','[]','香徑小船通，菱歌繞故宮。魚沉秋水靜，鳥宿暮山空。',48,'御定全唐詩/json/531.json','["香徑小船通，菱歌繞故宮。魚沉秋水靜，鳥宿暮山空。", "荷葉橋邊雨，蘆花海上風。歸心無處托，高枕畫屏中。"]'),
('yuding-14','寄殷堯藩','許渾','唐','御定全唐诗','yuding','','[]','直道知難用，經年向水濱。宅從栽竹貴，家為買書貧。',48,'御定全唐詩/json/531.json','["直道知難用，經年向水濱。宅從栽竹貴，家為買書貧。", "就學多新客，登朝盡故人。蓬萊自有路，莫羨武陵春。"]'),
('yuding-15','題鄒處士隱居','許渾','唐','御定全唐诗','yuding','','[]','桑柘滿江村，西齋接海門。浪沖高岸響，潮入小池渾。',48,'御定全唐詩/json/531.json','["桑柘滿江村，西齋接海門。浪沖高岸響，潮入小池渾。", "岩樹陰棋局，山花落酒樽。相逢亦留宿，還似識王孫。"]'),
('yuding-16','送僧歸敬亭山寺','許渾','唐','御定全唐诗','yuding','','[]','十年劍中路，傳盡本師經。曉月下黔峽，秋風歸敬亭。',48,'御定全唐詩/json/531.json','["十年劍中路，傳盡本師經。曉月下黔峽，秋風歸敬亭。", "開門新樹綠，登閣舊山青。遙想論禪處，松陰水一瓶。"]'),
('yuding-17','新卜原上居寄袁校書','許渾','唐','御定全唐诗','yuding','','[]','貧居樂游此，江海思迢迢。雪夜書千卷，花時酒一瓢。',48,'御定全唐詩/json/531.json','["貧居樂游此，江海思迢迢。雪夜書千卷，花時酒一瓢。", "獨愁秦樹老，孤夢楚山遙。有路應相念，風塵滿黑貂。"]'),
('yuding-18','天街曉望','許渾','唐','御定全唐诗','yuding','','[]','明星低未央，蓮闕迥蒼蒼。疊鼓催殘月，疏鐘迎早霜。',48,'御定全唐詩/json/531.json','["明星低未央，蓮闕迥蒼蒼。疊鼓催殘月，疏鐘迎早霜。", "關防浮瑞氣，宮館耀神光。再拜為君壽，南山高且長。"]'),
('yuding-19','江上喜洛中親友繼至','許渾','唐','御定全唐诗','yuding','','[]','戰馬昔紛紛，風驚嵩少塵。全家南渡遠，舊友北來頻。',48,'御定全唐詩/json/531.json','["戰馬昔紛紛，風驚嵩少塵。全家南渡遠，舊友北來頻。", "罷酒松筠晚，賦詩楊柳春。誰言今夜月，同是洛陽人。"]'),
('yuding-20','下第歸朱方寄劉三複','許渾','唐','御定全唐诗','yuding','','[]','素衣京洛塵，歸棹過南津。故里跡猶在，舊交心更新。',48,'御定全唐詩/json/531.json','["素衣京洛塵，歸棹過南津。故里跡猶在，舊交心更新。", "月高蕭寺夜，風暖庾樓春。詩酒應無暇，朝朝問旅人。"]'),
('yuding-21','送人歸吳興','許渾','唐','御定全唐诗','yuding','','[]','綠水棹雲月，洞庭歸路長。春橋懸酒幔，夜柵集茶檣。',48,'御定全唐詩/json/531.json','["綠水棹雲月，洞庭歸路長。春橋懸酒幔，夜柵集茶檣。", "箬葉沉溪暖，蘋花繞郭香。應逢柳太守，為說過瀟湘。"]'),
('yuding-22','月夜期友人不至','許渾','唐','御定全唐诗','yuding','','[]','坐待故人宿，月華清興秋。管弦誰處醉，池館此時愁。',48,'御定全唐詩/json/531.json','["坐待故人宿，月華清興秋。管弦誰處醉，池館此時愁。", "風過渚荷動，露含山桂幽。孤吟不可曙，昨夜共登樓。"]'),
('yuding-23','白馬寺不出院僧','許渾','唐','御定全唐诗','yuding','','[]','禪空心已寂，世路任多岐。到院客長見，閉關人不知。',48,'御定全唐詩/json/531.json','["禪空心已寂，世路任多岐。到院客長見，閉關人不知。", "寺喧聽講絕，廚遠送齋遲。牆外洛陽道，東西無盡時。"]'),
('yuding-24','寄袁校書','許渾','唐','御定全唐诗','yuding','','[]','擾擾換時節，舊山琪樹陰。猶乖清漢志，空負白雲心。',48,'御定全唐詩/json/531.json','["擾擾換時節，舊山琪樹陰。猶乖清漢志，空負白雲心。", "廣陌埃塵遠，重門管吹深。勞歌極西望，芸省有知音。"]'),
('yuding-25','贈柳璟、馮陶二校書','許渾','唐','御定全唐诗','yuding','','[]','霄漢兩飛鳴，喧喧動禁城。桂堂同日盛，芸閣間年榮。',48,'御定全唐詩/json/531.json','["霄漢兩飛鳴，喧喧動禁城。桂堂同日盛，芸閣間年榮。", "香掩蕙蘭氣，韻高鸞鶴聲。應憐茂陵客，未有子虛名。"]'),
('yuding-26','王秀才自越見尋不遇，題詩而回，因以酬寄','許渾','唐','御定全唐诗','yuding','','[]','南齋知數宿，半為木蘭開。晴閣留詩遍，春帆載酒回。',48,'御定全唐詩/json/531.json','["南齋知數宿，半為木蘭開。晴閣留詩遍，春帆載酒回。", "煙深揚子宅，雲斷越王台。自有孤舟興，何妨更一來。"]'),
('yuding-27','秋霽潼關驛亭','許渾','唐','御定全唐诗','yuding','','[]','霽色明高巘，關河獨望遙。殘雲歸太華，疏雨過中條。',48,'御定全唐詩/json/531.json','["霽色明高巘，關河獨望遙。殘雲歸太華，疏雨過中條。", "鳥散綠蘿靜，蟬鳴紅樹凋。何言此時節，去去任蓬飄。"]'),
('yuding-28','送客歸蘭溪','許渾','唐','御定全唐诗','yuding','','[]','花下送歸客，路長應過秋。暮隨江鳥宿，寒共嶺猿愁。',48,'御定全唐詩/json/531.json','["花下送歸客，路長應過秋。暮隨江鳥宿，寒共嶺猿愁。", "眾水喧嚴瀨，群峰抱沉樓。因君幾南望，曾向此中游。"]'),
('yuding-29','貽終南山隱者','許渾','唐','御定全唐诗','yuding','','[]','中岩多少隱，提榼抱琴遊。潭冷薜蘿晚，山香松桂秋。',48,'御定全唐詩/json/531.json','["中岩多少隱，提榼抱琴遊。潭冷薜蘿晚，山香松桂秋。", "瓢閑高樹掛，杯急曲池流。獨有迷津客，東西南北愁。"]'),
('yuding-30','送李文明下第鄜州覲兄','許渾','唐','御定全唐诗','yuding','','[]','征夫天一涯，醉贈別吾詩。雁迥參差遠，龍多次第遲。',48,'御定全唐詩/json/531.json','["征夫天一涯，醉贈別吾詩。雁迥參差遠，龍多次第遲。", "寧歌還夜苦，宋賦更秋悲。的的遙相待，清風白露時。"]'),
('yuding-31','送段覺歸東陽兼寄竇使君','許渾','唐','御定全唐诗','yuding','','[]','山水引歸路，陸郎從此諳。秋茶垂露細，寒菊帶霜甘。',48,'御定全唐詩/json/531.json','["山水引歸路，陸郎從此諳。秋茶垂露細，寒菊帶霜甘。", "台倚烏龍嶺，樓侵白雁潭。沈公如借問，心在浙河南。"]'),
('yuding-32','韶州送竇司直北歸','許渾','唐','御定全唐诗','yuding','','[]','江曲山如畫，貪程亦駐舟。果隨岩狖落，槎帶水禽流。',48,'御定全唐詩/json/531.json','["江曲山如畫，貪程亦駐舟。果隨岩狖落，槎帶水禽流。", "客散他鄉夜，人歸故國秋。樽前掛帆去，風雨下西樓。"]'),
('yuding-33','傷馮秀才','許渾','唐','御定全唐诗','yuding','','[]','旅葬不可問，茫茫西隴頭。水雲青草濕，山月白楊愁。',48,'御定全唐詩/json/531.json','["旅葬不可問，茫茫西隴頭。水雲青草濕，山月白楊愁。", "琴信有時罷，劍傷無處留。淮南舊煙月，孤棹更逢秋。"]'),
('yuding-34','送鄭寂上人南行','許渾','唐','御定全唐诗','yuding','','[]','儒家有釋子，年少學支公。心出是非外，跡辭榮辱中。',48,'御定全唐詩/json/531.json','["儒家有釋子，年少學支公。心出是非外，跡辭榮辱中。", "錫寒秦嶺月，杯急楚江風。離怨故園裏，小秋梨葉紅。"]'),
('yuding-35','贈王處士','許渾','唐','御定全唐诗','yuding','','[]','歸臥養天真，鹿裘烏角巾。茂陵閑久病，彭澤醉長貧。',48,'御定全唐詩/json/531.json','["歸臥養天真，鹿裘烏角巾。茂陵閑久病，彭澤醉長貧。", "冠蓋西園夜，笙歌北裏春。誰憐清渭曲，又老釣魚人。"]'),
('yuding-36','送友人歸荊楚','許渾','唐','御定全唐诗','yuding','','[]','調瑟勸離酒，苦諳荊楚門。竹斑悲帝女，草綠怨王孫。',48,'御定全唐詩/json/531.json','["調瑟勸離酒，苦諳荊楚門。竹斑悲帝女，草綠怨王孫。", "潮落九疑迥，雨連三峽昏。同來不同去，迢遞更傷魂。"]'),
('yuding-37','重傷楊攀處士二首','許渾','唐','御定全唐诗','yuding','','[]','綠雲多學術，黃發竟無成。酒縱山中性，詩留海上名。',96,'御定全唐詩/json/531.json','["綠雲多學術，黃發竟無成。酒縱山中性，詩留海上名。", "讀書新樹老，垂釣舊磯平。今日悲前事，西風聞哭聲。", "從官任直道，幾處脫長裾。歿後兒猶小，葬來人漸疏。", "新鄰占池館，長史覓圖書。身賤難相報，平生恨有餘。"]'),
('yuding-38','送友人罷舉歸東海','許渾','唐','御定全唐诗','yuding','','[]','滄波天塹外，何島是新羅。舶主辭番遠，棋僧入漢多。',48,'御定全唐詩/json/531.json','["滄波天塹外，何島是新羅。舶主辭番遠，棋僧入漢多。", "海風吹白鶴，沙日曬紅螺。此去知投筆，須求利劍磨。"]'),
('yuding-39','西園','許渾','唐','御定全唐诗','yuding','','[]','西園春欲盡，芳草徑難分。靜語唯幽鳥，閑眠獨使君。',48,'御定全唐詩/json/531.json','["西園春欲盡，芳草徑難分。靜語唯幽鳥，閑眠獨使君。", "密林生雨氣，古石帶苔文。雖去清朝遠，朝朝見白雲。"]'),
('yuding-40','苦雨','許渾','唐','御定全唐诗','yuding','','[]','江昏山半晴，南阻絕人行。葭菼連雲色，杉松共雨聲。',48,'御定全唐詩/json/531.json','["江昏山半晴，南阻絕人行。葭菼連雲色，杉松共雨聲。", "早秋仍燕舞，深夜更鼉鳴。為報迷津客，訛言未可輕。"]'),
('yuding-41','游茅山','許渾','唐','御定全唐诗','yuding','','[]','步步入山門，仙家鳥徑分。漁樵不到處，麋鹿自成群。',48,'御定全唐詩/json/531.json','["步步入山門，仙家鳥徑分。漁樵不到處，麋鹿自成群。", "石面迸出水，松頭穿破雲。道人星月下，相次禮茅君。"]'),
('yuding-42','洛陽道中','許渾','唐','御定全唐诗','yuding','','[]','洛陽多舊跡，一日幾堪愁。風起林花晚，月明陵樹秋。',36,'御定全唐詩/json/531.json','["洛陽多舊跡，一日幾堪愁。風起林花晚，月明陵樹秋。", "興亡不可問，自古水東流。"]'),
('yuding-0','江上燕別','許渾','唐','御定全唐诗','yuding','','[]','雲物如故鄉，山川異岐路。年來未歸客，馬上春欲暮。',48,'御定全唐詩/json/532.json','["雲物如故鄉，山川異岐路。年來未歸客，馬上春欲暮。", "一樽花下酒，殘日水西樹。不待管弦終，搖鞭背花去。"]'),
('yuding-1','卜居招書侶','許渾','唐','御定全唐诗','yuding','','[]','憶昨未知道，臨川每羨魚。世途行處見，人事病來疏。',48,'御定全唐詩/json/532.json','["憶昨未知道，臨川每羨魚。世途行處見，人事病來疏。", "微雨秋栽竹，孤燈夜讀書。憐君亦同志，晚歲傍山居。"]'),
('yuding-2','西山草堂','許渾','唐','御定全唐诗','yuding','','[]','何處少人事，西山舊草堂。曬書秋日晚，洗藥石泉香。',48,'御定全唐詩/json/532.json','["何處少人事，西山舊草堂。曬書秋日晚，洗藥石泉香。", "浚嶺有朝雨，北窗生夜涼。從勞問歸路，峰疊繞家鄉。"]'),
('yuding-3','贈隱者','許渾','唐','御定全唐诗','yuding','','[]','回報隱居士，莫愁山興闌。求人顏色盡，知道性情寬。',48,'御定全唐詩/json/532.json','["回報隱居士，莫愁山興闌。求人顏色盡，知道性情寬。", "信譜彈琴誤，緣崖劚藥難。東皋亦自給，殊愧遠相安。"]'),
('yuding-4','舟次武陵寄天竺僧無晝','許渾','唐','御定全唐诗','yuding','','[]','溪長山幾重，十裏萬株松。秋日下丹檻，暮雲歸碧峰。',48,'御定全唐詩/json/532.json','["溪長山幾重，十裏萬株松。秋日下丹檻，暮雲歸碧峰。", "樹棲新放鶴，潭隱舊降龍。還在孤舟宿，臥聞初夜鐘。"]'),
('yuding-5','寄小弟','許渾','唐','御定全唐诗','yuding','','[]','江城紅葉盡，旅思複淒傷。孤夢家山遠，獨眠秋夜長。',48,'御定全唐詩/json/532.json','["江城紅葉盡，旅思複淒傷。孤夢家山遠，獨眠秋夜長。", "道存空倚命，身賤未歸鄉。南望空垂淚，天邊雁一行。"]'),
('yuding-6','秋日','許渾','唐','御定全唐诗','yuding','','[]','有計自安業，秋風罷苦吟。買山兼種竹，對客更彈琴。',48,'御定全唐詩/json/532.json','["有計自安業，秋風罷苦吟。買山兼種竹，對客更彈琴。", "煙起藥園晚，杵聲松院深。閑眠得真性，惆悵舊時心。"]'),
('yuding-7','石池','許渾','唐','御定全唐诗','yuding','','[]','通竹引泉脈，泓澄瀲石盆。驚魚翻藻葉，浴鳥上松根。',48,'御定全唐詩/json/532.json','["通竹引泉脈，泓澄瀲石盆。驚魚翻藻葉，浴鳥上松根。", "殘月留山影，高風耗水痕。誰家秋洗藥，來往自開門。"]'),
('yuding-8','留題李侍禦書齋','許渾','唐','御定全唐诗','yuding','','[]','昔話平生志，高齋曾見留。道孤心易感，恩重力難酬。',48,'御定全唐詩/json/532.json','["昔話平生志，高齋曾見留。道孤心易感，恩重力難酬。", "獨立千峰曉，頻來一葉秋。雞鳴應有處，不覺淚空流。"]'),
('yuding-9','行次白沙館，先寄上河南王侍禦','許渾','唐','御定全唐诗','yuding','','[]','夜程何處宿，山疊樹層層。孤館閉秋雨，空堂停曙燈。',48,'御定全唐詩/json/532.json','["夜程何處宿，山疊樹層層。孤館閉秋雨，空堂停曙燈。", "歌慚漁浦客，詩學雁門僧。此意無人識，明朝見李膺。"]'),
('yuding-10','紫藤','許渾','唐','御定全唐诗','yuding','','[]','綠蘿縈數匝，本在草堂間。秋色寄高樹，晝陰籠遠山。',48,'御定全唐詩/json/532.json','["綠蘿縈數匝，本在草堂間。秋色寄高樹，晝陰籠遠山。", "移花疏處種，劚藥困時攀。日暮微風起，難尋舊徑還。"]'),
('yuding-11','暝投靈智寺渡溪不得，卻取沿江路往','許渾','唐','御定全唐诗','yuding','','[]','雙岩瀉一川，回馬斷橋前。古廟陰風地，寒鐘暮雨天。',48,'御定全唐詩/json/532.json','["雙岩瀉一川，回馬斷橋前。古廟陰風地，寒鐘暮雨天。", "沙虛留虎跡，水滑帶龍涎。卻下臨江路，潮深無渡船。"]'),
('yuding-12','下第歸蒲城墅居','許渾','唐','御定全唐诗','yuding','','[]','失意歸三徑，傷春別九門。薄煙楊柳路，微雨杏花村。',48,'御定全唐詩/json/532.json','["失意歸三徑，傷春別九門。薄煙楊柳路，微雨杏花村。", "牧豎還呼犢，鄰翁亦抱孫。不知餘正苦，迎馬問寒溫。"]'),
('yuding-13','重賦鷺鷥','許渾','唐','御定全唐诗','yuding','','[]','何年去此地，南浦滿鳧雛。雲漢知心遠，林塘覺思孤。',48,'御定全唐詩/json/532.json','["何年去此地，南浦滿鳧雛。雲漢知心遠，林塘覺思孤。", "低飛下晚樹，獨睡映新蒲。為爾多歸興，前年在五湖。"]'),
('yuding-14','途中寒食','許渾','唐','御定全唐诗','yuding','','[]','處處哭聲悲，行人馬亦遲。店閑無火日，村暖斫桑時。',48,'御定全唐詩/json/532.json','["處處哭聲悲，行人馬亦遲。店閑無火日，村暖斫桑時。", "泣路同楊子，燒山憶介推。清明明日是，甘負故園期。"]'),
('yuding-15','深春','許渾','唐','御定全唐诗','yuding','','[]','故里千帆外，深春一雁飛。幹名頻慟哭，將老欲何歸。',48,'御定全唐詩/json/532.json','["故里千帆外，深春一雁飛。幹名頻慟哭，將老欲何歸。", "未穀拋還憶，交親晚更稀。空持望鄉淚，沾灑寄來衣。"]'),
('yuding-16','歲首懷甘露寺自省上人','許渾','唐','御定全唐诗','yuding','','[]','心悟覺身勞，雲中棄寶刀。久閑生髀肉，多壽長眉毫。',49,'御定全唐詩/json/532.json','["心悟覺身勞，雲中棄寶刀。久閑生髀肉，多壽長眉毫。", "客棹春潮急，禪齋暮雪高。南da一回首，山碧水滔滔。"]'),
('yuding-17','尋周煉師不遇留贈','許渾','唐','御定全唐诗','yuding','','[]','閉門池館靜，雲訪紫芝翁。零落槿花雨，參差荷葉風。',48,'御定全唐詩/json/532.json','["閉門池館靜，雲訪紫芝翁。零落槿花雨，參差荷葉風。", "夜棋全局在，春酒半壺空。長嘯倚西閣，悠悠名利中。"]'),
('yuding-18','題灞西駱隱居','許渾','唐','御定全唐诗','yuding','','[]','志淩三蜀客，心愛五湖人。co死酒中老，謀生書外貧。',49,'御定全唐詩/json/532.json','["志淩三蜀客，心愛五湖人。co死酒中老，謀生書外貧。", "掃花眠石榻，搗藥轉溪輪。往往乘黃牸，鹿裘烏角巾。"]'),
('yuding-19','旅夜懷遠客','許渾','唐','御定全唐诗','yuding','','[]','異鄉多遠情，夢斷落江城。病起慚書癖，貧家負酒名。',48,'御定全唐詩/json/532.json','["異鄉多遠情，夢斷落江城。病起慚書癖，貧家負酒名。", "過春花自落，竟曉月空明。獨此一長嘯，故人天際行。"]'),
('yuding-20','秋夜棹舟訪李隱君','許渾','唐','御定全唐诗','yuding','','[]','望月憶披襟，長溪柳半陰。高齋初釀酒，孤棹遠攜琴。',48,'御定全唐詩/json/532.json','["望月憶披襟，長溪柳半陰。高齋初釀酒，孤棹遠攜琴。", "犬吠秋山迥，雞鳴曉樹深。開門更欹枕，誰識野人心。"]'),
('yuding-21','臥病寄諸公','許渾','唐','御定全唐诗','yuding','','[]','飛蓋集蘭堂，清歌遞柏觴。高城榆柳蔭，虛閣芰荷香。',48,'御定全唐詩/json/532.json','["飛蓋集蘭堂，清歌遞柏觴。高城榆柳蔭，虛閣芰荷香。", "海月秋偏靜，山風夜更涼。自憐書萬卷，扶病對螢光。"]'),
('yuding-22','寓崇聖寺懷李校書','許渾','唐','御定全唐诗','yuding','','[]','幾日臥南亭，捲簾秋月清。河關初罷夢，池閣更含情。',48,'御定全唐詩/json/532.json','["幾日臥南亭，捲簾秋月清。河關初罷夢，池閣更含情。", "寒露潤金井，高風飄玉箏。前年共遊客，刀筆事戎旌。"]'),
('yuding-23','秋日行次關西','許渾','唐','御定全唐诗','yuding','','[]','金風蕩天地，關西群木凋。早霜雞喔喔，殘月馬蕭蕭。',48,'御定全唐詩/json/532.json','["金風蕩天地，關西群木凋。早霜雞喔喔，殘月馬蕭蕭。", "紫陌秦山近，青楓楚樹遙。還同長卿志，題字滿河橋。"]'),
('yuding-24','山居冬夜喜魏扶見訪因贈','許渾','唐','御定全唐诗','yuding','','[]','霜風露葉下，遠思獨裴回。夜久草堂靜，月明山客來。',48,'御定全唐詩/json/532.json','["霜風露葉下，遠思獨裴回。夜久草堂靜，月明山客來。", "遣貧相勸酒，憶字共書灰。何事清平世，幹名待有媒。"]'),
('yuding-25','喜李詡秀才見訪因贈','許渾','唐','御定全唐诗','yuding','','[]','浙南分首日，誰謂別經時。路遠遙相訪，家貧喜見知。',48,'御定全唐詩/json/532.json','["浙南分首日，誰謂別經時。路遠遙相訪，家貧喜見知。", "不須辭不酌，更請續新詩。但得心中劍，酬恩會有期。"]'),
('yuding-26','晚投慈恩寺呈俊上人','許渾','唐','御定全唐诗','yuding','','[]','雙岩瀉一川，十裏絕人煙。古廟陰風地，寒鐘暮雨天。',48,'御定全唐詩/json/532.json','["雙岩瀉一川，十裏絕人煙。古廟陰風地，寒鐘暮雨天。", "沙虛留虎跡，水滑帶龍涎。不及曹溪侶，空林已夜禪。"]'),
('yuding-27','行次虎頭岩酬寄路中丞','許渾','唐','御定全唐诗','yuding','','[]','樟亭去已遠，來上虎頭岩。灘急水移棹，山回風滿帆。',48,'御定全唐詩/json/532.json','["樟亭去已遠，來上虎頭岩。灘急水移棹，山回風滿帆。", "石梯迎雨滑，沙井落潮鹹。何以慰行旅，如公書一緘。"]'),
('yuding-28','送荔浦蔣明府赴任','許渾','唐','御定全唐诗','yuding','','[]','路長春欲盡，歌怨酒初酣。白社蓮宮北，青袍桂水南。',48,'御定全唐詩/json/532.json','["路長春欲盡，歌怨酒初酣。白社蓮宮北，青袍桂水南。", "驛行盤鳥道，船宿避龍潭。真得詩人趣，煙霞處處諳。"]'),
('yuding-29','懷政禪師院','許渾','唐','御定全唐诗','yuding','','[]','山齋路幾層，敗衲學真乘。寒暑移雙樹，光陰盡一燈。',48,'御定全唐詩/json/532.json','["山齋路幾層，敗衲學真乘。寒暑移雙樹，光陰盡一燈。", "風飄高竹雪，泉漲小池冰。莫訝頻來此，修身欲到僧。"]'),
('yuding-30','秋夕有懷','許渾','唐','御定全唐诗','yuding','','[]','念遠坐西閣，華池涵月涼。書回秋欲盡，酒醒夜初長。',48,'御定全唐詩/json/532.json','["念遠坐西閣，華池涵月涼。書回秋欲盡，酒醒夜初長。", "露白蓮衣淺，風清蕙帶香。前年此佳景，蘭棹醉橫塘。"]'),
('yuding-31','秋霽寄遠','許渾','唐','御定全唐诗','yuding','','[]','初霽獨登賞，西樓多遠風。橫煙秋水上，疏雨夕陽中。',48,'御定全唐詩/json/532.json','["初霽獨登賞，西樓多遠風。橫煙秋水上，疏雨夕陽中。", "高樹下山鳥，平蕪飛草蟲。唯應待明月，千里與君同。"]'),
('yuding-32','聞范秀才自蜀游江湖','許渾','唐','御定全唐诗','yuding','','[]','蜀道下湘渚，客帆應不迷。江分三峽響，山並九華齊。',48,'御定全唐詩/json/532.json','["蜀道下湘渚，客帆應不迷。江分三峽響，山並九華齊。", "秋泊雁初宿，夜吟猿乍啼。歸時慎行李，莫到石城西。"]'),
('yuding-33','惜春','許渾','唐','御定全唐诗','yuding','','[]','花開又花落，時節暗中遷。無計延春日，可能留少年。',48,'御定全唐詩/json/532.json','["花開又花落，時節暗中遷。無計延春日，可能留少年。", "小叢初散蝶，高柳即聞蟬。繁豔歸何處，滿山啼杜鵑。"]'),
('yuding-34','題愁','許渾','唐','御定全唐诗','yuding','','[]','聚散竟無形，回腸百結成。古今銷不得，離別覺潛生。',48,'御定全唐詩/json/532.json','["聚散竟無形，回腸百結成。古今銷不得，離別覺潛生。", "降虜將軍思，窮秋遠客情。何人更憔悴，落第泣秦京。"]'),
('yuding-35','鴛鴦','許渾','唐','御定全唐诗','yuding','','[]','兩兩戲沙汀，長疑畫不成。錦機爭織樣，歌曲愛呼名。',48,'御定全唐詩/json/532.json','["兩兩戲沙汀，長疑畫不成。錦機爭織樣，歌曲愛呼名。", "好□顧棲息，堪憐泛淺清。鳧鷗皆爾類，唯羨獨含情。"]'),
('yuding-36','聞雁','許渾','唐','御定全唐诗','yuding','','[]','帶霜南去雁，夜好宿汀沙。驚起向何處，高飛極海涯。',48,'御定全唐詩/json/532.json','["帶霜南去雁，夜好宿汀沙。驚起向何處，高飛極海涯。", "入雲聲漸遠，離岳路猶賒。歸夢當時斷，參差欲到家。"]'),
('yuding-37','不寢','許渾','唐','御定全唐诗','yuding','','[]','到曉不成夢，思量堪白頭。多無百年命，長有萬般愁。',48,'御定全唐詩/json/532.json','["到曉不成夢，思量堪白頭。多無百年命，長有萬般愁。", "世事應難盡，營生卒未休。莫言名與利，名利是身仇。"]'),
('yuding-38','宿東橫山','許渾','唐','御定全唐诗','yuding','','[]','孤舟路漸賒，時見碧桃花。溪雨灘聲急，岩風樹勢斜。',48,'御定全唐詩/json/532.json','["孤舟路漸賒，時見碧桃花。溪雨灘聲急，岩風樹勢斜。", "獼猴垂弱蔓，鸛鶴睡橫槎。謾向仙林宿，無人識阮家。"]'),
('yuding-39','早行','許渾','唐','御定全唐诗','yuding','','[]','失枕驚先起，人家半夢中。聞雞憑早晏，占鬥認西東。',48,'御定全唐詩/json/532.json','["失枕驚先起，人家半夢中。聞雞憑早晏，占鬥認西東。", "轡濕知行露，衣單覺曉風。秋陽弄光影，忽吐半林紅。"]'),
('yuding-40','陪鄭史君泛舟晚歸','許渾','唐','御定全唐诗','yuding','','[]','南郭望歸處，郡樓高捲簾。平橋低皂蓋，曲岸轉彤襜。',48,'御定全唐詩/json/532.json','["南郭望歸處，郡樓高捲簾。平橋低皂蓋，曲岸轉彤襜。", "江晚笙歌促，山晴鼓角嚴。羊公莫先醉，清曉月纖纖。"]'),
('yuding-41','酬殷堯藩','許渾','唐','御定全唐诗','yuding','','[]','相如愧許詢，寥落向溪濱。竹馬兒猶小，荊釵婦慣貧。',48,'御定全唐詩/json/532.json','["相如愧許詢，寥落向溪濱。竹馬兒猶小，荊釵婦慣貧。", "獨愁憂過日，多病不如人。莫怪青袍選，長安隱舊春。"]'),
('yuding-42','贈遷客','許渾','唐','御定全唐诗','yuding','','[]','無機還得罪，直道不傷情。微雨昏山色，疏籠閉鶴聲。',48,'御定全唐詩/json/532.json','["無機還得罪，直道不傷情。微雨昏山色，疏籠閉鶴聲。", "閒居多野客，高枕見江城。門外長溪水，憐君又濯纓。"]'),
('yuding-43','征西舊卒','許渾','唐','御定全唐诗','yuding','','[]','少年乘勇氣，百戰過烏孫。力盡邊城難，功加上將恩。',48,'御定全唐詩/json/532.json','["少年乘勇氣，百戰過烏孫。力盡邊城難，功加上將恩。", "曉風聽戍角，殘月倚營門。自說輕生處，金瘡有舊痕。"]'),
('yuding-44','南陵留別段氏兄弟','許渾','唐','御定全唐诗','yuding','','[]','不知身老大，猶似舊時狂。為酒遊山縣，留詩遍草堂。',48,'御定全唐詩/json/532.json','["不知身老大，猶似舊時狂。為酒遊山縣，留詩遍草堂。", "歸期秋未盡，離恨日偏長。更羨君兄弟，參差雁一行。"]'),
('yuding-45','旅中別侄暐','許渾','唐','御定全唐诗','yuding','','[]','相見又南北，中宵淚滿襟。旅遊知世薄，貧別覺情深。',48,'御定全唐詩/json/532.json','["相見又南北，中宵淚滿襟。旅遊知世薄，貧別覺情深。", "歌管一尊酒，山川萬里心。此身多在路，休誦異鄉吟。"]'),
('yuding-46','松江渡送人','許渾','唐','御定全唐诗','yuding','','[]','故國今何在，扁舟竟不歸。雲移山漠漠，江闊樹依依。',48,'御定全唐詩/json/532.json','["故國今何在，扁舟竟不歸。雲移山漠漠，江闊樹依依。", "晚色千帆落，秋聲一雁飛。此時兼送客，憑檻欲沾衣。"]'),
('yuding-47','過鮑溶宅有感','許渾','唐','御定全唐诗','yuding','','[]','寥落故人宅，重來身已亡。古苔殘墨沼，深竹舊書堂。',48,'御定全唐詩/json/532.json','["寥落故人宅，重來身已亡。古苔殘墨沼，深竹舊書堂。", "秋色館池靜，雨聲雲木涼。無因展交道，日暮倍心傷。"]'),
('yuding-0','金陵懷古','許渾','唐','御定全唐诗','yuding','','[]','玉樹歌殘王氣終，景陽兵合戍樓空。松楸遠近千官塚，',40,'御定全唐詩/json/533.json','["玉樹歌殘王氣終，景陽兵合戍樓空。松楸遠近千官塚，", "英雄一去豪華盡，唯有青山似洛中。"]'),
('yuding-1','姑蘇懷古','許渾','唐','御定全唐诗','yuding','','[]','宮館餘基輟棹過，黍苗無限獨悲歌。荒台麋鹿爭新草，',40,'御定全唐詩/json/533.json','["宮館餘基輟棹過，黍苗無限獨悲歌。荒台麋鹿爭新草，", "可憐國破忠臣死，日日東流生白波。"]'),
('yuding-2','淩歊台','許渾','唐','御定全唐诗','yuding','','[]','宋祖淩高樂未回，三千歌舞宿層台。湘潭雲盡暮山出，',40,'御定全唐詩/json/533.json','["宋祖淩高樂未回，三千歌舞宿層台。湘潭雲盡暮山出，", "百年便作萬年計，岩畔古碑空綠苔。"]'),
('yuding-3','驪山','許渾','唐','御定全唐诗','yuding','','[]','聞說先皇醉碧桃，日華浮動郁金袍。風隨玉輦笙歌迥，',40,'御定全唐詩/json/533.json','["聞說先皇醉碧桃，日華浮動郁金袍。風隨玉輦笙歌迥，", "貴妃沒後巡遊少，瓦落宮牆見野蒿。"]'),
('yuding-4','咸陽城東樓','許渾','唐','御定全唐诗','yuding','','[]','一上高城萬里愁，蒹葭楊柳似汀洲。溪雲初起日沈閣，',40,'御定全唐詩/json/533.json','["一上高城萬里愁，蒹葭楊柳似汀洲。溪雲初起日沈閣，", "行人莫問當年事，故國東來渭水流。"]'),
('yuding-5','京口閒居寄京洛友人','許渾','唐','御定全唐诗','yuding','','[]','吳門煙月昔同遊，楓葉蘆花並客舟。聚散有期雲北去，',40,'御定全唐詩/json/533.json','["吳門煙月昔同遊，楓葉蘆花並客舟。聚散有期雲北去，", "何處相思不相見，鳳城龍闕楚江頭。"]'),
('yuding-6','冬日登越王台懷歸','許渾','唐','御定全唐诗','yuding','','[]','月沉高岫宿雲開，萬里歸心獨上來。河畔雪飛揚子宅，',40,'御定全唐詩/json/533.json','["月沉高岫宿雲開，萬里歸心獨上來。河畔雪飛揚子宅，", "鄉信漸稀人漸老，只應頻看一枝梅。"]'),
('yuding-7','對雪','許渾','唐','御定全唐诗','yuding','','[]','雲度龍山暗倚城，先飛淅瀝引輕盈。素娥冉冉拜瑤闕，',40,'御定全唐詩/json/533.json','["雲度龍山暗倚城，先飛淅瀝引輕盈。素娥冉冉拜瑤闕，", "剡溪一醉十年事，忽憶棹回天未明。"]'),
('yuding-8','送蕭處士歸緱嶺別業','許渾','唐','御定全唐诗','yuding','','[]','醉斜烏帽發如絲，曾看仙人一局棋。賓館有魚為客久，',40,'御定全唐詩/json/533.json','["醉斜烏帽發如絲，曾看仙人一局棋。賓館有魚為客久，", "今夜月明何處宿，九疑雲盡碧參差。"]'),
('yuding-9','與鄭二秀才同舟東下洛中，親朋送至景雲寺','許渾','唐','御定全唐诗','yuding','','[]','三十六峰橫一川，綠波無路草芊芊。牛羊晚食鋪平地，',40,'御定全唐詩/json/533.json','["三十六峰橫一川，綠波無路草芊芊。牛羊晚食鋪平地，", "東西未有相逢日，更把繁華共醉眠。"]'),
('yuding-10','長安歲暮','許渾','唐','御定全唐诗','yuding','','[]','獨望天門倚劍歌，幹時無計老關河。東歸萬里慚張翰，',40,'御定全唐詩/json/533.json','["獨望天門倚劍歌，幹時無計老關河。東歸萬里慚張翰，", "三山歲歲有人去，唯恐海風生白波。"]'),
('yuding-11','贈茅山高拾遺','許渾','唐','御定全唐诗','yuding','','[]','諫獵歸來綺季歌，大茅峰影滿秋波。山齋留客掃紅葉，',40,'御定全唐詩/json/533.json','["諫獵歸來綺季歌，大茅峰影滿秋波。山齋留客掃紅葉，", "雲中黃鵠日千里，自宿自飛無網羅。"]'),
('yuding-12','李秀才近自塗口遷居新安適枉緘書見寬悲戚因以此答','許渾','唐','御定全唐诗','yuding','','[]','遠書開罷更依依，晨坐高臺竟落暉。顏巷雪深人已去，',40,'御定全唐詩/json/533.json','["遠書開罷更依依，晨坐高臺竟落暉。顏巷雪深人已去，", "今日勞君猶問訊，一官唯長故山薇。"]'),
('yuding-13','贈蕭兵曹先輩','許渾','唐','御定全唐诗','yuding','','[]','廣陵堤上昔離居，帆轉瀟湘萬里餘。楚客病時無鵩鳥，',40,'御定全唐詩/json/533.json','["廣陵堤上昔離居，帆轉瀟湘萬里餘。楚客病時無鵩鳥，", "聞說攜琴兼載酒，邑人爭識馬相如。"]'),
('yuding-14','題舒女廟','許渾','唐','御定全唐诗','yuding','','[]','山樂來迎去不言，廟前高柳水禽喧。綺羅無色雨侵帳，',40,'御定全唐詩/json/533.json','["山樂來迎去不言，廟前高柳水禽喧。綺羅無色雨侵帳，", "孤舟夢斷行雲散，何限離心寄曉猿。"]'),
('yuding-15','姑孰官舍','許渾','唐','御定全唐诗','yuding','','[]','草生宮舍似閒居，雪照南窗滿素書。貧後始知為吏拙，',40,'御定全唐詩/json/533.json','["草生宮舍似閒居，雪照南窗滿素書。貧後始知為吏拙，", "不待秋風便歸去，紫陽山下是吾廬。"]'),
('yuding-16','淩歊台送韋秀才','許渾','唐','御定全唐诗','yuding','','[]','雲起高臺日未沉，數村殘照半岩陰，野蠶成繭桑柘盡，',40,'御定全唐詩/json/533.json','["雲起高臺日未沉，數村殘照半岩陰，野蠶成繭桑柘盡，", "故山迢遞故人去，一夜月明千里心。"]'),
('yuding-17','送嶺南盧判官罷職歸華陰山居','許渾','唐','御定全唐诗','yuding','','[]','曾事劉琨雁塞空，十年書劍任飄蓬。東堂舊屈移山志，',40,'御定全唐詩/json/533.json','["曾事劉琨雁塞空，十年書劍任飄蓬。東堂舊屈移山志，", "關西舊友如相問，已許滄浪伴釣翁。"]'),
('yuding-18','將度故城湖阻風夜泊永陽戍','許渾','唐','御定全唐诗','yuding','','[]','行盡青溪日已蹉，雲容山影水嵯峨。樓前歸客怨清夢，',40,'御定全唐詩/json/533.json','["行盡青溪日已蹉，雲容山影水嵯峨。樓前歸客怨清夢，", "終期一艇載樵去，來往使帆淩白波。"]'),
('yuding-19','鄭侍禦廳玩鶴','許渾','唐','御定全唐诗','yuding','','[]','碧天飛舞下晴莎，金閣瑤池絕網羅。岩響數聲風滿樹，',40,'御定全唐詩/json/533.json','["碧天飛舞下晴莎，金閣瑤池絕網羅。岩響數聲風滿樹，", "雙翅一開千萬里，只應棲隱戀喬柯。"]'),
('yuding-20','南亭夜坐，貽開元禪定二道者','許渾','唐','御定全唐诗','yuding','','[]','暮暮焚香何處宿，西岩一室映疏藤。光陰難駐跡如客，',40,'御定全唐詩/json/533.json','["暮暮焚香何處宿，西岩一室映疏藤。光陰難駐跡如客，", "身閑境靜日為樂，若問其餘非我能。"]'),
('yuding-21','朱坡故少保杜公池亭','許渾','唐','御定全唐诗','yuding','','[]','杜陵池榭綺城東，孤島回汀路不窮。高岫乍疑三峽近，',40,'御定全唐詩/json/533.json','["杜陵池榭綺城東，孤島回汀路不窮。高岫乍疑三峽近，", "還有昔時巢燕在，飛來飛去畫堂中。"]'),
('yuding-22','秋日早朝','許渾','唐','御定全唐诗','yuding','','[]','宵衣應待絕更籌，環佩鏘鏘月下樓。井轉轆轤千樹曉，',40,'御定全唐詩/json/533.json','["宵衣應待絕更籌，環佩鏘鏘月下樓。井轉轆轤千樹曉，", "虛戴鐵冠無一事，滄江歸去老漁舟。"]'),
('yuding-23','滄浪峽','許渾','唐','御定全唐诗','yuding','','[]','纓帶流塵發半霜，獨尋殘月下滄浪。一聲溪鳥暗雲散，',40,'御定全唐詩/json/533.json','["纓帶流塵發半霜，獨尋殘月下滄浪。一聲溪鳥暗雲散，", "紅蝦青鯽紫芹脆，歸去不辭來路長。"]'),
('yuding-24','故洛城','許渾','唐','御定全唐诗','yuding','','[]','禾黍離離半野蒿，昔人城此豈知勞。水聲東去市朝變，',40,'御定全唐詩/json/533.json','["禾黍離離半野蒿，昔人城此豈知勞。水聲東去市朝變，", "可憐緱嶺登仙子，猶自吹笙醉碧桃。"]'),
('yuding-25','聞釋子棲玄欲奉道因寄','許渾','唐','御定全唐诗','yuding','','[]','欲求真訣戀禪扃，羽帔方袍盡有情。仙骨本微靈鶴遠，',40,'御定全唐詩/json/533.json','["欲求真訣戀禪扃，羽帔方袍盡有情。仙骨本微靈鶴遠，", "今日勸師師莫惑，長生難學證無生。"]'),
('yuding-26','南海府罷南康阻淺行侶稍稍登陸而邁主人燕餞至頻暮宿東溪','許渾','唐','御定全唐诗','yuding','','[]','暗灘水落漲虛沙，灘去秦吳萬里賒。馬上折殘江北柳，',40,'御定全唐詩/json/533.json','["暗灘水落漲虛沙，灘去秦吳萬里賒。馬上折殘江北柳，", "山鳥一聲人未起，半床春月在天涯。"]'),
('yuding-27','秋晚雲陽驛西亭蓮池','許渾','唐','御定全唐诗','yuding','','[]','心憶蓮池秉燭游，葉殘花敗尚維舟。煙開翠扇清風曉，',40,'御定全唐詩/json/533.json','["心憶蓮池秉燭游，葉殘花敗尚維舟。煙開翠扇清風曉，", "空懷遠道難持贈，醉倚闌幹盡日愁。"]'),
('yuding-28','題勤尊師曆陽山居','許渾','唐','御定全唐诗','yuding','','[]','二十知兵在羽林，中年潛識子房心。蒼鷹出塞胡塵滅。',64,'御定全唐詩/json/533.json','["二十知兵在羽林，中年潛識子房心。蒼鷹出塞胡塵滅。", "白鶴還鄉楚水深。春坼酒瓶浮藥氣，晚攜棋局帶松陰。", "雞籠山上雲多處，自劚黃精不可尋。"]'),
('yuding-29','懷舊居','許渾','唐','御定全唐诗','yuding','','[]','兵書一篋老無功，故國郊扉在夢中。藤蔓覆梨張穀暗。',64,'御定全唐詩/json/533.json','["兵書一篋老無功，故國郊扉在夢中。藤蔓覆梨張穀暗。", "草花侵菊庾園空。朱門跡忝登龍客，白屋心期失馬翁。", "楚水吳山何處是，北窗殘月照屏風。"]'),
('yuding-30','祗命許昌自郊居，移就公館秋日寄茅山高拾遺','許渾','唐','御定全唐诗','yuding','','[]','一笛迎風萬葉飛，強攜刀筆換荷衣。潮寒水國秋砧早，',40,'御定全唐詩/json/533.json','["一笛迎風萬葉飛，強攜刀筆換荷衣。潮寒水國秋砧早，", "中年未識從軍樂，虛近三茅望少微。"]'),
('yuding-31','傷虞將軍','許渾','唐','御定全唐诗','yuding','','[]','白首從軍未有名，近將孤劍到江城。巴童戍久能番語，',40,'御定全唐詩/json/533.json','["白首從軍未有名，近將孤劍到江城。巴童戍久能番語，", "可憐身死家猶遠，汴水東流無哭聲。"]'),
('yuding-32','晚自朝台津至韋隱居郊園','許渾','唐','御定全唐诗','yuding','','[]','秋來鳧雁下方塘，系馬朝臺步夕陽。村徑繞山松葉暗，',40,'御定全唐詩/json/533.json','["秋來鳧雁下方塘，系馬朝臺步夕陽。村徑繞山松葉暗，", "西下磻溪猶萬里，可能垂白待文王。"]'),
('yuding-33','寓居開元精舍，酬薛秀才見貽','許渾','唐','御定全唐诗','yuding','','[]','知己蕭條信陸沉，茂陵扶疾臥西林。芰荷風起客堂靜，',40,'御定全唐詩/json/533.json','["知己蕭條信陸沉，茂陵扶疾臥西林。芰荷風起客堂靜，", "憐君詩句猶相憶，題在空齋夜夜吟。"]'),
('yuding-34','別劉秀才','許渾','唐','御定全唐诗','yuding','','[]','三獻無功玉有瑕，更攜書劍客天涯。孤帆夜別瀟湘雨，',40,'御定全唐詩/json/533.json','["三獻無功玉有瑕，更攜書劍客天涯。孤帆夜別瀟湘雨，", "關河萬里秋風急，望見鄉山不到家。"]'),
('yuding-35','早發天臺中岩寺度關嶺次天姥岑','許渾','唐','御定全唐诗','yuding','','[]','來往天臺天姥間，欲求真訣駐衰顏。星河半落岩前寺，',40,'御定全唐詩/json/533.json','["來往天臺天姥間，欲求真訣駐衰顏。星河半落岩前寺，", "可知劉阮逢人處，行盡深山又是山。"]'),
('yuding-36','游錢塘青山李隱居西齋','許渾','唐','御定全唐诗','yuding','','[]','小隱西亭為客開，翠蘿深處遍蒼苔。林間掃石安棋局，',40,'御定全唐詩/json/533.json','["小隱西亭為客開，翠蘿深處遍蒼苔。林間掃石安棋局，", "雲山繞屋猶嫌淺，欲棹漁舟近釣台。"]'),
('yuding-37','春日郊園戲贈楊嘏評事','許渾','唐','御定全唐诗','yuding','','[]','十裏蒹葭入薜蘿，春風誰許暫鳴珂。相如渴後狂還減，',40,'御定全唐詩/json/533.json','["十裏蒹葭入薜蘿，春風誰許暫鳴珂。相如渴後狂還減，", "野橋沽酒茅簷醉，誰羨紅樓一曲歌。"]'),
('yuding-38','晚自東郭回留一二游侶','許渾','唐','御定全唐诗','yuding','','[]','鄉心迢遞宦情微，吏散尋幽竟落暉。林下草腥巢鷺宿，',40,'御定全唐詩/json/533.json','["鄉心迢遞宦情微，吏散尋幽竟落暉。林下草腥巢鷺宿，", "今夜西齋好風月，一瓢春酒莫相違。"]'),
('yuding-39','與鄭秀才叔侄會送楊秀才昆仲東歸','許渾','唐','御定全唐诗','yuding','','[]','書劍功遲白髮新，異鄉仍送故鄉人。阮公留客竹林晚，',40,'御定全唐詩/json/533.json','["書劍功遲白髮新，異鄉仍送故鄉人。阮公留客竹林晚，", "洞庭煙月如終老，誰是長楊諫獵臣。"]'),
('yuding-40','送郭秀才游天臺','許渾','唐','御定全唐诗','yuding','','[]','雲埋陰壑雪凝峰，半壁天臺已萬重。人度碧溪疑輟棹，',40,'御定全唐詩/json/533.json','["雲埋陰壑雪凝峰，半壁天臺已萬重。人度碧溪疑輟棹，", "曾約共遊今獨去，赤城西面水溶溶。"]'),
('yuding-41','送張尊師歸洞庭','許渾','唐','御定全唐诗','yuding','','[]','能琴道士洞庭西，風滿歸帆路不迷。對岸水花霜後淺，',40,'御定全唐詩/json/533.json','["能琴道士洞庭西，風滿歸帆路不迷。對岸水花霜後淺，", "他日相思兩行字，無人知處武陵溪。"]'),
('yuding-42','移攝太平寄前李明府','許渾','唐','御定全唐诗','yuding','','[]','病移岩邑稱閑身，何處風光貰酒頻。溪柳繞門彭澤令，',40,'御定全唐詩/json/533.json','["病移岩邑稱閑身，何處風光貰酒頻。溪柳繞門彭澤令，", "早晚高臺更同醉，綠蘿如帳草如茵。"]'),
('yuding-0','再游姑蘇玉芝觀','許渾','唐','御定全唐诗','yuding','','[]','高梧一葉下秋初，迢遞重廊舊寄居。月過碧窗今夜酒，',40,'御定全唐詩/json/534.json','["高梧一葉下秋初，迢遞重廊舊寄居。月過碧窗今夜酒，", "明日掛帆更東去，仙翁應笑為鱸魚。"]'),
('yuding-1','夜歸驛樓','許渾','唐','御定全唐诗','yuding','','[]','水晚雲秋山不窮，自疑身在畫屏中。孤舟移棹一江月，',40,'御定全唐詩/json/534.json','["水晚雲秋山不窮，自疑身在畫屏中。孤舟移棹一江月，", "早炊香稻待鱸鱠，南渚未明尋釣翁。"]'),
('yuding-2','題靈山寺行堅師院','許渾','唐','御定全唐诗','yuding','','[]','西岩一徑不通樵，八十持杯未覺遙。龍在石潭聞夜雨，',40,'御定全唐詩/json/534.json','["西岩一徑不通樵，八十持杯未覺遙。龍在石潭聞夜雨，", "應笑東歸又南去，越山無路水迢迢。"]'),
('yuding-3','湖州韋長史山居','許渾','唐','御定全唐诗','yuding','','[]','一官唯買晝公堂，但得身閑日自長。琴曲少聲重勘譜，',40,'御定全唐詩/json/534.json','["一官唯買晝公堂，但得身閑日自長。琴曲少聲重勘譜，", "明日鱖魚何處釣，門前春水似滄浪。"]'),
('yuding-4','贈李伊闕','許渾','唐','御定全唐诗','yuding','','[]','桐履如飛不可尋，一壺雙笈嶧陽琴。舟橫野渡寒風急，',40,'御定全唐詩/json/534.json','["桐履如飛不可尋，一壺雙笈嶧陽琴。舟橫野渡寒風急，", "雲間二室勞君畫，水墨蒼蒼半壁陰。"]'),
('yuding-5','重遊練湖懷舊','許渾','唐','御定全唐诗','yuding','','[]','西風渺渺月連天，同醉蘭舟未十年。鵩鳥賦成人已沒，',40,'御定全唐詩/json/534.json','["西風渺渺月連天，同醉蘭舟未十年。鵩鳥賦成人已沒，", "日暮長堤更回首，一聲鄰笛舊山川。"]'),
('yuding-6','乘月棹舟送大曆寺靈聰上人不及','許渾','唐','御定全唐诗','yuding','','[]','萬峰秋盡百泉清，舊鎖禪扉在赤城。楓浦客來煙未散，',40,'御定全唐詩/json/534.json','["萬峰秋盡百泉清，舊鎖禪扉在赤城。楓浦客來煙未散，", "一字不留何足訝，白雲無路水無情。"]'),
('yuding-7','汴河亭','許渾','唐','御定全唐诗','yuding','','[]','廣陵花盛帝東遊，先劈昆侖一派流。百二禁兵辭象闕，',40,'御定全唐詩/json/534.json','["廣陵花盛帝東遊，先劈昆侖一派流。百二禁兵辭象闕，", "四海義師歸有道，迷樓還似景陽樓。"]'),
('yuding-8','村舍二首','許渾','唐','御定全唐诗','yuding','','[]','自翦青莎織雨衣，南峰煙火是柴扉。萊妻早報蒸藜熟，',80,'御定全唐詩/json/534.json','["自翦青莎織雨衣，南峰煙火是柴扉。萊妻早報蒸藜熟，", "花時未免人來往，欲買嚴光舊釣磯。", "尚平多累自歸難，一日身閑一日安。山徑曉雲收獵網，", "三頃水田秋更熟，北窗誰拂舊塵冠。"]'),
('yuding-9','鄭秀才東歸憑達家書','許渾','唐','御定全唐诗','yuding','','[]','欲寄家書少客過，閉門心遠洞庭波。兩岩花落夜風急，',40,'御定全唐詩/json/534.json','["欲寄家書少客過，閉門心遠洞庭波。兩岩花落夜風急，", "貧居不問應知處，溪上閑船系綠蘿。"]'),
('yuding-10','傷故湖州李郎中','許渾','唐','御定全唐诗','yuding','','[]','政成身沒共興衰，鄉路兵戈旅櫬回。城上暮雲凝鼓角，',40,'御定全唐詩/json/534.json','["政成身沒共興衰，鄉路兵戈旅櫬回。城上暮雲凝鼓角，", "南北相逢皆掩泣，白蘋洲暖百花開。"]'),
('yuding-11','和友人送僧歸桂州靈岩寺','許渾','唐','御定全唐诗','yuding','','[]','楚客送僧歸桂陽，海門帆勢極瀟湘。碧雲千里暮愁合，',40,'御定全唐詩/json/534.json','["楚客送僧歸桂陽，海門帆勢極瀟湘。碧雲千里暮愁合，", "南京長老幾年別，聞道半岩多影堂。"]'),
('yuding-12','淮陰阻風寄呈楚州韋中丞','許渾','唐','御定全唐诗','yuding','','[]','垂釣京江欲白頭，江魚堪釣卻西遊。劉伶台下稻花晚，',40,'御定全唐詩/json/534.json','["垂釣京江欲白頭，江魚堪釣卻西遊。劉伶台下稻花晚，", "河橋有酒無人醉，獨上高城望庾樓。"]'),
('yuding-13','途經敷水','許渾','唐','御定全唐诗','yuding','','[]','修蛾顰翠倚柔桑，遙謝春風白麵郎。五夜有情隨暮雨，',40,'御定全唐詩/json/534.json','["修蛾顰翠倚柔桑，遙謝春風白麵郎。五夜有情隨暮雨，", "何處野花何處水，下峰流出一渠香。"]'),
('yuding-14','和人賀楊僕射致政','許渾','唐','御定全唐诗','yuding','','[]','蓮府公卿拜後塵，手持優詔掛朱輪。從軍幕下三千客，',40,'御定全唐詩/json/534.json','["蓮府公卿拜後塵，手持優詔掛朱輪。從軍幕下三千客，", "豈同王謝山陰會，空敘流杯醉暮春。"]'),
('yuding-15','題四皓廟','許渾','唐','御定全唐诗','yuding','','[]','桂香松暖廟門開，獨瀉椒漿奠一杯。秦法欲興鴻已去，',40,'御定全唐詩/json/534.json','["桂香松暖廟門開，獨瀉椒漿奠一杯。秦法欲興鴻已去，", "山下驛塵南竄路，不知冠蓋幾人回。"]'),
('yuding-16','鶴林寺中秋夜玩月','許渾','唐','御定全唐诗','yuding','','[]','待月東林月正圓，廣庭無樹草無煙。中秋雲盡出滄海，',40,'御定全唐詩/json/534.json','["待月東林月正圓，廣庭無樹草無煙。中秋雲盡出滄海，", "莫辭達曙殷勤望，一墮西岩又來年。"]'),
('yuding-17','南海府罷歸京口經大庾嶺贈張明府','許渾','唐','御定全唐诗','yuding','','[]','樓船旌旆極天涯，一劍從軍兩鬢華。回日眼明河畔草。',64,'御定全唐詩/json/534.json','["樓船旌旆極天涯，一劍從軍兩鬢華。回日眼明河畔草。", "去時腸斷嶺頭花。陶詩盡寫行過縣，張賦初成臥到家。", "官滿知君有歸處，姑蘇臺上舊煙霞。"]'),
('yuding-18','題衛將軍廟','許渾','唐','御定全唐诗','yuding','','[]','武牢關下護龍旗，挾槊彎弧馬上飛。漢業未興王霸在，',40,'御定全唐詩/json/534.json','["武牢關下護龍旗，挾槊彎弧馬上飛。漢業未興王霸在，", "欲奠忠魂何處問，葦花楓葉雨霏霏。"]'),
('yuding-19','訪別韋隱居不值','許渾','唐','御定全唐诗','yuding','','[]','犬吠雙岩碧樹間，主人朝出半開關。湯師閣上留詩別，',40,'御定全唐詩/json/534.json','["犬吠雙岩碧樹間，主人朝出半開關。湯師閣上留詩別，", "故鄉蕪沒兵戈後，憑向溪南買一山。"]'),
('yuding-20','送前東陽於明府由鄂渚歸故林','許渾','唐','御定全唐诗','yuding','','[]','結束征東換黑貂，灞西風雨正瀟瀟。茂陵久病書千卷，',40,'御定全唐詩/json/534.json','["結束征東換黑貂，灞西風雨正瀟瀟。茂陵久病書千卷，", "殷勤為謝南溪客，白首螢窗未見招。"]'),
('yuding-21','聽歌鷓鴣辭','許渾','唐','御定全唐诗','yuding','','[]','南國多情多豔詞，鷓鴣清怨繞梁飛。甘棠城上客先醉，',40,'御定全唐詩/json/534.json','["南國多情多豔詞，鷓鴣清怨繞梁飛。甘棠城上客先醉，", "山行水宿不知遠，猶夢玉釵金縷衣。"]'),
('yuding-22','寄題華嚴韋秀才院','許渾','唐','御定全唐诗','yuding','','[]','三面樓臺百丈峰，西岩高枕樹重重。晴攀翠竹題詩滑，',40,'御定全唐詩/json/534.json','["三面樓臺百丈峰，西岩高枕樹重重。晴攀翠竹題詩滑，", "今來故國遙相憶，月照千山半夜鐘。"]'),
('yuding-23','戲代李協律松江有贈','許渾','唐','御定全唐诗','yuding','','[]','蜀客操琴吳女歌，明珠十斛是天河。霜凝薜荔怯秋樹，',40,'御定全唐詩/json/534.json','["蜀客操琴吳女歌，明珠十斛是天河。霜凝薜荔怯秋樹，", "西樓沉醉不知散，潮落洞庭洲渚多。"]'),
('yuding-24','送黃隱居歸南海','許渾','唐','御定全唐诗','yuding','','[]','瘴霧南邊久寄家，海中來往信流槎。林藏狒狒多殘筍，',40,'御定全唐詩/json/534.json','["瘴霧南邊久寄家，海中來往信流槎。林藏狒狒多殘筍，", "知君愛宿層峰頂，坐到三更見日華。"]'),
('yuding-25','朝台送客有懷','許渾','唐','御定全唐诗','yuding','','[]','趙佗西拜已登壇，馬援南征土宇寬。越國舊無唐印綬，',40,'御定全唐詩/json/534.json','["趙佗西拜已登壇，馬援南征土宇寬。越國舊無唐印綬，", "嶺北歸人莫回首，蓼花楓葉萬重灘。"]'),
('yuding-26','自楞伽寺晨起泛舟，道中有懷','許渾','唐','御定全唐诗','yuding','','[]','碧樹蒼蒼茂苑東，佳期迢遞路何窮。一聲山鳥曙雲外，',40,'御定全唐詩/json/534.json','["碧樹蒼蒼茂苑東，佳期迢遞路何窮。一聲山鳥曙雲外，", "欲知此路堪惆悵，菱葉蓼花連故宮。"]'),
('yuding-27','十二月拜起居表回','許渾','唐','御定全唐诗','yuding','','[]','一章西奏拜仙曹，回馬天津北望勞。寒水欲春冰彩薄，',40,'御定全唐詩/json/534.json','["一章西奏拜仙曹，回馬天津北望勞。寒水欲春冰彩薄，", "空鎖煙霞絕巡幸，周人誰識郁金袍。"]'),
('yuding-28','觀章中丞夜按歌舞','許渾','唐','御定全唐诗','yuding','','[]','夜按雙娃禁曲新，東西簫鼓接雲津。舞衫未換紅鉛濕，',40,'御定全唐詩/json/534.json','["夜按雙娃禁曲新，東西簫鼓接雲津。舞衫未換紅鉛濕，", "西樓月在襄王醉，十二山高不見人。"]'),
('yuding-29','重遊飛泉觀題故梁道士宿龍池','許渾','唐','御定全唐诗','yuding','','[]','西岩泉落水容寬，靈物蜿蜒黑處蟠。松葉正秋琴韻響，',40,'御定全唐詩/json/534.json','["西岩泉落水容寬，靈物蜿蜒黑處蟠。松葉正秋琴韻響，", "仙客不歸龍亦去，稻畦長滿此池幹。"]'),
('yuding-30','下第貽友人','許渾','唐','御定全唐诗','yuding','','[]','身在關西家洞庭，夜寒歌苦燭熒熒。人心高下月中桂，',40,'御定全唐詩/json/534.json','["身在關西家洞庭，夜寒歌苦燭熒熒。人心高下月中桂，", "花前失意共寥落，莫遣東風吹酒醒。"]'),
('yuding-31','晚登龍門驛樓','許渾','唐','御定全唐诗','yuding','','[]','魚龍多處鑿門開，萬古人知夏禹材。青嶂遠分從地斷，',40,'御定全唐詩/json/534.json','["魚龍多處鑿門開，萬古人知夏禹材。青嶂遠分從地斷，", "心感膺門身過此，晚山秋樹獨徘徊。"]'),
('yuding-32','題故李秀才居','許渾','唐','御定全唐诗','yuding','','[]','曾醉笙歌日正遲，醉中相送易前期。橘花滿地人亡後，',40,'御定全唐詩/json/534.json','["曾醉笙歌日正遲，醉中相送易前期。橘花滿地人亡後，", "河橋酒熟平生事，更向東流奠一厄。"]'),
('yuding-33','韶州韶陽樓夜宴','許渾','唐','御定全唐诗','yuding','','[]','待月西樓卷翠羅，玉杯瑤瑟近星河。簾前碧樹窮秋密，',40,'御定全唐詩/json/534.json','["待月西樓卷翠羅，玉杯瑤瑟近星河。簾前碧樹窮秋密，", "使君莫惜通宵飲，刀筆初從馬伏波。"]'),
('yuding-34','聞韶州李相公移拜郴州因寄','許渾','唐','御定全唐诗','yuding','','[]','詔移丞相木蘭舟，桂水潺湲嶺北流。青漢夢歸雙闕曙，',40,'御定全唐詩/json/534.json','["詔移丞相木蘭舟，桂水潺湲嶺北流。青漢夢歸雙闕曙，", "聞說公卿盡南望，甘棠花暖鳳池頭。"]'),
('yuding-35','游江令舊宅','許渾','唐','御定全唐诗','yuding','','[]','身沒南朝宅已荒，邑人猶賞舊風光。芹根生葉石池淺，',40,'御定全唐詩/json/534.json','["身沒南朝宅已荒，邑人猶賞舊風光。芹根生葉石池淺，", "閒愁此地更西望，潮浸台城春草長。"]'),
('yuding-36','灞上逢元九處士東歸','許渾','唐','御定全唐诗','yuding','','[]','瘦馬頻嘶灞水寒，灞南高處望長安。何人更結王生襪，',40,'御定全唐詩/json/534.json','["瘦馬頻嘶灞水寒，灞南高處望長安。何人更結王生襪，", "舊交已變新知少，卻伴漁郎把釣竿。"]'),
('yuding-37','別張秀才','許渾','唐','御定全唐诗','yuding','','[]','不知何計寫離憂，萬里山川半舊遊。風卷暮沙和雪起，',40,'御定全唐詩/json/534.json','["不知何計寫離憂，萬里山川半舊遊。風卷暮沙和雪起，", "青桂一枝年少事，莫因鱸鱠涉窮秋。"]'),
('yuding-38','別表兄軍倅','許渾','唐','御定全唐诗','yuding','','[]','盧橘花香拂釣磯，佳人猶舞越羅衣。三洲水淺魚來少，',40,'御定全唐詩/json/534.json','["盧橘花香拂釣磯，佳人猶舞越羅衣。三洲水淺魚來少，", "交親不念征南吏，昨夜風帆去似飛。"]'),
('yuding-39','題蘇州虎丘寺僧院','許渾','唐','御定全唐诗','yuding','','[]','暫引寒泉濯遠塵，此生多是異鄉人。荊溪夜雨花開疾，',40,'御定全唐詩/json/534.json','["暫引寒泉濯遠塵，此生多是異鄉人。荊溪夜雨花開疾，", "世間誰似西林客，一臥煙霞四十春。"]'),
('yuding-40','酬郭少府先奉使巡澇見寄兼呈裴明府','許渾','唐','御定全唐诗','yuding','','[]','載書攜榼別池龍，十幅輕帆處處通。謝脁宅荒山翠裏，',40,'御定全唐詩/json/534.json','["載書攜榼別池龍，十幅輕帆處處通。謝脁宅荒山翠裏，", "飽食鱠魚榜歸楫，待君琴酒醉陶公。"]'),
('yuding-41','出永通門經李氏莊','許渾','唐','御定全唐诗','yuding','','[]','飛軒危檻百花堂，朝宴歌鐘暮已荒。中散獄成琴自怨，',40,'御定全唐詩/json/534.json','["飛軒危檻百花堂，朝宴歌鐘暮已荒。中散獄成琴自怨，", "力保山河家又慶，只應中令敵汾陽。"]'),
('yuding-0','漢水傷稼','許渾','唐','御定全唐诗','yuding','','[]','西北樓開四望通，殘霞成綺月懸弓。江村夜漲浮天水，',40,'御定全唐詩/json/535.json','["西北樓開四望通，殘霞成綺月懸弓。江村夜漲浮天水，", "才微分薄憂何益，卻欲回心學釣翁。"]'),
('yuding-1','送王總下第歸丹陽','許渾','唐','御定全唐诗','yuding','','[]','秦樓心斷楚江湄，系馬春風酒一卮。汴水月明東下疾，',40,'御定全唐詩/json/535.json','["秦樓心斷楚江湄，系馬春風酒一卮。汴水月明東下疾，", "憑寄家書為回報，舊鄉還有故人知。"]'),
('yuding-2','南陽道中','許渾','唐','御定全唐诗','yuding','','[]','月斜孤館傍村行，野店高低帶古城。籬上曉花齋後落，',40,'御定全唐詩/json/535.json','["月斜孤館傍村行，野店高低帶古城。籬上曉花齋後落，", "荒草連天風動地，不知誰學武侯耕。"]'),
('yuding-3','破北虜太和公主歸宮闕','許渾','唐','御定全唐诗','yuding','','[]','毳幕承秋極斷蓬，飄颻一劍黑山空。匈奴北走荒秦壘，',40,'御定全唐詩/json/535.json','["毳幕承秋極斷蓬，飄颻一劍黑山空。匈奴北走荒秦壘，", "恩沾殘類從歸去，莫使華人雜犬戎。"]'),
('yuding-4','李定言自殿院銜命歸闕，拜員外郎遷右史因寄','許渾','唐','御定全唐诗','yuding','','[]','白筆南征變二毛，越山愁瘴海驚濤。才歸龍尾含雞舌，',40,'御定全唐詩/json/535.json','["白筆南征變二毛，越山愁瘴海驚濤。才歸龍尾含雞舌，", "吳中舊侶君先貴，曾憶王祥與佩刀。"]'),
('yuding-5','早秋韶陽夜雨','許渾','唐','御定全唐诗','yuding','','[]','宋玉含淒夢亦驚，芙蓉山響一猿聲。陰雲迎雨枕先潤，',40,'御定全唐詩/json/535.json','["宋玉含淒夢亦驚，芙蓉山響一猿聲。陰雲迎雨枕先潤，", "西歸萬里未千里，應到故園春草生。"]'),
('yuding-6','將為南行陪尚書崔公宴海榴堂','許渾','唐','御定全唐诗','yuding','','[]','朝宴華堂暮未休，幾人偏得謝公留。風傳鼓角霜侵戟，',40,'御定全唐詩/json/535.json','["朝宴華堂暮未休，幾人偏得謝公留。風傳鼓角霜侵戟，", "謾誇書劍無知己，水遠山長步步愁。"]'),
('yuding-7','贈王山人','許渾','唐','御定全唐诗','yuding','','[]','貰酒攜琴訪我頻，始知城市有閒人。君臣藥在寧憂病，',40,'御定全唐詩/json/535.json','["貰酒攜琴訪我頻，始知城市有閒人。君臣藥在寧憂病，", "近來聞說燒丹處，玉洞桃花萬樹春。"]'),
('yuding-8','宣城崔大夫召聯句，偶疾不獲赴因獻','許渾','唐','御定全唐诗','yuding','','[]','心慕知音命自拘，畫堂聞欲試吹竽。茂陵罷酒慚中聖，',40,'御定全唐詩/json/535.json','["心慕知音命自拘，畫堂聞欲試吹竽。茂陵罷酒慚中聖，", "還愁旅棹空歸去，楓葉荷花釣五湖。"]'),
('yuding-9','贈鄭處士','許渾','唐','御定全唐诗','yuding','','[]','道傍年少莫矜誇，心在重霄鬢未華。楊子可曾過北裏，',40,'御定全唐詩/json/535.json','["道傍年少莫矜誇，心在重霄鬢未華。楊子可曾過北裏，", "且賣湖田釀春酒，與君書劍是生涯。"]'),
('yuding-10','正元','許渾','唐','御定全唐诗','yuding','','[]','高揭雞竿辟帝閽，祥風微暖瑞雲屯。千官共削奸臣跡，',40,'御定全唐詩/json/535.json','["高揭雞竿辟帝閽，祥風微暖瑞雲屯。千官共削奸臣跡，", "華夷一軌人方泰，莫學論兵誤至尊。"]'),
('yuding-11','登尉佗樓','許渾','唐','御定全唐诗','yuding','','[]','劉項持兵鹿未窮，自乘黃屋島夷中。南來作尉任囂力，',40,'御定全唐詩/json/535.json','["劉項持兵鹿未窮，自乘黃屋島夷中。南來作尉任囂力，", "越人未必知虞舜，一奏熏弦萬古風。"]'),
('yuding-12','韶州驛樓宴罷','許渾','唐','御定全唐诗','yuding','','[]','簷外千帆背夕陽，歸心杳杳鬢蒼蒼。嶺猿群宿夜山靜，',40,'御定全唐詩/json/535.json','["簷外千帆背夕陽，歸心杳杳鬢蒼蒼。嶺猿群宿夜山靜，", "主人不醉下樓去，月在南軒更漏長。"]'),
('yuding-13','和淮南王相公與賓僚同遊瓜洲別業，題舊書齋','許渾','唐','御定全唐诗','yuding','','[]','碧油紅旆想青衿，積雪窗前盡日吟。巢鶴去時雲樹老，',40,'御定全唐詩/json/535.json','["碧油紅旆想青衿，積雪窗前盡日吟。巢鶴去時雲樹老，", "賓禦莫辭岩下醉，武丁高枕待為霖。"]'),
('yuding-14','送盧先輩自衡岳赴複州嘉禮二首','許渾','唐','御定全唐诗','yuding','','[]','名振金閨步玉京，暫留滄海見高情。眾花盡處松千尺，',80,'御定全唐詩/json/535.json','["名振金閨步玉京，暫留滄海見高情。眾花盡處松千尺，", "離心不異西江水，直送征帆萬里行。", "湘南詩客海中行，鵬翅垂雲不自矜。秋水靜磨金鏡土，", "醉倚西樓人已遠，柳溪無浪月澄澄。"]'),
('yuding-15','哭楊攀處士','許渾','唐','御定全唐诗','yuding','','[]','先生憂道樂清貧，白髮終為不仕身。嵇阮沒來無酒客，',40,'御定全唐詩/json/535.json','["先生憂道樂清貧，白髮終為不仕身。嵇阮沒來無酒客，", "昨夜回舟更惆悵，至今鐘磬滿南鄰。"]'),
('yuding-16','宿松江驛卻寄蘇州一二同志','許渾','唐','御定全唐诗','yuding','','[]','候館人稀夜自長，姑蘇台遠樹蒼蒼。江湖潮落高樓迥，',40,'御定全唐詩/json/535.json','["候館人稀夜自長，姑蘇台遠樹蒼蒼。江湖潮落高樓迥，", "西園詩侶應多思，莫醉笙歌掩畫堂。"]'),
('yuding-17','盧山人自巴蜀由湘潭歸茅山因贈','許渾','唐','御定全唐诗','yuding','','[]','太乙靈方煉紫荷，紫荷飛盡發皤皤。猿啼巫峽曉雲薄，',40,'御定全唐詩/json/535.json','["太乙靈方煉紫荷，紫荷飛盡發皤皤。猿啼巫峽曉雲薄，", "華陽舊隱莫歸去，水沒芝田生綠莎。"]'),
('yuding-18','潁州從事西湖亭宴餞','許渾','唐','御定全唐诗','yuding','','[]','西湖清宴不知回，一曲離歌酒一杯。城帶夕陽聞鼓角，',40,'御定全唐詩/json/535.json','["西湖清宴不知回，一曲離歌酒一杯。城帶夕陽聞鼓角，", "獨想征車過鞏洛，此中霜菊繞潭開。"]'),
('yuding-19','瓜洲留別李詡','許渾','唐','御定全唐诗','yuding','','[]','泣玉三年一見君，白衣憔悴更離群。柳堤惜別春潮落，',40,'御定全唐詩/json/535.json','["泣玉三年一見君，白衣憔悴更離群。柳堤惜別春潮落，", "悲歌曲盡莫重奏，心繞關河不忍聞。"]'),
('yuding-20','余謝病東歸，王秀才見寄，今潘秀才南棹奉酬','許渾','唐','御定全唐诗','yuding','','[]','酷似牢之玉不如，落星山下白雲居。春耕旋構金門客，',40,'御定全唐詩/json/535.json','["酷似牢之玉不如，落星山下白雲居。春耕旋構金門客，", "莫將年少輕時節，王氏家風在石渠。"]'),
('yuding-21','獻韶陽相國崔公','許渾','唐','御定全唐诗','yuding','','[]','一匱為功極九層，康莊猶自劍棱棱。舟回北渚經年泊，',40,'御定全唐詩/json/535.json','["一匱為功極九層，康莊猶自劍棱棱。舟回北渚經年泊，", "賢臣會致唐虞世，獨倚江樓笑範增。"]'),
('yuding-22','郡齋夜坐寄舊鄉二侄','許渾','唐','御定全唐诗','yuding','','[]','千官奉職袞龍垂，旅臥淮陽鬢日衰。三月已乖棠樹政，',40,'御定全唐詩/json/535.json','["千官奉職袞龍垂，旅臥淮陽鬢日衰。三月已乖棠樹政，", "長欲掛帆君莫笑，越禽花晚夢南枝。"]'),
('yuding-23','病間寄郡中文士','許渾','唐','御定全唐诗','yuding','','[]','盧橘含花處處香，老人依舊臥清漳。心同客舍驚秋早，',40,'御定全唐詩/json/535.json','["盧橘含花處處香，老人依舊臥清漳。心同客舍驚秋早，", "明朝欲醉文中彥，猶覺吟聲帶越鄉。"]'),
('yuding-24','賀少師相公致政','許渾','唐','御定全唐诗','yuding','','[]','六十懸車自古稀，我公年少獨忘機。門臨二室留侯隱，',40,'御定全唐詩/json/535.json','["六十懸車自古稀，我公年少獨忘機。門臨二室留侯隱，", "龍城鳳沼棠陰在，只恐歸鴻更北飛。"]'),
('yuding-25','題崔處士山居','許渾','唐','御定全唐诗','yuding','','[]','坐窮今古掩書堂，二頃湖田一半荒。荊樹有花兄弟樂，',40,'御定全唐詩/json/535.json','["坐窮今古掩書堂，二頃湖田一半荒。荊樹有花兄弟樂，", "向夜欲歸心萬里，故園松月更蒼蒼。"]'),
('yuding-26','疾後與郡中群公宴李秀才','許渾','唐','御定全唐诗','yuding','','[]','強留佳客宴王孫，岩上餘花落酒樽。書院欲開蟲網戶，',40,'御定全唐詩/json/535.json','["強留佳客宴王孫，岩上餘花落酒樽。書院欲開蟲網戶，", "莫引劉安倚西檻，夜來紅葉下江村。"]'),
('yuding-27','晨起白雲樓寄龍興江准上人兼呈竇秀才','許渾','唐','御定全唐诗','yuding','','[]','茲樓今是望鄉台，鄉信全稀曉雁哀。山翠萬重當檻出，',40,'御定全唐詩/json/535.json','["茲樓今是望鄉台，鄉信全稀曉雁哀。山翠萬重當檻出，", "欲吊靈均能賦否，秋風還有木蘭開。"]'),
('yuding-28','宴餞李員外','許渾','唐','御定全唐诗','yuding','','[]','病守江城眼暫開，昔年吳越共銜杯。膺舟出鎮虛陳榻，',40,'御定全唐詩/json/535.json','["病守江城眼暫開，昔年吳越共銜杯。膺舟出鎮虛陳榻，", "心期解印同君醉，九曲池西望月來。"]'),
('yuding-29','酬錢汝州','許渾','唐','御定全唐诗','yuding','','[]','白雪多隨漢水流，謾勞旌旆晚悠悠。笙歌暗寫終年恨，',40,'御定全唐詩/json/535.json','["白雪多隨漢水流，謾勞旌旆晚悠悠。笙歌暗寫終年恨，", "怪來雅韻清無敵，三十六峰當庾樓。"]'),
('yuding-30','將歸姑蘇南樓餞送李明府','許渾','唐','御定全唐诗','yuding','','[]','無處登臨不系情，一憑春酒醉高城。暫移羅綺見山色，',40,'御定全唐詩/json/535.json','["無處登臨不系情，一憑春酒醉高城。暫移羅綺見山色，", "前期迢遞今宵短，更倚朱闌待月明。"]'),
('yuding-31','和浙西從事劉三複送僧南歸','許渾','唐','御定全唐诗','yuding','','[]','楚客送僧歸故鄉，海門帆勢極瀟湘。碧雲千里暮愁合，',40,'御定全唐詩/json/535.json','["楚客送僧歸故鄉，海門帆勢極瀟湘。碧雲千里暮愁合，", "憐師不得隨師去，已戴儒冠事素王。"]'),
('yuding-32','送上元王明府赴任','許渾','唐','御定全唐诗','yuding','','[]','莫言名重懶驅雞，六代江山碧海西。日照蒹葭明楚塞，',40,'御定全唐詩/json/535.json','["莫言名重懶驅雞，六代江山碧海西。日照蒹葭明楚塞，", "官滿定知歸未得，九重霄漢有丹梯。"]'),
('yuding-33','送沈卓少府任江都','許渾','唐','御定全唐诗','yuding','','[]','煬帝都城春水邊，笙歌夜上木蘭船。三千宮女自塗地，',40,'御定全唐詩/json/535.json','["煬帝都城春水邊，笙歌夜上木蘭船。三千宮女自塗地，", "少年作尉須兢慎，莫向樓前墜馬鞭。"]'),
('yuding-34','酬邢杜二員外','許渾','唐','御定全唐诗','yuding','','[]','雪帶東風洗畫屏，客星懸處聚文星。未歸嵩嶺暮雲碧，',40,'御定全唐詩/json/535.json','["雪帶東風洗畫屏，客星懸處聚文星。未歸嵩嶺暮雲碧，", "豈知京洛舊親友，夢繞潺湲江上亭。"]'),
('yuding-35','經故丁補闕郊居','許渾','唐','御定全唐诗','yuding','','[]','死酬知己道終全，波暖孤冰且自堅。鵩上承塵才一日，',40,'御定全唐詩/json/535.json','["死酬知己道終全，波暖孤冰且自堅。鵩上承塵才一日，", "四尺孤墳何處是，闔閭城外草連天。"]'),
('yuding-36','陪宣城大夫崔公泛後池兼北樓宴二首','許渾','唐','御定全唐诗','yuding','','[]','陪泛芳池醉北樓，水花繁豔照膺舟。亭台陰合樹初晝，',80,'御定全唐詩/json/535.json','["陪泛芳池醉北樓，水花繁豔照膺舟。亭台陰合樹初晝，", "昔時恩遇今能否，一尉滄洲已白頭。", "江上西來共鳥飛，剪荷浮泛似輕肥。王珣作簿公曾喜，", "宛陵行樂金陵住，遙對家山未憶歸。"]'),
('yuding-37','留別趙端公','許渾','唐','御定全唐诗','yuding','','[]','海門征棹赴龍瀧，暫寄華筵倒玉缸。簫鼓散時逢夜雨，',40,'御定全唐詩/json/535.json','["海門征棹赴龍瀧，暫寄華筵倒玉缸。簫鼓散時逢夜雨，", "卻願煙波阻風雪，待君同拜碧油幢。"]'),
('yuding-38','寄陽陵處士','許渾','唐','御定全唐诗','yuding','','[]','舊隱青山紫桂陰，一書迢遞寄歸心。謝公樓上晚花盛。',48,'御定全唐詩/json/535.json','["舊隱青山紫桂陰，一書迢遞寄歸心。謝公樓上晚花盛。", "揚子宅前春草深。吳岫雨來溪鳥浴，楚江雲暗嶺猿吟，"]'),
('yuding-39','與張道士同訪李隱君不遇','許渾','唐','御定全唐诗','yuding','','[]','千岩萬壑獨攜琴，知在陵陽不可尋。去轍已平秋草遍，',40,'御定全唐詩/json/535.json','["千岩萬壑獨攜琴，知在陵陽不可尋。去轍已平秋草遍，", "唯有西鄰張仲蔚，坐來同愴別離心。"]'),
('yuding-40','聞州中有宴寄崔大夫兼簡邢群評事','許渾','唐','御定全唐诗','yuding','','[]','簫管筵間列翠蛾，玉杯金液耀金波。池邊雨過飄帷幕，',40,'御定全唐詩/json/535.json','["簫管筵間列翠蛾，玉杯金液耀金波。池邊雨過飄帷幕，", "甘心不及同年友，臥聽行雲一曲歌。"]'),
('yuding-41','寄殷堯藩先輩','許渾','唐','御定全唐诗','yuding','','[]','十載功名翰墨林，為從知己信浮沈。青山有雪諳松性，',40,'御定全唐詩/json/535.json','["十載功名翰墨林，為從知己信浮沈。青山有雪諳松性，", "思君一見如瓊樹，空把新詩盡日吟。"]'),
('yuding-42','贈河東虞押衙二首','許渾','唐','御定全唐诗','yuding','','[]','長劍高歌換素衣，君恩未報不言歸。舊精鳥篆諳書體，',80,'御定全唐詩/json/535.json','["長劍高歌換素衣，君恩未報不言歸。舊精鳥篆諳書體，", "生平志氣何人見，空上西樓望落暉。", "吳門風水各萍流，月滿花開懶獨遊。萬里山川分曉夢，", "莫向尊前更惆悵，古來投筆盡封侯。"]'),
('yuding-43','陵陽春日','許渾','唐','御定全唐诗','yuding','','[]','百年身世似飄蓬，澤國移家疊嶂中。萬里綠波魚戀釣，',40,'御定全唐詩/json/535.json','["百年身世似飄蓬，澤國移家疊嶂中。萬里綠波魚戀釣，", "縱倒芳尊心不醉，故人多在洛城東。"]'),
('yuding-44','酬杜補闕初春雨中舟次橫江喜裴郎中相迎見寄','許渾','唐','御定全唐诗','yuding','','[]','江館維舟為庾公，暖波微淥雨濛濛。紅橋迤邐春岩下，',40,'御定全唐詩/json/535.json','["江館維舟為庾公，暖波微淥雨濛濛。紅橋迤邐春岩下，", "郢歌莫問青山吏，魚在深池鳥在籠。"]'),
('yuding-45','送張厚浙東謁丁常侍','許渾','唐','御定全唐诗','yuding','','[]','涼露清蟬柳陌空，故人遙指浙江東。青山有雪松當澗，',40,'御定全唐詩/json/535.json','["涼露清蟬柳陌空，故人遙指浙江東。青山有雪松當澗，", "定知洛下聲名士，共說膺門得孔融。"]'),
('yuding-46','酬副使鄭端公見寄','許渾','唐','御定全唐诗','yuding','','[]','一日高名遍九州，玄珠仍向道中求。郢中白雪慚新唱，',40,'御定全唐詩/json/535.json','["一日高名遍九州，玄珠仍向道中求。郢中白雪慚新唱，", "柳營迢遞江風闊，夜夜孤吟月下樓。"]'),
('yuding-47','酬綿州於中丞使君見寄','許渾','唐','御定全唐诗','yuding','','[]','故人書信越褒斜，新意雖多舊約賒。皆就一麾先去國，',40,'御定全唐詩/json/535.json','["故人書信越褒斜，新意雖多舊約賒。皆就一麾先去國，", "半月離居猶悵望，可堪垂白各天涯。"]'),
('yuding-0','春早郡樓書事寄呈府中群公','許渾','唐','御定全唐诗','yuding','','[]','兩鬢垂絲發半霜，石城孤夢繞襄陽。鴛鴻幕裏蓮披檻，',40,'御定全唐詩/json/536.json','["兩鬢垂絲發半霜，石城孤夢繞襄陽。鴛鴻幕裏蓮披檻，", "峴亭風起花千片，流入南湖盡日香。"]'),
('yuding-1','元處士自洛歸宛陵山居見示詹事相公餞行之什因贈','許渾','唐','御定全唐诗','yuding','','[]','紫霄峰下絕韋編，舊隱相如結襪前。月落尚留東合醉，',40,'御定全唐詩/json/536.json','["紫霄峰下絕韋編，舊隱相如結襪前。月落尚留東合醉，", "一頃豆花三頃竹，想應拋卻釣魚船。"]'),
('yuding-2','送元晝上人歸蘇州兼寄張厚二首','許渾','唐','御定全唐诗','yuding','','[]','自卜閒居荊水頭，感時相別思悠悠。一樽酒盡青山暮，',80,'御定全唐詩/json/536.json','["自卜閒居荊水頭，感時相別思悠悠。一樽酒盡青山暮，", "晝公此去應相問，為說沾巾憶舊遊。", "三年無事客吳鄉，南陌春園碧草長。共醉八門回畫舸，", "經歲別離心自苦，何堪黃葉落清漳。"]'),
('yuding-3','送陸拾遺東歸','許渾','唐','御定全唐诗','yuding','','[]','獨振儒風遇盛時，紫泥初降世人知。文章報主非無意，',40,'御定全唐詩/json/536.json','["獨振儒風遇盛時，紫泥初降世人知。文章報主非無意，", "東歸自是緣清興，莫比商山詠紫芝。"]'),
('yuding-4','湖南徐明府余之南鄰，久不還家，因題林館','許渾','唐','御定全唐诗','yuding','','[]','湘南官罷不歸來，高閣經年掩綠苔。魚溢池塘秋雨過，',40,'御定全唐詩/json/536.json','["湘南官罷不歸來，高閣經年掩綠苔。魚溢池塘秋雨過，", "借問先生獨何處，一籬疏菊又花開。"]'),
('yuding-5','酬和杜侍禦','許渾','唐','御定全唐诗','yuding','','[]','花時曾省杜陵游，聞下書帷不舉頭。因過石城先訪戴，',40,'御定全唐詩/json/536.json','["花時曾省杜陵游，聞下書帷不舉頭。因過石城先訪戴，", "正把新詩望南浦，棹歌應是木蘭舟。"]'),
('yuding-6','酬河中杜侍禦重寄','許渾','唐','御定全唐诗','yuding','','[]','五色如絲下碧空，片帆還繞楚王宮。文章已變南山霧，',40,'御定全唐詩/json/536.json','["五色如絲下碧空，片帆還繞楚王宮。文章已變南山霧，", "十千沽酒留君醉，莫道歸心似轉蓬。"]'),
('yuding-7','寄獻三川守劉公','許渾','唐','御定全唐诗','yuding','','[]','三川歌頌徹咸秦，十二樓前侍從臣。休閉玉籠留鸑鷟，',80,'御定全唐詩/json/536.json','["三川歌頌徹咸秦，十二樓前侍從臣。休閉玉籠留鸑鷟，", "自笑東風過寒食，茂陵寥落未知春。", "半年三度轉蓬居，錦帳心闌羨隼旟。老去自驚秦塞雁，", "春雪未晴春酒貴，莫教愁殺馬相如。"]'),
('yuding-8','送段覺之西蜀結婚','許渾','唐','御定全唐诗','yuding','','[]','詞賦名高身不閑，采衣如錦度函關。鏡中鸞影胡威去，',40,'御定全唐詩/json/536.json','["詞賦名高身不閑，采衣如錦度函關。鏡中鸞影胡威去，", "時人若問西遊客，心在重霄鬢欲斑。"]'),
('yuding-9','長慶寺遇常州阮秀才','許渾','唐','御定全唐诗','yuding','','[]','高閣晴軒對一峰，毗陵書客此相逢。晚收紅葉題詩遍，',40,'御定全唐詩/json/536.json','["高閣晴軒對一峰，毗陵書客此相逢。晚收紅葉題詩遍，", "上方有路應知處，疏磬寒蟬樹幾重。"]'),
('yuding-10','贈閑師','許渾','唐','御定全唐诗','yuding','','[]','近日高僧更有誰，宛陵山下遇閑師。東林共許三乘學，',40,'御定全唐詩/json/536.json','["近日高僧更有誰，宛陵山下遇閑師。東林共許三乘學，", "秋江莫惜題佳句，正是磷磷見底時。"]'),
('yuding-11','東游留別李叢秀才','許渾','唐','御定全唐诗','yuding','','[]','煩君沽酒強登樓，罷唱離歌說遠遊。文字豈勞諸子重，',40,'御定全唐詩/json/536.json','["煩君沽酒強登樓，罷唱離歌說遠遊。文字豈勞諸子重，", "起憑欄幹各垂淚，又驅羸馬向東州。"]'),
('yuding-12','竹林寺別友人','許渾','唐','御定全唐诗','yuding','','[]','騷人吟罷起鄉愁，暗覺年華似水流。花滿謝城傷共別，',40,'御定全唐詩/json/536.json','["騷人吟罷起鄉愁，暗覺年華似水流。花滿謝城傷共別，", "明日分襟又何處，江南江北路悠悠。"]'),
('yuding-13','送處士武君歸章洪山居','許渾','唐','御定全唐诗','yuding','','[]','形影無群消息沉，登聞三擊血沾襟。皇綱一日開冤氣，',40,'御定全唐詩/json/536.json','["形影無群消息沉，登聞三擊血沾襟。皇綱一日開冤氣，", "他時縱有征書至，雪滿空山不可尋。"]'),
('yuding-14','題義女亭','許渾','唐','御定全唐诗','yuding','','[]','身沒蘭閨道日明，郭南尋得舊池亭。詩人愁立暮山碧，',40,'御定全唐詩/json/536.json','["身沒蘭閨道日明，郭南尋得舊池亭。詩人愁立暮山碧，", "至今鄉里風猶在，借問誰傳義女銘。"]'),
('yuding-15','吳門送振武李從事','許渾','唐','御定全唐诗','yuding','','[]','晚促離筵醉玉缸，伊州一曲淚雙雙。欲攜刀筆從新幕，',40,'御定全唐詩/json/536.json','["晚促離筵醉玉缸，伊州一曲淚雙雙。欲攜刀筆從新幕，", "嫖姚若許傳書檄，坐築三城看受降。"]'),
('yuding-16','郊居春日有懷府中諸公並柬王兵曹','許渾','唐','御定全唐诗','yuding','','[]','欲學漁翁釣艇新，濯纓猶惜九衢塵。花前更謝依劉客，',40,'御定全唐詩/json/536.json','["欲學漁翁釣艇新，濯纓猶惜九衢塵。花前更謝依劉客，", "一山桃杏同時發，誰似東風不厭貧。"]'),
('yuding-17','同韋少尹傷故衛尉李少卿','許渾','唐','御定全唐诗','yuding','','[]','客醉更長樂未窮，似知身世一宵空。香街寶馬嘶殘月，',40,'御定全唐詩/json/536.json','["客醉更長樂未窮，似知身世一宵空。香街寶馬嘶殘月，", "何須更賦山陽笛，寒月沉西水向東。"]'),
('yuding-18','舟行早發廬陵郡郭寄滕郎中','許渾','唐','御定全唐诗','yuding','','[]','楚客停橈太守知，露凝丹葉自秋悲。蟹螯只恐相如渴，',40,'御定全唐詩/json/536.json','["楚客停橈太守知，露凝丹葉自秋悲。蟹螯只恐相如渴，", "離心更羨高齋夕，巫峽花深醉玉卮。"]'),
('yuding-19','聞邊將劉皋無辜受戮','許渾','唐','御定全唐诗','yuding','','[]','外監多假帝王尊，威脅偏裨勢不存。才許誓心安玉壘，',40,'御定全唐詩/json/536.json','["外監多假帝王尊，威脅偏裨勢不存。才許誓心安玉壘，", "卻賴漢庭多烈士，至今猶自伏蒲輪。"]'),
('yuding-20','送薛秀才南游','許渾','唐','御定全唐诗','yuding','','[]','姑蘇城外柳初凋，同上江樓更寂寥。繞壁舊詩塵漠漠，',40,'御定全唐詩/json/536.json','["姑蘇城外柳初凋，同上江樓更寂寥。繞壁舊詩塵漠漠，", "從此草玄應有處，白雲青嶂一相招。"]'),
('yuding-21','夜歸孤山寺卻寄盧郎中','許渾','唐','御定全唐诗','yuding','','[]','青山有志路猶賒，心在琴書自憶家。醉別庾樓山色曉，',40,'御定全唐詩/json/536.json','["青山有志路猶賒，心在琴書自憶家。醉別庾樓山色曉，", "他日此身須報德，莫言空愛舊煙霞。"]'),
('yuding-22','贈桐廬房明府先輩','許渾','唐','御定全唐诗','yuding','','[]','帝城春榜謫靈仙，四海聲華二十年。闕下書功無後輩，',40,'御定全唐詩/json/536.json','["帝城春榜謫靈仙，四海聲華二十年。闕下書功無後輩，", "自笑小儒非一鶚，亦趨門屏冀相憐。"]'),
('yuding-23','甘露寺感事貽同志','許渾','唐','御定全唐诗','yuding','','[]','雲蔽長安路更賒，獨隨漁艇老天涯。青山盡日尋黃絹，',40,'御定全唐詩/json/536.json','["雲蔽長安路更賒，獨隨漁艇老天涯。青山盡日尋黃絹，", "東堂舊侶勤書劍，同出膺門是一家。"]'),
('yuding-24','泛溪夜回寄道玄上人','許渾','唐','御定全唐诗','yuding','','[]','南郭煙光異世間，碧桃紅杏水潺潺。猿來近嶺獼猴散，',40,'御定全唐詩/json/536.json','["南郭煙光異世間，碧桃紅杏水潺潺。猿來近嶺獼猴散，", "幾回策杖終難去，洞口雲歸不見山。"]'),
('yuding-25','客至','許渾','唐','御定全唐诗','yuding','','[]','得路逢津更俊才，可憐鞍馬照春來。殘花幾日小齋閉，',40,'御定全唐詩/json/536.json','["得路逢津更俊才，可憐鞍馬照春來。殘花幾日小齋閉，", "相逢少別更堪恨，何必秋風江上臺。"]'),
('yuding-26','經李給事舊居','許渾','唐','御定全唐诗','yuding','','[]','歸作儒翁出致君，故山誰複有遺文。漢庭使氣摧張禹，',40,'御定全唐詩/json/536.json','["歸作儒翁出致君，故山誰複有遺文。漢庭使氣摧張禹，", "朱弦一奏沉湘怨，風起寒波日欲曛。"]'),
('yuding-27','新興道中','許渾','唐','御定全唐诗','yuding','','[]','芙蓉村步失官金，折獄無功不可尋。初掛海帆逢歲暮，',40,'御定全唐詩/json/536.json','["芙蓉村步失官金，折獄無功不可尋。初掛海帆逢歲暮，", "夜榜歸舟望漁火，一溪風雨兩岩陰。"]'),
('yuding-28','下第有懷親友','許渾','唐','御定全唐诗','yuding','','[]','萬山晴雪九衢塵，何處風光寄夢頻。花盛庾園攜酒客，',40,'御定全唐詩/json/536.json','["萬山晴雪九衢塵，何處風光寄夢頻。花盛庾園攜酒客，", "無限別情多病後，杜陵寥落在漳濱。"]'),
('yuding-29','中秋夕寄大樑劉尚書','許渾','唐','御定全唐诗','yuding','','[]','汴人迎拜洛人留，虎豹旌旗擁碧油。刁鬥嚴更軍耳目，',40,'御定全唐詩/json/536.json','["汴人迎拜洛人留，虎豹旌旗擁碧油。刁鬥嚴更軍耳目，", "應念散郎千裏外，去年今夜醉蘭舟。"]'),
('yuding-30','臥病','許渾','唐','御定全唐诗','yuding','','[]','寒窗燈盡月斜暉，佩馬朝天獨掩扉。清露已凋秦塞柳，',40,'御定全唐詩/json/536.json','["寒窗燈盡月斜暉，佩馬朝天獨掩扉。清露已凋秦塞柳，", "惟有寄書書未得，臥聞燕雁向南飛。"]'),
('yuding-31','殘雪','許渾','唐','御定全唐诗','yuding','','[]','憶昨新春霰雪飛，階前簷上鬥寒姿。狂風送在竹深處，',40,'御定全唐詩/json/536.json','["憶昨新春霰雪飛，階前簷上鬥寒姿。狂風送在竹深處，", "晚來又喜登樓見，一曲高歌和者誰。"]'),
('yuding-32','和常秀才寄簡歸州鄭使君借猿','許渾','唐','御定全唐诗','yuding','','[]','謝守攜猿東路長，嫋藤穿竹似瀟湘。碧山初暝嘯秋月，',40,'御定全唐詩/json/536.json','["謝守攜猿東路長，嫋藤穿竹似瀟湘。碧山初暝嘯秋月，", "心知欲借南遊侶，未到三聲恐斷腸。"]'),
('yuding-33','送人之任邛州','許渾','唐','御定全唐诗','yuding','','[]','綠發監州丹府歸，還家樂事我先知。群童竹馬交迎日，',40,'御定全唐詩/json/536.json','["綠發監州丹府歸，還家樂事我先知。群童竹馬交迎日，", "亨衢自有橫飛勢，便到西垣視訓辭。"]'),
('yuding-34','和河南楊少尹奉陪薛司空石筍詩','許渾','唐','御定全唐诗','yuding','','[]','暖溪寒井碧岩前，謝傅賓朋盛綺筵。雲斷石峰高並筍，',40,'御定全唐詩/json/536.json','["暖溪寒井碧岩前，謝傅賓朋盛綺筵。雲斷石峰高並筍，", "聞道詩成歸已夕，柳風花露月初圓。"]'),
('yuding-35','獻鄜坊丘常侍','許渾','唐','御定全唐诗','yuding','','[]','詔選將軍護北戎，身騎白馬臂彤弓。柳營遠識金貂貴，',40,'御定全唐詩/json/536.json','["詔選將軍護北戎，身騎白馬臂彤弓。柳營遠識金貂貴，", "蓬萊每望平安火，應奏班超定遠功。"]'),
('yuding-36','寄當塗李遠','許渾','唐','御定全唐诗','yuding','','[]','賦擬相如詩似陶，雲陽煙月又同袍。車前驥病駑駘逸，',40,'御定全唐詩/json/536.json','["賦擬相如詩似陶，雲陽煙月又同袍。車前驥病駑駘逸，", "不須倚向青山住，詠雪題詩用意勞。"]'),
('yuding-37','和崔大夫新廣北樓登眺','許渾','唐','御定全唐诗','yuding','','[]','北望高樓夏亦寒，山重水闊接長安。修梁暗換丹楹小，',40,'御定全唐詩/json/536.json','["北望高樓夏亦寒，山重水闊接長安。修梁暗換丹楹小，", "庾公戀闕懷鄉處，目送歸帆下遠灘。"]'),
('yuding-38','送客自兩河歸江南','許渾','唐','御定全唐诗','yuding','','[]','兩河庶事已堪傷，南客秋歸路更長。台畔古松悲魏帝，',40,'御定全唐詩/json/536.json','["兩河庶事已堪傷，南客秋歸路更長。台畔古松悲魏帝，", "遙羨落帆逢舊友，綠蛾青鬢醉橫塘。"]'),
('yuding-39','題陸侍禦林亭','許渾','唐','御定全唐诗','yuding','','[]','野水通池石疊台，五營無事隱雄才。松齋下馬書千卷，',40,'御定全唐詩/json/536.json','["野水通池石疊台，五營無事隱雄才。松齋下馬書千卷，", "定知別後無多日，海柳江花次第開。"]'),
('yuding-40','泊蒜山津聞東林寺光儀上人物故','許渾','唐','御定全唐诗','yuding','','[]','雲齋曾宿借方袍，因說浮生大夢勞。言下是非齊虎尾，',40,'御定全唐詩/json/536.json','["雲齋曾宿借方袍，因說浮生大夢勞。言下是非齊虎尾，", "明日東林有誰在，不堪秋磬拂煙濤。"]'),
('yuding-41','春日思舊游寄南徐從事劉三複','許渾','唐','御定全唐诗','yuding','','[]','風暖曲江花半開，忽思京口共銜杯。湘潭雲盡暮山出，',40,'御定全唐詩/json/536.json','["風暖曲江花半開，忽思京口共銜杯。湘潭雲盡暮山出，", "薊門高處極歸思，隴雁北飛雙燕回。"]'),
('yuding-42','郊園秋日寄洛中友人','許渾','唐','御定全唐诗','yuding','','[]','楚水西來天際流，感時傷別思悠悠。一尊酒盡青山暮，',40,'御定全唐詩/json/536.json','["楚水西來天際流，感時傷別思悠悠。一尊酒盡青山暮，", "嵩陽親友如相問，潘嶽閒居欲白頭。"]'),
('yuding-43','送杜秀才歸桂林','許渾','唐','御定全唐诗','yuding','','[]','桂州南去與誰同，處處山連水自通。兩岸曉霞千里草，',40,'御定全唐詩/json/536.json','["桂州南去與誰同，處處山連水自通。兩岸曉霞千里草，", "愁君路遠銷年月，莫滯三湘五嶺中。"]'),
('yuding-44','春雨舟中次和橫江裴使君見迎李趙二秀才同來因書四韻兼寄江南','許渾','唐','御定全唐诗','yuding','','[]','芳草渡頭微雨時，萬株楊柳拂波垂。蒲根水暖雁初落，',40,'御定全唐詩/json/536.json','["芳草渡頭微雨時，萬株楊柳拂波垂。蒲根水暖雁初落，", "江南仲蔚多情調，悵望青雲幾首詩。"]'),
('yuding-45','東陵赴京道病東歸寓居開元寺寄盧員外宋魏二先輩','許渾','唐','御定全唐诗','yuding','','[]','西風吹雨雁初時，病寄僧齋罷獻書。萬里咸秦勞我馬，',40,'御定全唐詩/json/536.json','["西風吹雨雁初時，病寄僧齋罷獻書。萬里咸秦勞我馬，", "不是醉眠愁不散，莫言琴酒學相如。"]'),
('yuding-46','聞開江宋相公申錫下世二首','許渾','唐','御定全唐诗','yuding','','[]','權門陰奏奪移才，馹騎如星墮峽來。晁氏有恩忠作禍，',80,'御定全唐詩/json/536.json','["權門陰奏奪移才，馹騎如星墮峽來。晁氏有恩忠作禍，", "畢竟功成何處是，五湖雲月一帆開。", "月落湘潭棹不喧，玉杯瑤瑟奠蘋蘩。誰能力制乘時鶴，", "宵衣旰食明天子，日伏青蒲不敢言。"]'),
('yuding-47','贈所知','許渾','唐','御定全唐诗','yuding','','[]','因釣鱸魚住浙河，掛帆千里亦相過。茅簷夜醉平階月，',40,'御定全唐詩/json/536.json','["因釣鱸魚住浙河，掛帆千里亦相過。茅簷夜醉平階月，", "明時又作閒居賦，誰薦東門策四科。"]'),
('yuding-48','謝人贈鞭','許渾','唐','御定全唐诗','yuding','','[]','蜀國名鞭見惠稀，駑駘從此長光輝。獨根擁腫來雲岫，',40,'御定全唐詩/json/536.json','["蜀國名鞭見惠稀，駑駘從此長光輝。獨根擁腫來雲岫，", "莫言三尺長無用，百萬軍中要指揮。"]'),
('yuding-49','早秋寄劉尚書','許渾','唐','御定全唐诗','yuding','','[]','天生心識富人侯，將相門中第一流。旗纛早開擒虎帳，',40,'御定全唐詩/json/536.json','["天生心識富人侯，將相門中第一流。旗纛早開擒虎帳，", "昨夜雨涼今夜月，笙歌應醉最高樓。"]'),
('yuding-50','及第後春情','許渾','唐','御定全唐诗','yuding','','[]','世間得意是春風，散誕經過觸處通。細搖柳臉牽長帶，',40,'御定全唐詩/json/536.json','["世間得意是春風，散誕經過觸處通。細搖柳臉牽長帶，", "猶以西都名下客，今年一月始相逢。"]'),
('yuding-51','歸長安','許渾','唐','御定全唐诗','yuding','','[]','三年何處淚汍瀾，白帝城邊曉角殘。非是無心戀巫峽，',40,'御定全唐詩/json/536.json','["三年何處淚汍瀾，白帝城邊曉角殘。非是無心戀巫峽，", "大抵莫教聞雨後，此時腸斷不應難。"]'),
('yuding-52','經古行宮','許渾','唐','御定全唐诗','yuding','','[]','台閣參差倚太陽，年年花發滿山香。重門勘鎖青春晚，',40,'御定全唐詩/json/536.json','["台閣參差倚太陽，年年花發滿山香。重門勘鎖青春晚，", "先皇一去無回駕，紅粉雲鬟空斷腸。"]'),
('yuding-53','秋晚懷茅山石涵村舍','許渾','唐','御定全唐诗','yuding','','[]','十畝山田近石涵，村居風俗舊曾諳。簾前白艾驚春燕，',40,'御定全唐詩/json/536.json','["十畝山田近石涵，村居風俗舊曾諳。簾前白艾驚春燕，", "陵陽秋盡多歸思，紅樹蕭蕭覆碧潭。"]'),
('yuding-54','貴游','許渾','唐','御定全唐诗','yuding','','[]','朝回佩馬早淒淒，年少恩深衛霍齊。斧鉞舊威龍塞北，',40,'御定全唐詩/json/536.json','["朝回佩馬早淒淒，年少恩深衛霍齊。斧鉞舊威龍塞北，", "南陌行人盡回首，笙歌一曲暮雲低。"]'),
('yuding-55','贈別','許渾','唐','御定全唐诗','yuding','','[]','眼前迎送不曾休，相續輪蹄似水流。門外若無南北路，',40,'御定全唐詩/json/536.json','["眼前迎送不曾休，相續輪蹄似水流。門外若無南北路，", "莫怪分襟銜淚語，十年耕釣憶滄洲。"]'),
('yuding-56','秋夜與友人宿','許渾','唐','御定全唐诗','yuding','','[]','楚國同遊過十霜，萬重心事幾堪傷。蒹葭露白蓮塘淺，',40,'御定全唐詩/json/536.json','["楚國同遊過十霜，萬重心事幾堪傷。蒹葭露白蓮塘淺，", "寒城欲曉聞吹笛，猶臥東軒月滿床。"]'),
('yuding-57','將赴京留贈僧院','許渾','唐','御定全唐诗','yuding','','[]','九衢塵土遞追攀，馬跡軒車日暮間。玄發盡驚為客換，',40,'御定全唐詩/json/536.json','["九衢塵土遞追攀，馬跡軒車日暮間。玄發盡驚為客換，", "謝卻從前受恩地，歸來依止叩禪關。"]'),
('yuding-58','寄湘中友人','許渾','唐','御定全唐诗','yuding','','[]','莫戀醉鄉迷酒杯，流年長怕老年催。西陵水闊魚難到，',40,'御定全唐詩/json/536.json','["莫戀醉鄉迷酒杯，流年長怕老年催。西陵水闊魚難到，", "相如已定題橋志，江上無由夢釣台。"]'),
('yuding-59','江上逢友人','許渾','唐','御定全唐诗','yuding','','[]','故國歸人酒一杯，暫停蘭棹共徘徊。村連三峽暮雲起，',40,'御定全唐詩/json/536.json','["故國歸人酒一杯，暫停蘭棹共徘徊。村連三峽暮雲起，", "到時若見東籬菊，為問經霜幾度開。"]'),
('yuding-60','金谷懷古','許渾','唐','御定全唐诗','yuding','','[]','淒涼遺跡洛川東，浮世榮枯萬古同。桃李香銷金穀在，',40,'御定全唐詩/json/536.json','["淒涼遺跡洛川東，浮世榮枯萬古同。桃李香銷金穀在，", "□□□□□□□，□□□□□□□。"]'),
('yuding-61','經行廬山東林寺','許渾','唐','御定全唐诗','yuding','','[]','離魂斷續楚江壖，葉墜初紅十月天。紫陌事多難數悉，',40,'御定全唐詩/json/536.json','["離魂斷續楚江壖，葉墜初紅十月天。紫陌事多難數悉，", "他歲若教如範蠡，也應須入五湖煙。"]'),
('yuding-62','途中逢故人，話西山讀書早曾遊覽','許渾','唐','御定全唐诗','yuding','','[]','西岩曾到讀書堂，穿竹行沙十裏強。湖上夢餘波灩灩，',40,'御定全唐詩/json/536.json','["西岩曾到讀書堂，穿竹行沙十裏強。湖上夢餘波灩灩，", "莫道少年頭不白，君看潘嶽幾莖霜。"]'),
('yuding-63','將赴京題陵陽王氏水居','許渾','唐','御定全唐诗','yuding','','[]','簾卷平蕪接遠天，暫寬行役到尊前。是非境裏有閑日，',40,'御定全唐詩/json/536.json','["簾卷平蕪接遠天，暫寬行役到尊前。是非境裏有閑日，", "馬蹄不道貪西去，爭向一聲高樹蟬。"]'),
('yuding-64','冬日五浪館水亭懷別','許渾','唐','御定全唐诗','yuding','','[]','蘆荻花多觸處飛，獨憑虛檻雨微微。寒林葉落鳥巢出，',40,'御定全唐詩/json/536.json','["蘆荻花多觸處飛，獨憑虛檻雨微微。寒林葉落鳥巢出，", "江城向暝東風急，一半鄉愁聞擣衣。"]'),
('yuding-65','送別','許渾','唐','御定全唐诗','yuding','','[]','溪邊楊柳色參差，攀折年年贈別離。一片風帆望已極，',40,'御定全唐詩/json/536.json','["溪邊楊柳色參差，攀折年年贈別離。一片風帆望已極，", "莫殢酒杯閑過日，碧雲深處是佳期。"]'),
('yuding-66','寄遠','許渾','唐','御定全唐诗','yuding','','[]','兩葉愁眉愁不開，獨含惆悵上層台。碧雲空斷雁行處，',40,'御定全唐詩/json/536.json','["兩葉愁眉愁不開，獨含惆悵上層台。碧雲空斷雁行處，", "功名待寄淩煙閣，力盡遼城不肯回。"]'),
('yuding-67','新柳','許渾','唐','御定全唐诗','yuding','','[]','無力搖風曉色新，細腰爭妒看來頻。綠陰未覆長堤水，',40,'御定全唐詩/json/536.json','["無力搖風曉色新，細腰爭妒看來頻。綠陰未覆長堤水，", "東□門外多離別，愁殺朝朝暮暮人。"]'),
('yuding-68','旅懷作','許渾','唐','御定全唐诗','yuding','','[]','促促因吟晝短詩，朝驚穠色暮空枝。無情春色不長久，',40,'御定全唐詩/json/536.json','["促促因吟晝短詩，朝驚穠色暮空枝。無情春色不長久，", "眼前擾擾日一日，暗送白頭人不知。"]'),
('yuding-69','雁','許渾','唐','御定全唐诗','yuding','','[]','萬里銜蘆別故鄉，雲飛水宿向瀟湘。數聲孤枕堪垂淚，',40,'御定全唐詩/json/536.json','["萬里銜蘆別故鄉，雲飛水宿向瀟湘。數聲孤枕堪垂淚，", "年年辛苦來衡嶽，羽翼摧殘隴塞霜。"]'),
('yuding-70','出關','許渾','唐','御定全唐诗','yuding','','[]','朝纓初解佐江濱，麋鹿心知自有群。漢囿獵稀慵獻賦，',40,'御定全唐詩/json/536.json','["朝纓初解佐江濱，麋鹿心知自有群。漢囿獵稀慵獻賦，", "關吏不須迎馬笑，去時無意學終軍。"]'),
('yuding-71','寄房千里博士','許渾','唐','御定全唐诗','yuding','','[]','春風白馬紫絲韁，正值蠶眠未采桑。五夜有心隨暮雨，',40,'御定全唐詩/json/536.json','["春風白馬紫絲韁，正值蠶眠未采桑。五夜有心隨暮雨，", "為報西遊減離恨，阮郎才去嫁劉郎。"]'),
('yuding-0','泛五雲溪','許渾','唐','御定全唐诗','yuding','','[]','此溪何處路，遙問白髯翁。佛廟千岩裏，人家一島中。',72,'御定全唐詩/json/537.json','["此溪何處路，遙問白髯翁。佛廟千岩裏，人家一島中。", "魚傾荷葉露，蟬噪柳林風。急瀨鳴車軸，微波漾釣筒。", "石苔縈棹綠，山果拂舟紅。更就千村宿，溪橋與剡通。"]'),
('yuding-1','寄郴州李相公','許渾','唐','御定全唐诗','yuding','','[]','高樓王與謝，逸韻比南金。不遇銷憂日，埃塵誰複尋。',96,'御定全唐詩/json/537.json','["高樓王與謝，逸韻比南金。不遇銷憂日，埃塵誰複尋。", "曠懷澹得喪，失意縱登臨。彩檻浮雲迥，綺窗明月深。", "虯龍壓滄海，鴛鸞思鄧林。青雲傷國器，白髮軫鄉心。", "功高恩自洽，道直謗徒侵。應笑靈均恨，江畔獨行吟。"]'),
('yuding-2','贈蕭煉師','許渾','唐','御定全唐诗','yuding','','[]','曾試昭陽曲，瑤齋帝自臨。紅珠絡繡帽，翠鈿束羅襟。',240,'御定全唐詩/json/537.json','["曾試昭陽曲，瑤齋帝自臨。紅珠絡繡帽，翠鈿束羅襟。", "雙闕胡塵起，千門宿露陰。出宮迷國步，回駕軫皇心。", "桂殿春空晚，椒房夜自深。急宣求故劍，冥契得遺簪。", "暗記神仙傳，潛封女史箴。壺中知日永，掌上畏年侵。", "莫比班家扇，甯同卓氏琴。雲車辭鳳輦，羽帔別鴛衾。", "網斷魚遊藻，籠開鶴戲林。洛煙浮碧漢，嵩月上丹岑。", "露草爭三秀，風篁共八音。吹笙延鶴舞，敲磬引龍吟。", "旄節纖腰舉，霞杯皓腕斟。還磨照寶鏡，猶插辟寒金。", "東海人情變，南山聖壽沈。朱顏常似渥，綠發已如尋。", "養氣齊生死，留形盡古今。更求應不見，雞犬日駸駸。"]'),
('yuding-3','冬日宣城開元寺贈元孚上人','許渾','唐','御定全唐诗','yuding','','[]','一缽事南宗，僧儀稱病容。曹溪花裏別，蕭寺竹前逢。',240,'御定全唐詩/json/537.json','["一缽事南宗，僧儀稱病容。曹溪花裏別，蕭寺竹前逢。", "燭影深寒殿，經聲徹曙鐘。欲齋簷睡鴿，初定壁吟蛩。", "詩繼休遺韻，書傳永逸蹤。藝多人譽洽，機絕道情濃。", "汲澗瓶沈藻，眠階錫掛松。雲鳴新放鶴，池臥舊降龍。", "露茗山廚焙，霜粳野碓舂。梵文明處譯，禪衲暖時縫。", "層塔題應遍，飛軒步不慵。繡梁交薜荔，畫井倒芙蓉。", "翠戶垂旗網，朱窗列劍鋒。寒風金磬遠，晴雪玉樓重。", "妙理三乘達，清才萬象供。山高橫睥睨，灘淺聚艨艟。", "微霧蒼平楚，殘暉淡遠峰。林疏霜摵摵，波靜月溶溶。", "劍出因雷煥，琴全遇蔡邕。西方知有社，支許合相從。"]'),
('yuding-4','維舟秦淮過溫州李給事宅','許渾','唐','御定全唐诗','yuding','','[]','給事為郎日，青溪醉隱銜。冰池通極浦，雪徑繞高岩。',120,'御定全唐詩/json/537.json','["給事為郎日，青溪醉隱銜。冰池通極浦，雪徑繞高岩。", "珠玉砂同棄，松筠草共芟。帝圖憂一失，臣節恥三緘。", "代有王陵戇，時無靳尚讒。定應標直筆，寧為發空函。", "霧黑連雲棧，風狂截海帆。石梯迎雨潤，沙井待潮鹹。", "蠟屐青筇杖，籃輿白罽衫。應勞北歸夢，山路正巉巉。"]'),
('yuding-5','登蒜山觀發軍','許渾','唐','御定全唐诗','yuding','','[]','羽檄徵兵急，轅門選將雄。犬羊憂破竹，貔虎極飛蓬。',120,'御定全唐詩/json/537.json','["羽檄徵兵急，轅門選將雄。犬羊憂破竹，貔虎極飛蓬。", "定系倡狂虜，何煩矍鑠翁。更探黃石略，重振黑山功。", "別馬嘶營柳，驚烏散井桐。低星連寶劍，殘月讓雕弓。", "浪曉戈鋋裏，山晴鼓角中。甲開魚照水，旗颺虎拏風。", "去想金河遠，行知玉塞空。漢庭應有問，師律在元戎。"]'),
('yuding-6','送從兄別駕歸蜀','許渾','唐','御定全唐诗','yuding','','[]','聞與湘南令，童年侍玉墀。家留秦塞曲，官謫瘴溪湄。',120,'御定全唐詩/json/537.json','["聞與湘南令，童年侍玉墀。家留秦塞曲，官謫瘴溪湄。", "道直奸臣屏，冤深聖主知。逝川東去疾，霈澤北來遲。", "青漢龍髯絕，蒼岑馬鬣移。風淒聞笛處，月慘罷琴時。", "客路黃公廟，鄉關白帝祠。已稱鸚鵡賦，寧誦鶺鴒詩。", "遠道書難達，長亭酒莫持。當憑蜀江水，萬里寄相思。"]'),
('yuding-7','金陵阻風登延祚閣','許渾','唐','御定全唐诗','yuding','','[]','極目皆陳跡，披圖問遠公。戈鋋三國後，冠蓋六朝中。',96,'御定全唐詩/json/537.json','["極目皆陳跡，披圖問遠公。戈鋋三國後，冠蓋六朝中。", "葛蔓交殘壘，芒花沒後宮。水流簫鼓絕，山在綺羅空。", "極浦千艘聚，高臺一徑通。雲移吳岫雨，潮轉楚江風。", "登閣漸漂梗，停舟憶斷蓬。歸期與歸路，杉桂海門東。"]'),
('yuding-8','送林處士自閩中道越由霅抵兩川','許渾','唐','御定全唐诗','yuding','','[]','書劍少青眼，煙波初白頭。鄉關背梨嶺，客路轉蘋洲。',96,'御定全唐詩/json/537.json','["書劍少青眼，煙波初白頭。鄉關背梨嶺，客路轉蘋洲。", "處困道難固，乘時恩易酬。鏡中非訪戴，劍外欲依劉。", "高枕海天暝，落帆江雨秋。鼉聲應遠鼓，蜃氣學危樓。", "智士役千慮，達人經百憂。唯聞陶靖節，多在醉鄉遊。"]'),
('yuding-9','宣城贈蕭兵曹','許渾','唐','御定全唐诗','yuding','','[]','桂楫謫湘渚，三年波上春。舟寒剡溪雪，衣破洛城塵。',96,'御定全唐詩/json/537.json','["桂楫謫湘渚，三年波上春。舟寒剡溪雪，衣破洛城塵。", "客道恥搖尾，皇恩寬犯鱗。花時去國遠，月夕上樓頻。", "貪酒不辭病，傭書非為貧。行吟值漁父，坐隱對樵人。", "紫陌罷雙轍，碧潭窮一綸。高歌更南去，煙水是通津。"]'),
('yuding-10','秋夕宴李侍禦宅','許渾','唐','御定全唐诗','yuding','','[]','公子征詞客，秋堂遞玉杯。月高羅幕卷，風度錦屏開。',96,'御定全唐詩/json/537.json','["公子征詞客，秋堂遞玉杯。月高羅幕卷，風度錦屏開。", "鳳管添簧品，鶤弦促柱哀。轉喉雲旋合，垂手露徐來。", "燭換三條燼，香銷十炷灰。蛩聲聞鼓歇，螢焰觸簾回。", "廣檻煙分柳，空庭露積苔。解酲須滿酌，應為撥新醅。"]'),
('yuding-11','晨自竹徑至龍興寺崇隱上人院','許渾','唐','御定全唐诗','yuding','','[]','佛寺通南徑，僧堂倚北坡。藤陰迷晚竹，苔滑仰晴莎。',96,'御定全唐詩/json/537.json','["佛寺通南徑，僧堂倚北坡。藤陰迷晚竹，苔滑仰晴莎。", "病憶春前別，閑宜雨後過。石橫聞水遠，林缺見山多。", "欲結三天社，初降十地魔。毒龍來有窟，靈鶴去無窠。", "客路隨萍梗，鄉園失薜蘿。禪心如可學，不藉魯陽戈。"]'),
('yuding-12','歲暮自廣江至新興往復中題峽山寺四首','許渾','唐','御定全唐诗','yuding','','[]','夜醉晨方醒，孤吟恐失群。海鰍潮上見，江鵠霧中聞。',288,'御定全唐詩/json/537.json','["夜醉晨方醒，孤吟恐失群。海鰍潮上見，江鵠霧中聞。", "未臘梅先實，經冬草自熏。樹隨山崦合，泉到石棱分。", "虎跡空林雨，猿聲絕嶺雲。蕭蕭異鄉鬢，明日共絲棼。", "薄暮緣西峽，停橈一訪僧。鷺巢橫臥柳，猿飲倒垂藤。", "水曲岩千疊，雲重樹百層。山風寒殿磬，溪雨夜船燈。", "灘漲危槎沒，泉沖怪石崩。中台一襟淚，歲杪別良朋。", "密樹分蒼壁，長溪抱碧岑。海風聞鶴遠，潭日見魚深。", "松蓋環清韻，榕根架綠陰。洞丁多斫石，蠻女半淘金。", "南浦驚春至，西樓送月沉。江流不過嶺，何處寄歸心。", "月在行人起，千峰複萬峰。海虛爭翡翠，溪邏鬥芙蓉。", "古木高生槲，陰池滿種松。火探深洞燕，香送遠潭龍。", "藍塢寒先燒，禾堂晚並舂。更投何處宿，西峽隔雲鐘。"]'),
('yuding-13','南海使院對菊懷丁卯別墅','許渾','唐','御定全唐诗','yuding','','[]','何處曾移菊，溪橋鶴嶺東。籬疏還有豔，園小亦無叢。',72,'御定全唐詩/json/537.json','["何處曾移菊，溪橋鶴嶺東。籬疏還有豔，園小亦無叢。", "日晚秋煙裏，星繁曉露中。影搖金澗水，香染玉潭風。", "罷酒慚陶令，題詩答謝公。朝來數花發，身在尉佗宮。"]'),
('yuding-14','和李相國','許渾','唐','御定全唐诗','yuding','','[]','巨實珍吳果，馴雛重越禽。摘來漁浦上，攜在兔園陰。',72,'御定全唐詩/json/537.json','["巨實珍吳果，馴雛重越禽。摘來漁浦上，攜在兔園陰。", "霜合凝丹頰，風披斂素襟。刀分瓊液散，籠簌雪華深。", "虎帳齋中設，龍樓洛下吟。含消兼受彩，應貴塚卿心。"]'),
('yuding-15','陪少師李相國崔賓客宴居守狄僕射池亭','許渾','唐','御定全唐诗','yuding','','[]','池色似瀟湘，仙舟正日長。燕飛驚蛺蝶，魚躍動鴛鴦。',72,'御定全唐詩/json/537.json','["池色似瀟湘，仙舟正日長。燕飛驚蛺蝶，魚躍動鴛鴦。", "雲聚歌初轉，風回舞欲翔。暖醅松葉嫩，寒粥杏花香。", "羅綺留春色，笙竽送晚光。何須明月夜，紅燭在華堂。"]'),
('yuding-16','和賓客相國詠雪','許渾','唐','御定全唐诗','yuding','','[]','近臘千岩白，迎春四氣催。雲陰連海起，風急度山來。',192,'御定全唐詩/json/537.json','["近臘千岩白，迎春四氣催。雲陰連海起，風急度山來。", "盡日隋堤絮，經冬越嶺梅。豔疑歌處散，輕似舞時回。", "道蘊詩傳麗，相如賦騁才。霽添松筱媚，寒積蕙蘭猜。", "暗漲宮池水，平封輦路埃。燭龍初照耀，巢鶴乍裴回。", "簷日瓊先掛，牆風粉旋摧。五門環玉壘，雙闕對瑤台。", "綺席陵寒坐，珠簾遠曙開。靈芝霜下秀，仙桂月中栽。", "卷幌書千帙，援琴酒百杯。垂休編太史，呈瑞表中台。", "皓夜迷三徑，浮光徹九垓。茲辰是豐歲，歌詠屬良哉。"]'),
('yuding-17','奉和盧大夫新立假山','許渾','唐','御定全唐诗','yuding','','[]','岩穀留心賞，為山極自然。孤峰空迸筍，攢萼旋開蓮。',72,'御定全唐詩/json/537.json','["岩穀留心賞，為山極自然。孤峰空迸筍，攢萼旋開蓮。", "黛色朱樓下，雲形繡戶前。砌塵凝積靄，簷溜掛飛泉。", "樹暗壺中月，花香洞裏天。何如謝康樂，海嶠獨題篇。"]'),
('yuding-18','奉命和後池十韻','許渾','唐','御定全唐诗','yuding','','[]','疊石通溪水，量波失舊規。芳洲還屈曲，朱閣更逶迤。',120,'御定全唐詩/json/537.json','["疊石通溪水，量波失舊規。芳洲還屈曲，朱閣更逶迤。", "浴鳥翻荷葉，驚蟬出柳絲。翠煙秋檜聳，紅露曉蓮披。", "攀檻登樓近，停橈待客遲。野橋從浪沒，輕舸信風移。", "竹韻遷棋局，松陰遞酒卮。性閑鷗自識，心遠鶴先知。", "應想秦人會，休懷越相祠。當期穆天子，簫鼓宴瑤池。"]'),
('yuding-0','雨後思湖上居','許渾','唐','御定全唐诗','yuding','','[]','前山風雨涼，歇馬坐垂楊。何處芙蓉落，南渠秋水香。',24,'御定全唐詩/json/538.json','["前山風雨涼，歇馬坐垂楊。何處芙蓉落，南渠秋水香。"]'),
('yuding-1','聞歌','許渾','唐','御定全唐诗','yuding','','[]','新秋弦管清，時轉遏雲聲。曲盡不知處，月高風滿城。',24,'御定全唐詩/json/538.json','["新秋弦管清，時轉遏雲聲。曲盡不知處，月高風滿城。"]'),
('yuding-2','思天臺','許渾','唐','御定全唐诗','yuding','','[]','赤城雲雪深，山客負歸心。昨夜西齋宿，月明琪樹陰。',24,'御定全唐詩/json/538.json','["赤城雲雪深，山客負歸心。昨夜西齋宿，月明琪樹陰。"]'),
('yuding-3','長安早春懷江南','許渾','唐','御定全唐诗','yuding','','[]','雲月有歸處，故山清洛南。如何一花發，春夢遍江潭。',24,'御定全唐詩/json/538.json','["雲月有歸處，故山清洛南。如何一花發，春夢遍江潭。"]'),
('yuding-4','塞下','許渾','唐','御定全唐诗','yuding','','[]','夜戰桑幹北，秦兵半不歸。朝來有鄉信，猶自寄征衣。',24,'御定全唐詩/json/538.json','["夜戰桑幹北，秦兵半不歸。朝來有鄉信，猶自寄征衣。"]'),
('yuding-5','送客南歸','許渾','唐','御定全唐诗','yuding','','[]','野寺薜蘿晚，官渠楊柳春。歸心已無限，更送洞庭人。',24,'御定全唐詩/json/538.json','["野寺薜蘿晚，官渠楊柳春。歸心已無限，更送洞庭人。"]'),
